import React, { useState, useEffect, useCallback } from 'react';
import { Settings, Percent, Save, Plus, Trash2, ArrowLeft } from 'lucide-react';
import { Button } from '../../../components/common/Button';
import { useNavigate } from 'react-router-dom';
import { getSchemeTypes } from '../../../services/master.service';
import { getPaymentDistributionSettings, updatePaymentDistribution, deletePaymentDistribution } from '../../../services/workforce.service';
import toast from 'react-hot-toast';

const HRMSettings = () => {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(null);
    const [schemeTypes, setSchemeTypes] = useState([]);
    const [settings, setSettings] = useState([]);
    const [editingRow, setEditingRow] = useState(null);
    const [editValues, setEditValues] = useState({ center_share_percent: '', state_share_percent: '' });
    const [addingNew, setAddingNew] = useState(false);
    const [newSetting, setNewSetting] = useState({ scheme_type_id: '', center_share_percent: '', state_share_percent: '' });

    const fetchData = useCallback(async () => {
        setLoading(true);
        try {
            const [schemeRes, settingsRes] = await Promise.all([
                getSchemeTypes({ include_inactive: false }),
                getPaymentDistributionSettings()
            ]);

            const types = schemeRes.schemeTypes || schemeRes || [];
            setSchemeTypes(types);
            setSettings(Array.isArray(settingsRes.data) ? settingsRes.data : []);
        } catch (error) {
            console.error('Failed to load settings', error);
            toast.error('Failed to load settings');
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleEdit = (setting) => {
        setEditingRow(setting.scheme_type_id);
        setEditValues({
            center_share_percent: setting.center_share_percent,
            state_share_percent: setting.state_share_percent
        });
    };

    const handleCancelEdit = () => {
        setEditingRow(null);
        setEditValues({ center_share_percent: '', state_share_percent: '' });
    };

    const handleSave = async (schemeTypeId) => {
        const center = parseFloat(editValues.center_share_percent);
        const state = parseFloat(editValues.state_share_percent);

        if (isNaN(center) || isNaN(state)) {
            toast.error('Please enter valid numbers');
            return;
        }

        if (Math.abs(center + state - 100) > 0.01) {
            toast.error('Center + State share must equal 100%');
            return;
        }

        setSaving(schemeTypeId);
        try {
            await updatePaymentDistribution(schemeTypeId, {
                center_share_percent: center,
                state_share_percent: state
            });
            toast.success('Payment distribution updated');
            setEditingRow(null);
            fetchData();
        } catch (error) {
            toast.error(error.message || 'Failed to save');
        } finally {
            setSaving(null);
        }
    };

    const handleAddNew = async () => {
        if (!newSetting.scheme_type_id) {
            toast.error('Please select a scheme type');
            return;
        }

        const center = parseFloat(newSetting.center_share_percent);
        const state = parseFloat(newSetting.state_share_percent);

        if (isNaN(center) || isNaN(state)) {
            toast.error('Please enter valid numbers');
            return;
        }

        if (Math.abs(center + state - 100) > 0.01) {
            toast.error('Center + State share must equal 100%');
            return;
        }

        setSaving('new');
        try {
            await updatePaymentDistribution(newSetting.scheme_type_id, {
                center_share_percent: center,
                state_share_percent: state
            });
            toast.success('Payment distribution added');
            setAddingNew(false);
            setNewSetting({ scheme_type_id: '', center_share_percent: '', state_share_percent: '' });
            fetchData();
        } catch (error) {
            toast.error(error.message || 'Failed to save');
        } finally {
            setSaving(null);
        }
    };

    const handleDelete = async (schemeTypeId) => {
        if (!window.confirm('Are you sure you want to remove this payment distribution setting?')) return;

        try {
            await deletePaymentDistribution(schemeTypeId);
            toast.success('Payment distribution removed');
            fetchData();
        } catch (error) {
            toast.error(error.message || 'Failed to delete');
        }
    };

    // Get scheme types that don't have settings yet
    const availableSchemeTypes = schemeTypes.filter(
        st => !settings.find(s => s.scheme_type_id === st.scheme_type_id)
    );

    const handleCenterChange = (value, isNew = false) => {
        const center = parseFloat(value) || 0;
        const state = Math.max(0, 100 - center);
        if (isNew) {
            setNewSetting(prev => ({ ...prev, center_share_percent: value, state_share_percent: state.toFixed(2) }));
        } else {
            setEditValues({ center_share_percent: value, state_share_percent: state.toFixed(2) });
        }
    };

    const handleStateChange = (value, isNew = false) => {
        const state = parseFloat(value) || 0;
        const center = Math.max(0, 100 - state);
        if (isNew) {
            setNewSetting(prev => ({ ...prev, state_share_percent: value, center_share_percent: center.toFixed(2) }));
        } else {
            setEditValues({ state_share_percent: value, center_share_percent: center.toFixed(2) });
        }
    };

    if (loading) {
        return <div className="p-8 text-center text-slate-500">Loading settings...</div>;
    }

    return (
        <div className="space-y-8">
            {/* Header */}
            <div className="flex items-center gap-3">
                <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    onClick={() => navigate(-1)}
                    leftIcon={<ArrowLeft className="h-4 w-4" />}
                >
                    Back
                </Button>
                <div className="p-2 bg-blue-50 rounded-lg">
                    <Settings className="h-6 w-6 text-blue-600" />
                </div>
                <div>
                    <h1 className="text-2xl font-bold text-slate-800">HRM Settings</h1>
                    <p className="text-sm text-slate-500">Manage HRM configurations</p>
                </div>
            </div>

            {/* Payment Distribution Section */}
            <div className="bg-white rounded-xl border border-slate-200 shadow-sm">
                <div className="p-6 border-b border-slate-100">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <Percent className="h-5 w-5 text-blue-600" />
                            <div>
                                <h2 className="text-lg font-semibold text-slate-800">Payment Distribution</h2>
                                <p className="text-sm text-slate-500">Set center and state share percentages per scheme type</p>
                            </div>
                        </div>
                        {availableSchemeTypes.length > 0 && !addingNew && (
                            <Button
                                type="button"
                                variant="outline"
                                size="sm"
                                onClick={() => setAddingNew(true)}
                                leftIcon={<Plus className="h-4 w-4" />}
                            >
                                Add Setting
                            </Button>
                        )}
                    </div>
                </div>

                <div className="p-6">
                    {/* Table */}
                    <div className="overflow-x-auto">
                        <table className="w-full">
                            <thead>
                                <tr className="border-b border-slate-200">
                                    <th className="text-left py-3 px-4 text-sm font-semibold text-slate-700">Scheme Type</th>
                                    <th className="text-left py-3 px-4 text-sm font-semibold text-slate-700">Center Share (%)</th>
                                    <th className="text-left py-3 px-4 text-sm font-semibold text-slate-700">State Share (%)</th>
                                    <th className="text-right py-3 px-4 text-sm font-semibold text-slate-700">Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {settings.map(setting => (
                                    <tr key={setting.scheme_type_id} className="border-b border-slate-100 hover:bg-slate-50">
                                        <td className="py-3 px-4">
                                            <div>
                                                <span className="font-medium text-slate-800">{setting.scheme_name}</span>
                                                <span className="ml-2 text-xs bg-slate-100 text-slate-600 px-2 py-0.5 rounded">{setting.scheme_code}</span>
                                            </div>
                                        </td>
                                        <td className="py-3 px-4">
                                            {editingRow === setting.scheme_type_id ? (
                                                <input
                                                    type="number"
                                                    value={editValues.center_share_percent}
                                                    onChange={(e) => handleCenterChange(e.target.value)}
                                                    className="w-24 rounded-lg border border-slate-300 px-3 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                                    min="0"
                                                    max="100"
                                                    step="0.01"
                                                />
                                            ) : (
                                                <span className="text-sm font-medium text-blue-700 bg-blue-50 px-2 py-1 rounded">{setting.center_share_percent}%</span>
                                            )}
                                        </td>
                                        <td className="py-3 px-4">
                                            {editingRow === setting.scheme_type_id ? (
                                                <input
                                                    type="number"
                                                    value={editValues.state_share_percent}
                                                    onChange={(e) => handleStateChange(e.target.value)}
                                                    className="w-24 rounded-lg border border-slate-300 px-3 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                                    min="0"
                                                    max="100"
                                                    step="0.01"
                                                />
                                            ) : (
                                                <span className="text-sm font-medium text-green-700 bg-green-50 px-2 py-1 rounded">{setting.state_share_percent}%</span>
                                            )}
                                        </td>
                                        <td className="py-3 px-4 text-right">
                                            {editingRow === setting.scheme_type_id ? (
                                                <div className="flex items-center justify-end gap-2">
                                                    <Button
                                                        type="button"
                                                        size="sm"
                                                        onClick={() => handleSave(setting.scheme_type_id)}
                                                        disabled={saving === setting.scheme_type_id}
                                                        leftIcon={<Save className="h-3.5 w-3.5" />}
                                                    >
                                                        {saving === setting.scheme_type_id ? 'Saving...' : 'Save'}
                                                    </Button>
                                                    <Button type="button" variant="ghost" size="sm" onClick={handleCancelEdit}>
                                                        Cancel
                                                    </Button>
                                                </div>
                                            ) : (
                                                <div className="flex items-center justify-end gap-2">
                                                    <Button type="button" variant="outline" size="sm" onClick={() => handleEdit(setting)}>
                                                        Edit
                                                    </Button>
                                                    <Button
                                                        type="button"
                                                        variant="ghost"
                                                        size="sm"
                                                        className="text-red-500 hover:text-red-700 hover:bg-red-50"
                                                        onClick={() => handleDelete(setting.scheme_type_id)}
                                                    >
                                                        <Trash2 className="h-4 w-4" />
                                                    </Button>
                                                </div>
                                            )}
                                        </td>
                                    </tr>
                                ))}

                                {/* Add new row */}
                                {addingNew && (
                                    <tr className="border-b border-slate-100 bg-blue-50/30">
                                        <td className="py-3 px-4">
                                            <select
                                                value={newSetting.scheme_type_id}
                                                onChange={(e) => setNewSetting(prev => ({ ...prev, scheme_type_id: e.target.value }))}
                                                className="w-full rounded-lg border border-slate-300 px-3 py-1.5 text-sm focus:ring-2 focus:ring-blue-500"
                                            >
                                                <option value="">Select Scheme Type</option>
                                                {availableSchemeTypes.map(st => (
                                                    <option key={st.scheme_type_id} value={st.scheme_type_id}>
                                                        {st.scheme_name} ({st.scheme_code})
                                                    </option>
                                                ))}
                                            </select>
                                        </td>
                                        <td className="py-3 px-4">
                                            <input
                                                type="number"
                                                value={newSetting.center_share_percent}
                                                onChange={(e) => handleCenterChange(e.target.value, true)}
                                                className="w-24 rounded-lg border border-slate-300 px-3 py-1.5 text-sm focus:ring-2 focus:ring-blue-500"
                                                placeholder="60"
                                                min="0"
                                                max="100"
                                                step="0.01"
                                            />
                                        </td>
                                        <td className="py-3 px-4">
                                            <input
                                                type="number"
                                                value={newSetting.state_share_percent}
                                                onChange={(e) => handleStateChange(e.target.value, true)}
                                                className="w-24 rounded-lg border border-slate-300 px-3 py-1.5 text-sm focus:ring-2 focus:ring-blue-500"
                                                placeholder="40"
                                                min="0"
                                                max="100"
                                                step="0.01"
                                            />
                                        </td>
                                        <td className="py-3 px-4 text-right">
                                            <div className="flex items-center justify-end gap-2">
                                                <Button
                                                    type="button"
                                                    size="sm"
                                                    onClick={handleAddNew}
                                                    disabled={saving === 'new'}
                                                    leftIcon={<Save className="h-3.5 w-3.5" />}
                                                >
                                                    {saving === 'new' ? 'Saving...' : 'Save'}
                                                </Button>
                                                <Button type="button" variant="ghost" size="sm" onClick={() => setAddingNew(false)}>
                                                    Cancel
                                                </Button>
                                            </div>
                                        </td>
                                    </tr>
                                )}

                                {settings.length === 0 && !addingNew && (
                                    <tr>
                                        <td colSpan={4} className="py-8 text-center text-slate-500 text-sm">
                                            No payment distribution settings configured yet.
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>

                    <div className="mt-4 p-3 bg-amber-50 border border-amber-200 rounded-lg">
                        <p className="text-sm text-amber-800">
                            <strong>How it works:</strong> After payroll deductions, the net salary is split based on these percentages.
                            For example, if an employee&apos;s net salary is ₹10,000 and their scheme type is OSC (Center: 60%, State: 40%),
                            then Center pays ₹6,000 and State pays ₹4,000.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default HRMSettings;
