import React, { useState, useEffect } from "react";
import { Download, Upload, FileSpreadsheet, AlertCircle, CheckCircle, ArrowLeft } from "lucide-react";
import { Link, useNavigate } from "react-router-dom";
import { PermissionGuard } from "../../../components/auth/PermissionGuard";
import DropdownSearch from "../../../components/common/DropdownSearch";
import { getDistricts, getSchemesWithTypes, getSchemeTypes } from "../../../services/master.service";
import { downloadBulkAttendanceTemplate, uploadBulkAttendance } from "../../../services/workforce.service";

const BulkAttendanceUpload = () => {
  const navigate = useNavigate();
  const [selectedFile, setSelectedFile] = useState(null);
  const [remarks, setRemarks] = useState("");
  const [loading, setLoading] = useState(false);
  const [uploadResult, setUploadResult] = useState(null);
  const [error, setError] = useState(null);

  // Template filters
  const [month, setMonth] = useState(new Date().getMonth() + 1);
  const [year, setYear] = useState(new Date().getFullYear());
  const [districtId, setDistrictId] = useState("");
  const [selectedSchemeType, setSelectedSchemeType] = useState("");
  const [schemeId, setSchemeId] = useState("");

  // Master data
  const [districts, setDistricts] = useState([]);
  const [schemes, setSchemes] = useState([]);
  const [schemeTypes, setSchemeTypes] = useState([]);

  useEffect(() => {
    fetchMasterData();
  }, []);

  // No auto-redirect - stay on current page after successful upload

  const handleDistrictChange = (value) => {
    setDistrictId(value);
    setSelectedSchemeType("");
    setSchemeId("");
    fetchSchemesAndTypes(value);
  };

  const handleSchemeTypeChange = (value) => {
    setSelectedSchemeType(value);
    setSchemeId("");
  };

  const fetchMasterData = async () => {
    try {
      const districtsRes = await getDistricts({ is_active: true });
      
      setDistricts(
        (districtsRes || []).map((d) => ({
          id: d.district_id,
          name: d.district_name,
        }))
      );
    } catch (err) {
      console.error("Error fetching master data:", err);
    }
  };

  const fetchSchemesAndTypes = async (districtId) => {
    try {
      const params = { is_active: true };
      if (districtId) {
        params.district_id = districtId;
      }

      const [schemesRes, schemeTypesRes] = await Promise.all([
        getSchemesWithTypes(params),
        getSchemeTypes({ is_active: true }),
      ]);

      const schemesData = (schemesRes?.schemes || schemesRes || []).map((s) => ({
        id: s.scheme_id,
        name: s.scheme_name,
        scheme_type_id: s.scheme_type_id,
      }));
      
      setSchemes(schemesData);
      setSchemeTypes(schemeTypesRes?.schemeTypes || schemeTypesRes || []);
    } catch (err) {
      console.error("Error fetching schemes and scheme types:", err);
    }
  };

  const handleDownloadTemplate = async () => {
    try {
      setLoading(true);
      setError(null);

      const params = { month, year };
      
      // Only send relevant filters based on selection
      if (districtId) params.district_id = districtId;
      if (selectedSchemeType) params.scheme_type_id = selectedSchemeType;
      if (schemeId) params.scheme_id = schemeId;

      const blob = await downloadBulkAttendanceTemplate(params);

      const url = window.URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `attendance_template_${month}_${year}.xlsx`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
    } catch (err) {
      console.error("Error downloading template:", err);
      const errorMessage = err.response?.data?.message || "Failed to download template";
      
      if (errorMessage.includes("No employees found")) {
        setError("No employees found with the selected filters. Try selecting a different district, scheme type, or scheme.");
      } else {
        setError(errorMessage);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (
        file.type === "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" ||
        file.type === "application/vnd.ms-excel"
      ) {
        setSelectedFile(file);
        setError(null);
      } else {
        setError("Please select a valid Excel file (.xlsx or .xls)");
        setSelectedFile(null);
      }
    }
  };

  const handleUpload = async () => {
    if (!selectedFile) {
      setError("Please select a file to upload");
      return;
    }

    try {
      setLoading(true);
      setError(null);
      setUploadResult(null);

      const result = await uploadBulkAttendance(selectedFile, {
        remarks: remarks,
      });

      setUploadResult(result.data);
      setSelectedFile(null);
      setRemarks("");

      // Reset file input
      const fileInput = document.getElementById("file-upload");
      if (fileInput) fileInput.value = "";
    } catch (err) {
      console.error("Error uploading file:", err);
      setError(err.response?.data?.message || "Failed to upload file");
    } finally {
      setLoading(false);
    }
  };

  const months = [
    { id: 1, name: "January" },
    { id: 2, name: "February" },
    { id: 3, name: "March" },
    { id: 4, name: "April" },
    { id: 5, name: "May" },
    { id: 6, name: "June" },
    { id: 7, name: "July" },
    { id: 8, name: "August" },
    { id: 9, name: "September" },
    { id: 10, name: "October" },
    { id: 11, name: "November" },
    { id: 12, name: "December" },
  ];

  const years = Array.from({ length: 5 }, (_, i) => {
    const y = new Date().getFullYear() - 2 + i;
    return { id: y, name: y.toString() };
  });

  return (
    <PermissionGuard permissions="hrm.attendance.bulk_upload">
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold text-slate-900">Bulk Attendance Upload</h1>
            <p className="text-sm text-slate-600 mt-1">
              Download template, fill attendance data, and upload
            </p>
          </div>
        </div>

        {/* Download Template Section */}
        <div className="bg-white rounded-lg shadow-sm border border-slate-200 p-6">
          <div className="flex items-center gap-2 mb-4">
            <Download className="w-5 h-5 text-blue-600" />
            <h2 className="text-lg font-semibold text-slate-900">Step 1: Download Template</h2>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 mb-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Year</label>
              <DropdownSearch
                value={year}
                onChange={(e) => setYear(parseInt(e.target.value))}
                options={years}
                placeholder="Select Year"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Month</label>
              <DropdownSearch
                value={month}
                onChange={(e) => setMonth(parseInt(e.target.value))}
                options={months}
                placeholder="Select Month"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">
                District (Optional)
              </label>
              <DropdownSearch
                value={districtId}
                onChange={(e) => handleDistrictChange(e.target.value)}
                options={districts}
                placeholder="All Districts"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">
                Scheme Type (Optional)
              </label>
              <DropdownSearch
                value={selectedSchemeType}
                onChange={(e) => handleSchemeTypeChange(e.target.value)}
                options={schemeTypes.map((t) => ({ id: t.scheme_type_id, name: t.scheme_name }))}
                placeholder={districtId ? "Select Scheme Type" : "Select District First"}
                disabled={!districtId}
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">
                Scheme (Optional)
              </label>
              <DropdownSearch
                value={schemeId}
                onChange={(e) => setSchemeId(e.target.value)}
                options={schemes.filter((s) =>
                  selectedSchemeType ? String(s.scheme_type_id) === String(selectedSchemeType) : true
                )}
                placeholder={districtId ? "Select Scheme" : "Select District First"}
                disabled={!districtId}
              />
            </div>

          <div className="flex items-center justify-center">
            <button
              onClick={handleDownloadTemplate}
              disabled={loading}
              className="group relative inline-flex items-center justify-center gap-3 px-8 py-4 bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-xl hover:from-blue-700 hover:to-blue-800 disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-200 text-sm font-semibold shadow-lg hover:shadow-xl transform hover:scale-[1.02] min-w-[180px]"
            >
              <div className="absolute inset-0 bg-white opacity-0 group-hover:opacity-10 rounded-xl transition-opacity"></div>
              <FileSpreadsheet className="w-5 h-5 relative z-10" />
              <span className="relative z-10">
                {loading ? "Downloading..." : "Download Template"}
              </span>
              {loading && (
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                </div>
              )}
            </button>
          </div>

          <div className="mt-4 p-4 bg-blue-50 rounded-lg border border-blue-200">
            <p className="text-sm text-blue-800">
              <strong>Note:</strong> The template will be pre-filled with employee data based on your
              filters. Fill in the attendance status for each day and upload the file.
            </p>
          </div>
        </div>

        {/* Upload Section */}
        <div className="bg-white rounded-lg shadow-sm border border-slate-200 p-6">
          <div className="flex items-center gap-2 mb-4">
            <Upload className="w-5 h-5 text-green-600" />
            <h2 className="text-lg font-semibold text-slate-900">Step 2: Upload Filled Template</h2>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">
                Select Excel File
              </label>
              <input
                id="file-upload"
                type="file"
                accept=".xlsx,.xls"
                onChange={handleFileChange}
                className="block w-full text-sm text-slate-500
                  file:mr-4 file:py-2 file:px-4
                  file:rounded-lg file:border-0
                  file:text-sm file:font-semibold
                  file:bg-blue-50 file:text-blue-700
                  hover:file:bg-blue-100
                  cursor-pointer"
              />
              {selectedFile && (
                <p className="mt-2 text-sm text-green-600 flex items-center gap-1">
                  <CheckCircle className="w-4 h-4" />
                  Selected: {selectedFile.name}
                </p>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">
                Remarks (Optional)
              </label>
              <input
                type="text"
                value={remarks}
                onChange={(e) => setRemarks(e.target.value)}
                placeholder="Enter any remarks"
                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
              />
            </div>

            <div className="flex flex-col sm:flex-row gap-3">
              <button
                onClick={handleUpload}
                disabled={loading || !selectedFile}
                className="inline-flex items-center justify-center gap-2 px-6 py-3 bg-green-600 text-white rounded-lg hover:bg-green-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors text-sm font-medium min-w-[140px]"
              >
                <Upload className="w-4 h-4" />
                {loading ? "Uploading..." : "Upload Attendance"}
              </button>
            </div>
          </div>
        </div>

        {/* Error Message */}
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-lg p-4 flex items-start gap-3">
            <AlertCircle className="w-5 h-5 text-red-600 flex-shrink-0 mt-0.5" />
            <div>
              <h3 className="text-sm font-semibold text-red-900">Error</h3>
              <p className="text-sm text-red-700 mt-1">{error}</p>
            </div>
          </div>
        )}

        {/* Success Message */}
        {uploadResult && (
          <div className="bg-green-50 border border-green-200 rounded-lg p-6">
            <div className="flex items-start gap-3">
              <CheckCircle className="w-6 h-6 text-green-600 flex-shrink-0 mt-0.5" />
              <div className="flex-1">
                <h3 className="text-lg font-semibold text-green-900">Upload Successful!</h3>
                <p className="text-sm text-green-700 mt-2">
                  Bulk No: <span className="font-bold">{uploadResult.bulk.bulk_no}</span> | 
                  Total Records: <span className="font-bold">{uploadResult.bulk.total_records}</span> | 
                  Status: <span className="font-bold text-amber-600">{uploadResult.bulk.status}</span>
                </p>
                <p className="text-sm text-green-700 mt-3">
                  Upload completed successfully!
                </p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
    </PermissionGuard>
  );
};

export default BulkAttendanceUpload;
