import React from "react";
import { MapPin } from "lucide-react";

export const DistrictAttendanceTable = ({ districtsData, schemeWiseData, onDistrictSelect }) => {
  // Get attendance color based on percentage
  const getAttendanceColor = (percentage) => {
    if (percentage >= 75) return { bg: '#dcfce7', text: '#166534' };
    if (percentage >= 50) return { bg: '#fef3c7', text: '#92400e' };
    if (percentage > 0) return { bg: '#fee2e2', text: '#991b1b' };
    return { bg: '#f3f4f6', text: '#6b7280' };
  };

  // Get all available scheme types dynamically
  const getAvailableSchemeTypes = () => {
    const schemeTypes = new Set();
    districtsData?.forEach(district => {
      if (district.schemes) {
        Object.keys(district.schemes).forEach(schemeType => {
          if (schemeType !== 'OTHER') {
            schemeTypes.add(schemeType);
          }
        });
      }
    });
    return Array.from(schemeTypes);
  };

  // Get scheme color dynamically
  const getSchemeColor = (schemeType, index) => {
    const colors = [
      { bg: '#fed7aa', text: '#ea580c' }, // Orange
      { bg: '#cad8fe', text: '#2626dc' }, // Blue
      { bg: '#e5e7eb', text: '#6b7280' }, // Gray
      { bg: '#ddd6fe', text: '#7c3aed' }, // Purple
      { bg: '#ccfbf1', text: '#0d9488' }, // Teal
    ];
    return colors[index % colors.length];
  };

  if (!districtsData || districtsData.length === 0) {
    return (
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-6">
        <div className="text-center text-slate-400 text-sm">
          No district data available
        </div>
      </div>
    );
  }

  const availableSchemeTypes = getAvailableSchemeTypes();

  return (
    <div className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden">
      <div className="px-3 py-2 border-b border-slate-100">
        <h3 className="font-semibold text-slate-700 text-xs flex items-center gap-2">
          <MapPin className="h-3 w-3 text-blue-500" />
          All Districts - Attendance Overview
        </h3>
      </div>
      
      <div className="overflow-x-auto">
        <table className="w-full">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-3 py-1 text-left text-[10px] font-medium text-slate-700">District</th>
              <th className="px-3 py-1 text-center text-[10px] font-medium text-slate-700">Total</th>
              <th className="px-3 py-1 text-center text-[10px] font-medium text-slate-700">Present</th>
              <th className="px-3 py-1 text-center text-[10px] font-medium text-slate-700">Attendance</th>
              {availableSchemeTypes.map((schemeType, index) => (
                <th key={schemeType} className="px-3 py-1 text-center text-[10px] font-medium text-slate-700">
                  {schemeType}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {districtsData.map((district, index) => {
              const attendanceColor = getAttendanceColor(district.attendance_percentage || 0);
              const schemes = district.schemes || {};
              
              return (
                <tr 
                  key={index}
                  className="hover:bg-slate-50 cursor-pointer transition-colors"
                  onClick={() => onDistrictSelect && onDistrictSelect(district)}
                >
                  <td className="px-3 py-1 text-xs font-medium text-slate-900">
                    {district.district_name}
                  </td>
                  <td className="px-3 py-1 text-xs text-center text-slate-600">
                    {district.total_employees || district.post_count || district.total || 0}
                  </td>
                  <td className="px-3 py-1 text-xs text-center text-slate-600">
                    {district.present_today || district.application_count || district.present || 0}
                  </td>
                  <td className="px-3 py-1 text-center">
                    <div 
                      className="inline-flex items-center px-1.5 py-0.5 rounded-full text-[10px] font-medium"
                      style={{
                        backgroundColor: attendanceColor.bg,
                        color: attendanceColor.text
                      }}
                    >
                      {district.attendance_percentage || 0}%
                    </div>
                  </td>
                  {availableSchemeTypes.map((schemeType, index) => (
                  <td key={schemeType} className="px-3 py-1 text-center">
                    {schemes[schemeType] ? (
                      <div className="space-y-0.5">
                        <div 
                          className="inline-flex items-center px-1 py-0.5 rounded text-[10px] font-medium"
                          style={{
                            backgroundColor: getSchemeColor(schemeType, index).bg,
                            color: getSchemeColor(schemeType, index).text
                          }}
                        >
                          {schemes[schemeType].present}/{schemes[schemeType].total}
                        </div>
                        <div className="text-[10px] text-slate-500">
                          {schemes[schemeType].percentage || 0}%
                        </div>
                      </div>
                    ) : (
                      <span className="text-slate-400 text-[10px]">-</span>
                    )}
                  </td>
                ))}
                                  </tr>
              );
            })}
          </tbody>
        </table>
      </div>
      
      <div className="px-3 py-2 border-t border-slate-100 bg-slate-50">
        <div className="text-[10px] text-slate-500">
          Click district row to filter
        </div>
      </div>
    </div>
  );
};
