import React, { useState, useMemo, useEffect, useCallback, useRef } from "react";
import { DataTable } from "../../../components/ui/DataTable";
import DropdownSearch from "../../../components/common/DropdownSearch";
import {
  getAttendanceSummary,
  markAttendance,
  downloadAttendancePDF,
  getShiftTypes,
} from "../../../services/workforce.service";
import { getDistricts, getSchemesWithTypes, getSchemeTypes } from "../../../services/master.service";
import { PermissionGuard } from "../../../components/auth/PermissionGuard";
import { usePermission } from "../../../hooks/usePermission";
import { FileText } from "lucide-react";
import toast from "react-hot-toast";

const MONTHS = [
  { id: "all", name: "All Months" },
  { id: "0", name: "January" },
  { id: "1", name: "February" },
  { id: "2", name: "March" },
  { id: "3", name: "April" },
  { id: "4", name: "May" },
  { id: "5", name: "June" },
  { id: "6", name: "July" },
  { id: "7", name: "August" },
  { id: "8", name: "September" },
  { id: "9", name: "October" },
  { id: "10", name: "November" },
  { id: "11", name: "December" },
];


const formatDate = (date) => {
  const d = new Date(date);

  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");

  return `${year}-${month}-${day}`;
};

// Generate year options (current year ± 5 years)
const getYearOptions = () => {
  const currentYear = new Date().getFullYear();
  const years = [];
  for (let i = currentYear - 5; i <= currentYear + 2; i++) {
    years.push({ id: String(i), name: String(i) });
  }
  return years;
};

const AttendanceSummary = () => {
  const { hasPermission } = usePermission();
  const [selectedMonth, setSelectedMonth] = useState(
    String(new Date().getMonth()),
  );
  const [selectedYear, setSelectedYear] = useState(
    String(new Date().getFullYear()),
  );
  const [selectedDistrict, setSelectedDistrict] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const prevSearchRef = useRef("");

  const [records, setRecords] = useState([]);
  const [districts, setDistricts] = useState([]);
  const [schemes, setSchemes] = useState([]);
  const [filteredSchemes, setFilteredSchemes] = useState([]);
  const [loading, setLoading] = useState(false);

  const [summary, setSummary] = useState({});

  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  const [filterType, setFilterType] = useState("all");
  const [schemeId, setSchemeId] = useState("");
  const [pdfLoading, setPdfLoading] = useState(false);
  const [schemeTypes, setSchemeTypes] = useState([]);
  const [selectedSchemeType, setSelectedSchemeType] = useState("");

  const [selectedEmployee, setSelectedEmployee] = useState(null);
  const [date, setDate] = useState("");
  const [status, setStatus] = useState("");
  const [remarks, setRemarks] = useState("");
  const [shiftTypes, setShiftTypes] = useState([]);
  const [shiftType, setShiftType] = useState("");

  const fetchSummary = useCallback(async () => {
    try {
      setLoading(true);

      const params = {
        year: Number(selectedYear) || new Date().getFullYear(), // Default to current year
        page,
        limit,
        district_id: selectedDistrict || undefined,
        search: searchQuery || undefined,
      };
      
      // Only add month if not "All Months"
      if (selectedMonth !== "all") {
        params.month = Number(selectedMonth) + 1;
      } else {
        params.yearly = true; // Use yearly flag for full year data
      }

      // Add filter_type and scheme filters
      if (selectedDistrict) {
        params.filter_type = filterType || "all";
        if (schemeId) {
          params.scheme_id = schemeId;
        } else if (selectedSchemeType) {
          params.scheme_type_id = selectedSchemeType;
        }
      }
      
      const res = await getAttendanceSummary(params);

      setRecords(res?.data?.employees?.data || []);
      setTotalPages(res?.data?.employees?.pagination?.totalPages || 1);
      setTotalItems(res?.data?.employees?.pagination?.total || 0);
      setSummary(res?.data?.summary || {});
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [page, limit, selectedMonth, selectedYear, selectedDistrict, searchQuery, filterType, schemeId, selectedSchemeType]);

  const fetchDistricts = async () => {
    try {
      const res = await getDistricts({ is_active: true });
      setDistricts(
        (res || []).map((d) => ({
          id: d.district_id,
          name: d.district_name,
        })),
      );
    } catch (err) {
      console.error(err);
    }
  };

  const fetchComponentsAndHubs = async (districtId) => {
    try {
      const params = { is_active: true };
      if (districtId) {
        params.district_id = districtId;
      }

      const [schemesRes, schemeTypesRes] = await Promise.all([
        getSchemesWithTypes(params),
        getSchemeTypes({ is_active: true }),
      ]);

      const schemesData = (schemesRes?.schemes || schemesRes || []).map((s) => ({
        id: s.scheme_id,
        name: s.scheme_name,
        scheme_type_id: s.scheme_type_id,
      }));
      
      setSchemes(schemesData);
      setFilteredSchemes(schemesData);
      
      setSchemeTypes(schemeTypesRes?.schemeTypes || schemeTypesRes || []);
    } catch (err) {
      console.error("Error fetching schemes and scheme types:", err);
    }
  };

  const handleDistrictChange = (value) => {
    setSelectedDistrict(value);
    setFilterType("all");
    setSchemeId("");
    setSelectedSchemeType("");
    fetchComponentsAndHubs(value);
  };

  useEffect(() => {
    fetchSummary();
  }, [fetchSummary]);

  useEffect(() => {
    fetchDistricts();
  }, []);

  const handleSearch = useCallback((value) => {
    // Only reset page to 1 if search value actually changed
    if (value !== prevSearchRef.current) {
      prevSearchRef.current = value;
      setSearchQuery(value);
      setPage(1);
    }
  }, []);

  // Fetch shift types
  const fetchShiftTypes = async () => {
    try {
      const response = await getShiftTypes();
      // Handle both response formats: direct array or nested in data property
      const shiftTypesData = response?.data || response || [];
      setShiftTypes(Array.isArray(shiftTypesData) ? shiftTypesData : []);
    } catch (error) {
      console.error("Failed to fetch shift types:", error);
      setShiftTypes([]); // Ensure shiftTypes is always an array
    }
  };

  useEffect(() => {
    if (selectedEmployee) {
      setDate(new Date().toISOString().split("T")[0]);
    }
  }, [selectedEmployee]);

  useEffect(() => {
    fetchShiftTypes();
  }, []);

  const filtered = useMemo(() => records, [records]);

  const handleGenerateEmployeePDF = async (row) => {
    if (!row?.employee_id) {
      alert("Employee not found for PDF download");
      return;
    }

    try {
      setPdfLoading(true);

      const params = {
        employee_id: row.employee_id,
        year: Number(selectedYear) || new Date().getFullYear(),
        district_id: selectedDistrict || undefined,
        search: row.employee_code || searchQuery || undefined,
      };

      if (selectedMonth !== "all") {
        params.month = Number(selectedMonth) + 1;
      } else {
        params.yearly = true;
      }

      params.filter_type = filterType || "all";
      if (schemeId) {
        params.scheme_id = schemeId;
      } else if (selectedSchemeType) {
        params.scheme_type_id = selectedSchemeType;
      }

      await downloadAttendancePDF(params, `attendance-${row.employee_code || row.employee_id}.pdf`);
    } catch (err) {
      console.error("Error generating employee PDF:", err);
      alert("Failed to generate employee PDF. Please try again.");
    } finally {
      setPdfLoading(false);
    }
  };

  const columns = useMemo(
    () => [
      {
        key: "employee_code",
        header: "Emp Code",
        render: (_, row) => (
          <span className="font-mono text-xs text-slate-700">{row.employee_code || "-"}</span>
        ),
      },
      { 
        key: "name", 
        header: "Name", 
        render: (_, row) => (
          <span className="font-medium text-slate-900">{row.name || "-"}</span>
        ) 
      },
      {
        key: "district",
        header: "District",
        render: (_, row) => (
          <span className="text-xs text-slate-700">{row.district || "-"}</span>
        ),
      },
      {
        key: "scheme_name",
        header: "Scheme",
        render: (_, row) => (
          <span className="text-xs text-slate-700">{row.scheme_name || "-"}</span>
        ),
      },
      {
        key: "working_days",
        header: "Working Days",
        render: (_, row) => (
          <span className="text-sm font-medium text-slate-800">{row.working_days || 0}</span>
        ),
      },
      {
        key: "present",
        header: "Present",
        render: (_, row) => (
          <span className="text-sm font-semibold text-green-600">{row.present}</span>
        ),
      },
      {
        key: "absent",
        header: "Absent",
        render: (_, row) => (
          <span className="text-sm font-semibold text-red-600">{row.absent}</span>
        ),
      },
      {
        key: "on_leave",
        header: "On Leave",
        render: (_, row) => (
          <span className="text-sm font-semibold text-amber-600">{row.on_leave}</span>
        ),
      },
      {
        key: "half_day",
        header: "Half Day",
        render: (_, row) => (
          <span className="text-sm font-semibold text-purple-600">{row.half_day ?? 0}</span>
        ),
      },
      {
        key: "attendance_percentage",
        header: "Attendance %",
        render: (_, row) => (
          <span className="text-sm font-semibold text-blue-600">{row.attendance_percentage || 0}%</span>
        ),
      },

      {
        key: "action",
        header: "Action",
        render: (_, row) => (
          <div className="flex items-center gap-2">
            {hasPermission("hrm.attendance.manage") && (
              <button
                onClick={() => setSelectedEmployee(row)}
                className="text-xs bg-blue-600 text-white px-2 py-1 rounded"
              >
                Mark
              </button>
            )}
            <button
              type="button"
              onClick={() => handleGenerateEmployeePDF(row)}
              disabled={pdfLoading}
              className="text-xs bg-emerald-600 text-white px-2 py-1 rounded disabled:opacity-50"
            >
              PDF
            </button>
          </div>
        ),
      },
    ],
    [handleGenerateEmployeePDF, hasPermission, pdfLoading],
  );

  const handleGeneratePDF = async () => {
    // Validate district selection
    if (!selectedDistrict) {
      alert("Please select a district to generate PDF");
      return;
    }

    try {
      setPdfLoading(true);

      const params = {
        district_id: selectedDistrict,
        search: searchQuery || undefined,
      };

      // Add date filter - use same logic as records page
      if (selectedMonth !== "all") {
        params.month = Number(selectedMonth) + 1;
        params.year = Number(selectedYear) || new Date().getFullYear();
      } else {
        // For "All Months", use the entire year
        params.from_date = `${selectedYear}-01-01`;
        params.to_date = `${selectedYear}-12-31`;
      }

      // Add filter_type and scheme filters matching the list filters
      params.filter_type = filterType || "all";
      if (selectedDistrict) {
        if (schemeId) params.scheme_id = schemeId;
        else if (selectedSchemeType) params.scheme_type_id = selectedSchemeType;
      }

      // Call service function to download PDF
      await downloadAttendancePDF(params);
    } catch (err) {
      console.error("Error generating PDF:", err);
      alert("Failed to generate PDF. Please try again.");
    } finally {
      setPdfLoading(false);
    }
  };

  const submitAttendance = async () => {
    try {
      const payload = {
        employee_ids: [selectedEmployee.employee_id],
        attendance_date: formatDate(date),
        status: status.toUpperCase(),
        remarks: remarks || "",
        shift_type_id: shiftType ? parseInt(shiftType) : null,
      };

      await markAttendance(payload);

      setSelectedEmployee(null);
      setShiftType("");
      fetchSummary();
      toast.success("Attendance marked successfully");
    } catch (err) {
      console.error(err.response?.data);
      toast.error(err.response?.data?.message || "Failed to mark attendance");
    }
  };

  return (
    <div className="space-y-4">
      {/* SUMMARY CARDS */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">

        <div className="bg-white p-4 rounded-xl shadow-sm">
          <p className="text-xs text-gray-500">Present</p>
          <p className="text-xl font-bold text-green-600">
            {summary.total_present || 0}
          </p>
        </div>

        <div className="bg-white p-4 rounded-xl shadow-sm">
          <p className="text-xs text-gray-500">Absent</p>
          <p className="text-xl font-bold text-red-500">
            {summary.total_absent || 0}
          </p>
        </div>

        <div className="bg-white p-4 rounded-xl shadow-sm">
          <p className="text-xs text-gray-500">On Leave</p>
          <p className="text-xl font-bold text-amber-500">
            {summary.total_on_leave || 0}
          </p>
        </div>

        <div className="bg-white p-4 rounded-xl shadow-sm">
          <p className="text-xs text-gray-500">Half Day (count)</p>
          <p className="text-xl font-bold text-purple-600">
            {summary.total_half_day || 0}
          </p>
        </div>

        <div className="bg-white p-4 rounded-xl shadow-sm">
          <p className="text-xs text-gray-500">Attendance %</p>
          <p className="text-xl font-bold text-blue-600">
            {summary.attendance_percentage || 0}%
          </p>
        </div>
      </div>

      {/* FILTER */}
      <div className="flex items-center justify-between gap-3 flex-wrap">
        <div className="flex items-center gap-3 flex-wrap">
          <div className="w-32">
            <select
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-400/30 focus:border-indigo-400"
            >
              {MONTHS.map((month) => (
                <option key={month.id} value={month.id}>
                  {month.name}
                </option>
              ))}
            </select>
          </div>
          <div className="w-24">
            <select
              value={selectedYear}
              onChange={(e) => setSelectedYear(e.target.value)}
              className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-400/30 focus:border-indigo-400"
            >
              {getYearOptions().map((year) => (
                <option key={year.id} value={year.id}>
                  {year.name}
                </option>
              ))}
            </select>
          </div>
          <div className="w-48">
            <DropdownSearch
              value={selectedDistrict}
              onChange={(e) => handleDistrictChange(e.target.value)}
              options={districts}
              placeholder="Select District"
            />
          </div>

          {selectedDistrict && (
            <>
              <div className="w-48">
                <DropdownSearch
                  value={selectedSchemeType}
                  onChange={(e) => {
                    setSelectedSchemeType(e.target.value);
                    setSchemeId("");
                  }}
                  options={schemeTypes.map((t) => ({ id: t.scheme_type_id, name: t.scheme_name }))}
                  placeholder="Scheme Type"
                />
              </div>

              <div className="w-48">
                <DropdownSearch
                  value={schemeId}
                  onChange={(e) => setSchemeId(e.target.value)}
                  options={schemes.filter((s) =>
                    selectedSchemeType
                      ? String(s.scheme_type_id) === String(selectedSchemeType)
                      : true
                  )}
                  placeholder="Select Scheme"
                />
              </div>
            </>
          )}
        </div>

        {/* PDF Download Button */}
        {selectedDistrict && (
          <button
            onClick={handleGeneratePDF}
            disabled={pdfLoading}
            className="inline-flex items-center gap-2 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <FileText className="w-4 h-4" />
            {pdfLoading ? "Generating..." : "Download Summary PDF"}
          </button>
        )}
      </div>

      {/* TABLE */}
      <DataTable
      enableSelection={false}
        columns={columns}
        data={filtered}
        onSearch={handleSearch}
        pagination={{
          currentPage: page,
          totalPages: totalPages,
          totalItems: totalItems,
          onPageChange: setPage,
          pageSize: limit,
          onPageSizeChange: (newLimit) => {
            setLimit(newLimit);
            setPage(1);
          },
          pageSizeOptions: [10, 25, 50],
        }}
        isLoading={loading}
        rowKey="employee_id"
        headerClassName="bg-slate-900 text-white"
        showRowNumbers={true}
      />

      {/* MODAL */}
      {selectedEmployee && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-2xl max-w-md w-full">
            {/* Header */}
            <div className="border-b border-gray-200 px-6 py-4">
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-lg font-semibold text-gray-900">Mark Attendance</h3>
                  <p className="text-sm text-gray-500 mt-1">Update attendance record for employee</p>
                </div>
                <button
                  onClick={() => setSelectedEmployee(null)}
                  className="text-gray-400 hover:text-gray-600 transition-colors"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>
            </div>

            {/* Body */}
            <div className="px-6 py-4 space-y-4">
              {/* Employee Info */}
              <div className="bg-gray-50 rounded-lg p-3">
                <div className="flex items-center space-x-3">
                  <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center">
                    <svg className="w-5 h-5 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                    </svg>
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">{selectedEmployee.name}</p>
                    <p className="text-sm text-gray-500">Employee Code: {selectedEmployee.employee_code}</p>
                  </div>
                </div>
              </div>

              {/* Date Field */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Attendance Date <span className="text-red-500">*</span>
                </label>
                <input
                  type="date"
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                  required
                />
              </div>

              {/* Status Field */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Status <span className="text-red-500">*</span>
                </label>
                <select
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
                  value={status}
                  onChange={(e) => setStatus(e.target.value)}
                  required
                >
                  <option value="">Select Status</option>
                  <option value="PRESENT">Present</option>
                  <option value="ABSENT">Absent</option>
                  <option value="HALF_DAY">Half Day</option>
                  <option value="ON_LEAVE">Leave</option>
                  <option value="WEEKLY_OFF">Weekly Off</option>
                </select>
              </div>

              {/* Shift Type Field */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Shift Type <span className="text-gray-400">(Optional)</span>
                </label>
                <select
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
                  value={shiftType}
                  onChange={(e) => setShiftType(e.target.value)}
                >
                  <option value="">Select Shift Type</option>
                  {shiftTypes.map((shift) => (
                    <option key={shift.shift_type_id} value={shift.shift_type_id}>
                      {shift.shift_name}
                    </option>
                  ))}
                </select>
                <p className="text-xs text-gray-500 mt-1">Optional: Select shift type for better tracking</p>
              </div>

              {/* Remarks Field */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Remarks <span className="text-red-500">*</span>
                </label>
                <textarea
                  placeholder="Enter remarks for this attendance change..."
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors resize-none"
                  rows={3}
                  value={remarks}
                  onChange={(e) => setRemarks(e.target.value)}
                  required
                />
                <p className="text-xs text-gray-500 mt-1">Remarks are mandatory when updating attendance</p>
              </div>
            </div>

            {/* Footer */}
            <div className="border-t border-gray-200 px-6 py-4">
              <div className="flex justify-end space-x-3">
                <button
                  onClick={() => setSelectedEmployee(null)}
                  className="px-4 py-2 text-gray-700 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors font-medium"
                >
                  Cancel
                </button>
                <button
                  onClick={submitAttendance}
                  disabled={!date || !status || !remarks?.trim()}
                  className="px-4 py-2 bg-blue-600 hover:bg-blue-700 disabled:bg-gray-300 disabled:cursor-not-allowed text-white rounded-lg transition-colors font-medium"
                >
                  Mark Attendance
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AttendanceSummary;
