import React, { useState, useMemo, useEffect, useCallback, useRef } from "react";
import { DataTable } from "../../../components/ui/DataTable";
import DropdownSearch from "../../../components/common/DropdownSearch";
import { getLeaveSummary } from "../../../services/workforce.service";
import { getDistricts, getSchemesWithTypes, getSchemeTypes } from "../../../services/master.service";

const MONTHS = [
  { id: "0", name: "January" },
  { id: "1", name: "February" },
  { id: "2", name: "March" },
  { id: "3", name: "April" },
  { id: "4", name: "May" },
  { id: "5", name: "June" },
  { id: "6", name: "July" },
  { id: "7", name: "August" },
  { id: "8", name: "September" },
  { id: "9", name: "October" },
  { id: "10", name: "November" },
  { id: "11", name: "December" },
];

const LeaveSummary = () => {
  const [selectedDistrict, setSelectedDistrict] = useState("");
  const [selectedMonth, setSelectedMonth] = useState(
    String(new Date().getMonth()),
  );
  const [searchQuery, setSearchQuery] = useState("");
  const prevSearchRef = useRef("");

  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [rawLeaveTypes, setRawLeaveTypes] = useState([]);
  const [districts, setDistricts] = useState([]);
  const [schemes, setSchemes] = useState([]);
  const [schemeTypes, setSchemeTypes] = useState([]);
  const [selectedSchemeType, setSelectedSchemeType] = useState("");
  const [schemeId, setSchemeId] = useState("");
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  const fetchDistricts = async () => {
    try {
      const [districtsRes, schemeTypesRes] = await Promise.all([
        getDistricts({ is_active: true }),
        getSchemeTypes({ is_active: true }),
      ]);

      setDistricts(
        (districtsRes || []).map((d) => ({
          id: d.district_id,
          name: d.district_name,
        })),
      );
      
      setSchemeTypes(schemeTypesRes?.schemeTypes || schemeTypesRes || []);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchSchemes = async (districtId, schemeTypeId) => {
    try {
      const params = { is_active: true };
      if (districtId) params.district_id = districtId;
      if (schemeTypeId) params.scheme_type_id = schemeTypeId;
      
      console.log("Fetching schemes with params:", params);
      const res = await getSchemesWithTypes(params);
      console.log("Schemes API response:", res);
      
      const schemesData = (res?.data || res || []).map((s) => ({
        id: s.scheme_id,
        name: s.scheme_name,
        scheme_type_id: s.scheme_type_id,
        district_id: s.district_id,
      }));
      
      console.log("Processed schemes data:", schemesData);
      setSchemes(schemesData);
    } catch (err) {
      console.error("Error fetching schemes:", err);
    }
  };

  // Leave Summary API
  const fetchSummary = useCallback(async () => {
    try {
      setLoading(true);

      const params = {
        month: Number(selectedMonth) + 1,
        page,
        limit,
      };

      if (selectedDistrict) {
        params.district_id = selectedDistrict;
      }

      if (selectedSchemeType) {
        params.scheme_type_id = selectedSchemeType;
      }

      if (schemeId) {
        params.scheme_id = schemeId;
      }

      if (searchQuery) {
        params.search = searchQuery;
      }

      const res = await getLeaveSummary(params);

      const raw = res?.data || {};

      const employees = raw.records || [];
      const leaveTypes = raw.summary?.leave_types || [];

      setRawLeaveTypes(leaveTypes);

      // ✅ pagination set
      setTotalPages(raw.pagination?.totalPages || 1);
      setTotalItems(raw.pagination?.total || 0);

      const formatted = employees.map((emp, index) => {
        // Get unified balance (same for all types)
        const firstLeaveType = leaveTypes[0];
        const unifiedBalance = emp.leave_balances?.[firstLeaveType?.leave_code] || {};
        
        return {
          id: emp.employee_id || index + 1,
          employee_code: emp.employee_code || "-",
          name: emp.full_name,
          district: emp.district_name,
          post: emp.post_name,
          status: emp.employment_status,
          total_allocated: unifiedBalance.allocated || 11,
          total_used: emp.total_used_days ?? 0,
          total_remaining: unifiedBalance.balance || (11 - (emp.total_used_days ?? 0)),
          pending: emp.pending_count ?? 0,
          approved: emp.approved_count ?? 0,
          rejected: emp.rejected_count ?? 0,
          applications_count: emp.applications_count ?? 0,
        };
      });

      setData(formatted);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [selectedMonth, selectedDistrict, selectedSchemeType, schemeId, page, limit, searchQuery]);

  useEffect(() => {
    fetchSummary();
  }, [fetchSummary]);

  useEffect(() => {
    fetchDistricts();
    fetchSchemes("", ""); // Initial load with no filters
  }, []);

  const handleSearch = useCallback((value) => {
    // Only reset page to 1 if search value actually changed
    if (value !== prevSearchRef.current) {
      prevSearchRef.current = value;
      setSearchQuery(value);
      setPage(1);
    }
  }, []);

  const monthName = MONTHS.find((m) => m.id === selectedMonth)?.name || "";

  // Columns
  const columns = useMemo(() => {
    const baseColumns = [
      { key: "employee_code", header: "Emp Code", sortable: true },
      {
        key: "name",
        header: "Name",
        sortable: true,
        render: (_, row) => (
          <span className="font-medium text-slate-800">{row.name}</span>
        ),
      },
      { key: "district", header: "District", sortable: true },
      { key: "post", header: "Post", sortable: true },
    ];

    const leaveColumns = [
      {
        key: "total_allocated",
        header: "Allocated",
        render: (_, row) => (
          <span className="text-sm font-bold text-blue-600">{row.total_allocated}</span>
        ),
      },
      {
        key: "total_used",
        header: "Used",
        render: (_, row) => (
          <span className={`font-bold ${
            row.total_used >= 8
              ? "text-orange-700"
              : row.total_used >= 4
                ? "text-yellow-600"
                : "text-orange-500"
          }`}>
            {row.total_used}
          </span>
        ),
      },
      {
        key: "total_remaining",
        header: "Remaining",
        render: (_, row) => (
          <span className={`font-bold ${
            row.total_remaining <= 2 ? 'text-red-600' : row.total_remaining <= 5 ? 'text-amber-600' : 'text-green-600'
          }`}>
            {row.total_remaining}
          </span>
        ),
      },
    ];

    const statusColumns = [
      {
        key: "pending",
        header: "Pending",
        render: (_, row) => (
          <span className="text-amber-600 font-medium">{row.pending}</span>
        ),
      },
      {
        key: "approved",
        header: "Approved", 
        render: (_, row) => (
          <span className="text-green-600 font-medium">{row.approved}</span>
        ),
      },
      {
        key: "rejected",
        header: "Rejected", 
        render: (_, row) => (
          <span className="text-red-600 font-medium">{row.rejected}</span>
        ),
      },
      {
        key: "applications_count",
        header: "Total",
        render: (_, row) => (
          <span className="text-slate-700 font-medium">{row.applications_count}</span>
        ),
      },
    ];

    return [...baseColumns, ...leaveColumns, ...statusColumns];
  }, [rawLeaveTypes]);

  return (
    <div className="space-y-4">
      {/* Filters */}
      <div className="flex items-center justify-between gap-3 flex-wrap">
        <div className="flex items-center gap-3 flex-wrap">
          <div className="w-44">
            <DropdownSearch
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              options={MONTHS}
              placeholder="Select Month"
            />
          </div>

          <div className="w-44">
            <DropdownSearch
              value={selectedDistrict}
              onChange={(e) => {
                setSelectedDistrict(e.target.value);
                setSelectedSchemeType("");
                setSchemeId("");
                fetchSchemes(e.target.value, "");
              }}
              options={districts}
              placeholder="All Districts"
            />
          </div>

          {selectedDistrict && (
            <>
              <div className="w-44">
                <DropdownSearch
                  value={selectedSchemeType}
                  onChange={(e) => {
                    setSelectedSchemeType(e.target.value);
                    setSchemeId("");
                    fetchSchemes(selectedDistrict, e.target.value);
                  }}
                  options={schemeTypes.map((t) => ({ id: t.scheme_type_id, name: t.scheme_name }))}
                  placeholder="Scheme Type"
                />
              </div>

              <div className="w-44">
                <DropdownSearch
                  value={schemeId}
                  onChange={(e) => setSchemeId(e.target.value)}
                  options={(() => {
                    const filtered = schemes.filter((s) =>
                      selectedSchemeType
                        ? String(s.scheme_type_id) === String(selectedSchemeType)
                        : true
                    );
                    console.log("Scheme dropdown options:", {
                      selectedSchemeType,
                      totalSchemes: schemes.length,
                      filteredSchemes: filtered.length,
                      schemes: schemes,
                      filtered: filtered
                    });
                    return filtered;
                  })()}
                  placeholder="Select Scheme"
                />
              </div>
            </>
          )}
        </div>

      </div>

      {/* Table */}
      <DataTable
        columns={columns}
        data={data}
        onSearch={handleSearch}
        pagination={{
          currentPage: page,
          totalPages,
          totalItems,
          onPageChange: setPage,
          pageSize: limit,
          onPageSizeChange: (l) => {
            setLimit(l);
            setPage(1);
          },
          pageSizeOptions: [10, 25, 50],
        }}
        isLoading={loading}
        rowKey="id"
        headerClassName="bg-slate-900 text-white"
        showRowNumbers={true}
        enableSelection={false}
      />
    </div>
  );
};

export default LeaveSummary;
