import React, {
  useState,
  useMemo,
  useEffect,
  useCallback,
  useRef,
} from "react";
import { Eye, Pencil, RefreshCw, Download, FileSpreadsheet } from "lucide-react";
import { useSearchParams } from "react-router-dom";
import { DataTable } from "../../../components/ui/DataTable";
import DropdownSearch from "../../../components/common/DropdownSearch";
import { getEmployees, exportEmployees } from "../../../services/workforce.service";
import {
  getDistricts,
  getSchemesWithTypes,
  getSchemeTypes,
} from "../../../services/master.service";
import toast from "react-hot-toast";

const EmployeeRecords = () => {
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(true);

  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  const [selectedScheme, setSelectedScheme] = useState("");
  const [selectedDistrict, setSelectedDistrict] = useState("");
  const [selectedSchemeType, setSelectedSchemeType] = useState("");

  const [schemeOptions, setSchemeOptions] = useState([]);
  const [schemeTypes, setSchemeTypes] = useState([]);
  const [districtOptions, setDistrictOptions] = useState([]);
  const [exportLoading, setExportLoading] = useState(false);

  const [, setSearchParams] = useSearchParams();
  const [searchQuery, setSearchQuery] = useState("");
  const prevSearchRef = useRef("");

  const handleSearch = useCallback((value) => {
    // Only reset page to 1 if search value actually changed
    if (value !== prevSearchRef.current) {
      prevSearchRef.current = value;
      setSearchQuery(value);
      setPage(1);
    }
  }, []);

  // Load masters
  useEffect(() => {
    const loadMasters = async () => {
      try {
        const [schemes, schemeTypes, districts] = await Promise.all([
          getSchemesWithTypes({ is_active: true }),
          getSchemeTypes({ is_active: true }),
          getDistricts({ is_active: true }),
        ]);

        // Group schemes by type
        const schemesByType = schemeTypes.reduce((acc, type) => {
          acc[type.scheme_type_id] = {
            ...type,
            schemes: schemes.filter(scheme => scheme.scheme_type_id === type.scheme_type_id)
          };
          return acc;
        }, {});

        setSchemeOptions(
          (schemes || []).map((s) => ({ 
            id: s.scheme_id, 
            name: s.scheme_name, 
            district_id: s.district_id,
            scheme_type_id: s.scheme_type_id
          }))
        );
        setSchemeTypes(schemeTypes || []);
        setDistrictOptions(
          (districts || []).map((d) => ({ id: d.district_id, name: d.district_name }))
        );
      } catch {
        toast.error("Failed to load master data");
      }
    };
    loadMasters();
  }, []);

  // Fetch employees
  const fetchEmployees = useCallback(async () => {
    setLoading(true);
    try {
      const res = await getEmployees({
        page,
        limit,
        search: searchQuery || undefined,
        district_id: selectedDistrict || undefined,
        scheme_id: selectedScheme || undefined,
        scheme_type_id: selectedSchemeType || undefined,
      });

      setEmployees(res?.data?.data || []);
      setTotalPages(res?.data?.pagination?.totalPages || 1);
      setTotalItems(res?.data?.pagination?.total || 0);
    } catch (err) {
      toast.error(err.message || "Failed to load employees");
    } finally {
      setLoading(false);
    }
  }, [page, limit, selectedDistrict, selectedScheme, selectedSchemeType, searchQuery]);

  // Group schemes by type like we did for OSC/Hub
  const schemesByType = schemeTypes.reduce((acc, type) => {
    acc[type.scheme_type_id] = {
      ...type,
      schemes: schemeOptions.filter(scheme => scheme.scheme_type_id === type.scheme_type_id)
    };
    return acc;
  }, {});

  // Filter schemes by district and scheme type
  const filteredSchemesByType = useMemo(() => {
    return Object.keys(schemesByType).reduce((acc, typeId) => {
      const type = schemesByType[typeId];
      
      // First filter by scheme type if selected
      if (selectedSchemeType && String(typeId) !== String(selectedSchemeType)) {
        return acc;
      }
      
      // Then filter by district if selected
      acc[typeId] = {
        ...type,
        schemes: selectedDistrict 
          ? type.schemes.filter(scheme => String(scheme.district_id) === String(selectedDistrict))
          : type.schemes
      };
      return acc;
    }, {});
  }, [selectedDistrict, selectedSchemeType, schemeOptions, schemeTypes]);

  useEffect(() => {
    fetchEmployees();
  }, [fetchEmployees]);

  // Status logic
  const getStatus = (employmentStatus, is_active, endDate) => {
    // If employment_status is set and not ACTIVE/INACTIVE, show it directly
    if (employmentStatus && employmentStatus !== 'ACTIVE' && employmentStatus !== 'INACTIVE') {
      return employmentStatus.charAt(0).toUpperCase() + employmentStatus.slice(1).toLowerCase().replace('_', ' ');
    }
    
    // If employee is inactive, show Inactive
    if (is_active === false) {
      return "Inactive";
    }
    
    // If employment_status is ACTIVE, show Active
    if (employmentStatus === 'ACTIVE') {
      return "Active";
    }
    
    // Fallback to contract date calculation if employment_status is not set
    if (!endDate) return "Unknown";
    const today = new Date();
    const end = new Date(endDate);
    return end < today ? "Expired" : "Active";
  };

  // Columns
  const columns = useMemo(
    () => [
      { key: "employee_code", header: "Emp Code" },

      {
        key: "name",
        header: "Employee",
        render: (_, r) => (
          <div>
            <div className="font-medium">
              {r.applicant?.personal?.full_name}
            </div>
            <div className="text-xs text-gray-400">
              {r.applicant?.email}
            </div>
          </div>
        ),
      },

      {
        key: "location",
        header: "Location",
        render: (_, r) => (
          <div>
            <div>{r.district?.district_name}</div>
            <div className="text-xs text-gray-400">
              {r.scheme?.scheme_name || "-"}
            </div>
          </div>
        ),
      },

      {
        key: "post",
        header: "Post",
        render: (_, r) => r.post?.post_name || "-",
      },

      {
        key: "contract",
        header: "Contract",
        render: (_, r) => (
          <div>
            <div>
              {new Date(r.contract_start_date).toLocaleDateString("en-IN")}
            </div>
            <div className="text-xs text-gray-400">
              {new Date(r.contract_end_date).toLocaleDateString("en-IN")}
            </div>
          </div>
        ),
      },

      {
        key: "account_status",
        header: "Account Status",
        render: (_, r) => (
          <span
            className={`px-2 py-0.5 text-xs rounded-full ${
              r.is_active
                ? "bg-green-50 text-green-700"
                : "bg-red-50 text-red-700"
            }`}
          >
            {r.is_active ? "Active" : "Inactive"}
          </span>
        ),
      },

      {
        key: "status",
        header: "Employment Status",
        render: (_, r) => {
          const status = getStatus(r.employment_status, r.is_active, r.contract_end_date);
          return (
            <span
              className={`px-2 py-0.5 text-xs rounded-full ${
                status === "Active"
                  ? "bg-green-50 text-green-700"
                  : status === "Inactive"
                  ? "bg-gray-50 text-gray-700"
                  : status === "On Leave"
                  ? "bg-yellow-50 text-yellow-700"
                  : status === "Suspended"
                  ? "bg-orange-50 text-orange-700"
                  : status === "Terminated"
                  ? "bg-red-50 text-red-700"
                  : status === "Resigned"
                  ? "bg-purple-50 text-purple-700"
                  : status === "Contract Ended"
                  ? "bg-blue-50 text-blue-700"
                  : "bg-gray-50 text-gray-700"
              }`}
            >
              {status}
            </span>
          );
        },
      },

      {
        key: "actions",
        header: "Actions",
        render: (_, row) => (
          <div className="flex gap-1">
            <button
              className="p-2 text-blue-600 hover:bg-blue-50 rounded-full"
              title="View"
              onClick={() =>
                setSearchParams({
                  tab: "employees",
                  subtab: "employee-view",
                  id: row.employee_id,
                  fromTab: "employee-records",
                })
              }
            >
              <Eye className="h-4 w-4" />
            </button>
            <button
              className="p-2 text-amber-600 hover:bg-amber-50 rounded-full"
              title="Edit"
              onClick={() =>
                setSearchParams({
                  tab: "employees",
                  subtab: "employee-edit",
                  id: row.employee_id,
                  fromTab: "employee-records",
                })
              }
            >
              <Pencil className="h-4 w-4" />
            </button>
          </div>
        ),
      },
    ],
    [setSearchParams],
  );

  // Handle export - backend generates files, just download
  const handleExportExcel = async () => {
    try {
      setExportLoading(true);
      const params = {
        search: searchQuery || undefined,
        district_id: selectedDistrict || undefined,
        scheme_id: selectedScheme || undefined,
        scheme_type_id: selectedSchemeType || undefined,
      };
      console.log('Export params:', params);
      await exportEmployees(params, 'excel');
      toast.success('Excel downloaded');
    } catch (err) {
      toast.error(err.message || "Export failed");
    } finally {
      setExportLoading(false);
    }
  };

  const handleExportPDF = async () => {
    try {
      setExportLoading(true);
      await exportEmployees({
        search: searchQuery || undefined,
        district_id: selectedDistrict || undefined,
        scheme_id: selectedScheme || undefined,
        scheme_type_id: selectedSchemeType || undefined,
      }, 'pdf');
      toast.success('PDF downloaded');
    } catch (err) {
      toast.error(err.message || "Export failed");
    } finally {
      setExportLoading(false);
    }
  };

  return (
    <div className="space-y-4">
      {/* Filter Section */}
      <div className="bg-white p-4 rounded-xl shadow-sm">
        <div className="flex flex-col gap-4">
          {/* Primary Filters Row */}
          <div className="flex flex-wrap gap-3 items-center">
            {/* District Filter */}
            <DropdownSearch
              value={selectedDistrict}
              onChange={(e) => {
                setSelectedDistrict(e.target.value);
                setSelectedScheme("");
                setSelectedSchemeType("");
              }}
              options={districtOptions}
              placeholder="All Districts"
            />

            {/* Scheme Type Filter */}
            <DropdownSearch
              value={selectedSchemeType}
              onChange={(e) => {
                setSelectedSchemeType(e.target.value);
                setSelectedScheme("");
              }}
              options={schemeTypes.map(type => ({
                id: type.scheme_type_id,
                name: type.scheme_name
              }))}
              placeholder="All Scheme Types"
            />

            {/* Scheme Filter */}
            <DropdownSearch
              value={selectedScheme}
              onChange={(e) => setSelectedScheme(e.target.value)}
              options={Object.values(filteredSchemesByType).flatMap(type => 
                type.schemes.map(scheme => ({
                  id: scheme.id,
                  name: `${scheme.name} (${type.scheme_name})`,
                  group: type.scheme_name
                }))
              )}
              placeholder="All Schemes"
            />

            
            {/* Action Buttons */}
            <div className="flex gap-2 ml-auto">
              <button
                onClick={fetchEmployees}
                className="flex items-center gap-2 px-3 py-2 rounded-lg hover:bg-slate-100 text-slate-600 transition-colors text-sm font-medium"
                title="Refresh"
              >
                <RefreshCw className="h-4 w-4" />
                Refresh
              </button>

              {/* Export Buttons */}
              <button
                onClick={handleExportExcel}
                disabled={exportLoading}
                title="Export to Excel"
                className="flex items-center gap-2 px-3 py-2 rounded-lg border-blue-200 text-blue-700 hover:bg-blue-50 text-sm font-medium transition-all disabled:opacity-40 disabled:cursor-not-allowed"
              >
                {exportLoading ? (
                  <RefreshCw className="h-4 w-4 animate-spin" />
                ) : (
                  <FileSpreadsheet className="h-4 w-4" />
                )}
                Excel
              </button>

              <button
                onClick={handleExportPDF}
                disabled={exportLoading}
                title="Export to PDF"
                className="flex items-center gap-2 px-3 py-2 rounded-lg border-red-200 text-red-700 hover:bg-red-50 text-sm font-medium transition-all disabled:opacity-40 disabled:cursor-not-allowed"
              >
                {exportLoading ? (
                  <RefreshCw className="h-4 w-4 animate-spin" />
                ) : (
                  <Download className="h-4 w-4" />
                )}
                PDF
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Table */}
      <DataTable
  columns={columns}
  data={employees}
  isLoading={loading}
  enableSelection={false}
  showRowNumbers={true}
  rowKey="employee_id"
  onSearch={handleSearch} 
  pagination={{
    currentPage: page,
    totalPages,
    totalItems,
    onPageChange: setPage,
    pageSize: limit,
    onPageSizeChange: (newLimit) => {
      setLimit(newLimit);
      setPage(1);
    },
    pageSizeOptions: [10, 25, 50, 100],
  }}
/>
    </div>
  );
};

export default EmployeeRecords;