import React, { useState, useMemo, useEffect } from "react";
import { DataTable } from "../../../components/ui/DataTable";
import { Button } from "../../../components/common/Button";
import { PUBLIC_FILE_BASE_URL } from "../../../config/appConfig";
import {
  CheckCircle2,
  XCircle,
  X,
  CalendarDays,
  User,
  MapPin,
  Clock,
  PauseCircle,
  Wallet,
  AlertTriangle,
} from "lucide-react";
import toast from "react-hot-toast";
import {
  getLeaveApprovals,
  updateLeaveStatus,
} from "../../../services/workforce.service";
import { PermissionGuard } from "../../../components/auth/PermissionGuard";
import { usePermission } from "../../../hooks/usePermission";

const STATUS_CONFIG = {
  Approved: { bg: "bg-green-50", text: "text-green-700", dot: "bg-green-500" },
  Pending: { bg: "bg-amber-50", text: "text-amber-700", dot: "bg-amber-400" },
  Rejected: { bg: "bg-red-50", text: "text-red-700", dot: "bg-red-500" },
};

const getStatusBadge = (status) => {
  const c = STATUS_CONFIG[status] || {
    bg: "bg-slate-100",
    text: "text-slate-500",
    dot: "bg-slate-400",
  };

  return (
    <span
      className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold ${c.bg} ${c.text}`}
    >
      <span className={`w-1.5 h-1.5 rounded-full ${c.dot}`} />
      {status}
    </span>
  );
};

const ActionButtons = ({ row, onOpen }) => (
  <div className="flex items-center justify-center gap-1">
    <button onClick={() => onOpen(row, "Approved")}>
      <CheckCircle2 className="h-5 w-5 text-green-600" />
    </button>

    <button onClick={() => onOpen(row, "Rejected")}>
      <XCircle className="h-5 w-5 text-red-500" />
    </button>
  </div>
);

const ACTION_META = {
  Approved: {
    label: "Approve Leave",
    color: "bg-green-600 hover:bg-green-700",
    header: "bg-green-600",
    icon: CheckCircle2,
    remarkRequired: false,
  },
  Rejected: {
    label: "Reject Leave",
    color: "bg-red-500 hover:bg-red-600",
    header: "bg-red-500",
    icon: XCircle,
    remarkRequired: true,
  },
};

const ApprovalModal = ({ leave, action, onClose, onConfirm }) => {
  const [remark, setRemark] = useState("");
  const [loading, setLoading] = useState(false);
  const balance = leave.leave_balance;
  const canBePaid = balance?.can_be_paid ?? false;
  const [isPaid, setIsPaid] = useState(canBePaid);

  const meta = ACTION_META[action];
  const Icon = meta.icon;

  const handleConfirm = async () => {
    console.log('Modal handleConfirm called:', { action, remark, isPaid });
    
    if (meta.remarkRequired && !remark.trim()) {
      console.log('Remark required validation failed');
      toast.error("Please enter a remark");
      return;
    }

    setLoading(true);
    try {
      console.log('Calling onConfirm from modal');
      await onConfirm(leave.id, action, remark, action === "Approved" ? isPaid : undefined);
      console.log('onConfirm completed successfully');
    } catch (err) {
      console.error('Error in modal handleConfirm:', err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div
        className="absolute inset-0 bg-black/40 backdrop-blur-sm"
        onClick={onClose}
      />

      <div className="relative w-full max-w-md bg-white rounded-2xl shadow-2xl max-h-[90vh] flex flex-col">
        <div
          className={`px-6 py-4 flex items-center justify-between ${meta.header}`}
        >
          <div className="flex items-center gap-2">
            <Icon className="h-5 w-5 text-white" />
            <h2 className="text-sm font-semibold text-white">{meta.label}</h2>
          </div>
          <button
            onClick={onClose}
            className="text-white/70 hover:text-white transition-colors"
          >
            <X className="h-4 w-4" />
          </button>
        </div>

        <div className="p-6 space-y-5 overflow-y-auto flex-1">
          <div className="bg-slate-50 rounded-xl border border-slate-200 p-4 space-y-3">
            <div className="flex items-center gap-3">
              <div className="h-9 w-9 rounded-xl bg-slate-900 flex items-center justify-center text-xs font-bold text-white">
                {leave.full_name
                  ?.split(" ")
                  .map((w) => w[0])
                  .join("")
                  .slice(0, 2)}
              </div>
              <div>
                <p className="text-sm font-bold text-slate-800">
                  {leave.full_name}
                </p>
                <p className="text-xs text-slate-400 font-mono">
                  {leave.employee_code}
                </p>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2.5 pt-1">
              <div className="flex items-center gap-2 text-xs text-slate-600">
                <Clock className="h-3.5 w-3.5 text-slate-400" />
                {leave.leave_type}
              </div>

              <div className="flex items-center gap-2 text-xs text-slate-600 col-span-2">
                <CalendarDays className="h-3.5 w-3.5 text-slate-400" />
                {leave.from_date} → {leave.to_date}
              </div>

              <div className="flex items-center gap-2 text-xs text-slate-600">
                <User className="h-3.5 w-3.5 text-slate-400" />
                {leave.days} day{leave.days > 1 ? "s" : ""}
              </div>
            </div>

            <div className="pt-2 border-t border-slate-200">
              <p className="text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-1">
                Reason
              </p>
              <p className="text-xs text-slate-600">{leave.reason}</p>
            </div>
            {leave.document && (
              <div className="pt-2 border-t border-slate-200 space-y-2">
                <p className="text-[10px] font-bold uppercase tracking-widest text-slate-400">
                  Document
                </p>

                <button
                  onClick={() => window.open(leave.document, "_blank")}
                  className="text-blue-600 underline text-xs"
                >
                  View Image
                </button>
              </div>
            )}
          </div>

          {action === "Approved" && balance && (
            <div className="bg-blue-50 rounded-xl border border-blue-200 p-4 space-y-3">
              <div className="flex items-center gap-2">
                <Wallet className="h-4 w-4 text-blue-600" />
                <p className="text-xs font-bold uppercase tracking-widest text-blue-700">
                  Leave Balance
                </p>
              </div>
              <div className="grid grid-cols-3 gap-2">
                <div className="text-center p-2 bg-white rounded-lg">
                  <p className="text-lg font-bold text-slate-800">{balance.total_allocated}</p>
                  <p className="text-[10px] text-slate-400">Allocated</p>
                </div>
                <div className="text-center p-2 bg-white rounded-lg">
                  <p className="text-lg font-bold text-orange-600">{balance.used}</p>
                  <p className="text-[10px] text-slate-400">Used</p>
                </div>
                <div className="text-center p-2 bg-white rounded-lg">
                  <p className={`text-lg font-bold ${balance.remaining > 0 ? 'text-green-600' : 'text-red-600'}`}>{balance.remaining}</p>
                  <p className="text-[10px] text-slate-400">Remaining</p>
                </div>
              </div>

              {!canBePaid && (
                <div className="flex items-center gap-2 bg-amber-50 border border-amber-200 rounded-lg p-2">
                  <AlertTriangle className="h-4 w-4 text-amber-500 flex-shrink-0" />
                  <p className="text-xs text-amber-600 font-medium">Note: Insufficient balance ({balance.remaining} days for {leave.days} day{leave.days > 1 ? 's' : ''}). Consider marking as UNPAID.</p>
                </div>
              )}

              <div className="space-y-2">
                <p className="text-xs font-semibold uppercase tracking-widest text-slate-400">Leave Type</p>
                <div className="flex gap-3">
                  <label
                    className={`flex-1 flex items-center justify-center gap-2 p-3 rounded-xl border-2 cursor-pointer transition-all ${
                      isPaid
                        ? 'border-green-500 bg-green-50 text-green-700'
                        : 'border-slate-200 bg-white text-slate-500 hover:border-slate-300'
                    }`}
                  >
                    <input
                      type="radio"
                      name="leavePayType"
                      checked={isPaid}
                      onChange={() => setIsPaid(true)}
                      className="sr-only"
                    />
                    <Wallet className="h-4 w-4" />
                    <span className="text-sm font-semibold">Paid</span>
                  </label>
                  <label
                    className={`flex-1 flex items-center justify-center gap-2 p-3 rounded-xl border-2 cursor-pointer transition-all ${
                      !isPaid
                        ? 'border-amber-500 bg-amber-50 text-amber-700'
                        : 'border-slate-200 bg-white text-slate-500 hover:border-slate-300'
                    }`}
                  >
                    <input
                      type="radio"
                      name="leavePayType"
                      checked={!isPaid}
                      onChange={() => setIsPaid(false)}
                      className="sr-only"
                    />
                    <XCircle className="h-4 w-4" />
                    <span className="text-sm font-semibold">Unpaid</span>
                  </label>
                </div>
              </div>
            </div>
          )}

          <div className="space-y-2">
            <p className="text-xs font-semibold uppercase tracking-widest text-slate-400">
              Remark{" "}
              {meta.remarkRequired && <span className="text-red-400">*</span>}
            </p>
            <textarea
              rows={3}
              value={remark}
              onChange={(e) => setRemark(e.target.value)}
              placeholder={
                meta.remarkRequired
                  ? "Remark required..."
                  : "Optional remark..."
              }
              className="w-full rounded-xl border border-slate-200 bg-slate-50 px-4 py-3 text-sm outline-none focus:border-slate-400 focus:bg-white"
            />
          </div>
        </div>

        <div className="flex justify-end gap-3 px-6 py-4 border-t bg-slate-50">
          <Button variant="outline" onClick={onClose}>
            Cancel
          </Button>

          <button
            onClick={handleConfirm}
            disabled={loading}
            className={`px-5 py-2 rounded-xl text-sm font-semibold text-white ${meta.color}`}
          >
            {loading ? "Processing..." : meta.label}
          </button>
        </div>
      </div>
    </div>
  );
};

const LeaveApprovals = () => {
  const { hasPermission } = usePermission();
  const [leaves, setLeaves] = useState([]);
  const [modal, setModal] = useState(null);

  const [loading, setLoading] = useState(false);
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  const openModal = (leave, action) => setModal({ leave, action });
  const closeModal = () => setModal(null);
  const fetchLeaves = async () => {
    try {
      setLoading(true);

      const res = await getLeaveApprovals({
        status: "PENDING",
        page,
        limit,
      });

      const raw = res?.data?.records || [];

      const formatted = raw.map((item) => ({
        id: item.leave_id,
        employee_code: item.employee?.employee_code,
        full_name: item.employee_name || "-",
        leave_type: item.leaveType?.leave_name || "-",
        from_date: item.from_date,
        to_date: item.to_date,
        days: item.total_days || "-",
        reason: item.reason,
        document: item.supporting_document_path
          ? `${PUBLIC_FILE_BASE_URL.replace(/\/$/, "")}/${item.supporting_document_path}`
          : null,
        status:
          item.status === "PENDING"
            ? "Pending"
            : item.status === "APPROVED"
              ? "Approved"
              : "Rejected",
        leave_balance: item.leave_balance || null,
      }));

      setLeaves(formatted);
      setTotalPages(res?.data?.data?.pagination?.totalPages || 1);
      setTotalItems(res?.data?.data?.pagination?.total || 0);

      setLeaves(formatted);
      setTotalPages(res?.data?.pagination?.totalPages || 1);
      setTotalItems(res?.data?.pagination?.total || 0);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchLeaves();
  }, [page, limit]);

  // Action
  const handleConfirm = async (id, action, remark, isPaid) => {
    if (!hasPermission("hrm.leave.manage")) {
      toast.error("Unauthorized");
      return;
    }

    try {
      console.log('Starting leave action:', { id, action, isPaid });
      
      const statusMap = {
        Approved: "APPROVED",
        Rejected: "REJECTED",
      };

      const payload = {
        status: statusMap[action],
      };

      if (action === "Rejected" || action === "Hold") {
        payload.rejection_reason = remark;
      }

      if (action === "Approved" && isPaid !== undefined) {
        payload.is_paid = isPaid;
      }

      console.log('Sending payload:', payload);
      const response = await updateLeaveStatus(id, payload);
      console.log('API response:', response);

      fetchLeaves();
      console.log('Showing success toast');
      toast.success(`Leave ${action.toLowerCase()} successfully`);
      closeModal();
    } catch (err) {
      console.error('Error in leave action:', err);
      console.log('Error response:', err.response?.data);
      
      // Display specific validation error if available
      if (err.response?.data?.errors && Array.isArray(err.response.data.errors)) {
        const firstError = err.response.data.errors[0];
        console.log('Showing field error toast:', firstError.message);
        toast.error(firstError.message || "Validation failed");
      } else {
        console.log('Showing general error toast:', err.response?.data?.message);
        toast.error(err.response?.data?.message || "Action failed");
      }
    }
  };

  // Table Columns
  const columns = useMemo(
    () => [
      { key: "employee_code", header: "Emp Code" },
      { key: "full_name", header: "Name" },
      { key: "leave_type", header: "Leave Type" },
      { key: "from_date", header: "From" },
      { key: "to_date", header: "To" },
      { key: "days", header: "Days" },
      { key: "reason", header: "Reason" },
      {
        key: "status",
        header: "Status",
        render: (_, row) => getStatusBadge(row.status),
      },
      {
        key: "actions",
        header: "Actions",
        render: (_, row) =>
          row.status !== "Pending" ? (
            <span className="text-xs text-slate-400 italic">—</span>
          ) : hasPermission("hrm.leave.manage") ? (
            <ActionButtons row={row} onOpen={openModal} />
          ) : (
            <span className="text-xs text-slate-400 italic">No Access</span>
          ),
      },
    ],
    [],
  );

  return (
    <>
      <DataTable
        columns={columns}
        data={leaves}
        pagination={{
          currentPage: page,
          totalPages,
          totalItems,
          onPageChange: setPage,
          pageSize: limit,
          onPageSizeChange: (l) => {
            setLimit(l);
            setPage(1);
          },
          pageSizeOptions: [10, 25, 50],
        }}
        isLoading={loading}
        rowKey="id"
        headerClassName="bg-slate-900 text-white"
        showRowNumbers={true}
        enableSelection={false}
      />

      {modal && (
        <ApprovalModal
          leave={modal.leave}
          action={modal.action}
          onClose={closeModal}
          onConfirm={handleConfirm}
        />
      )}
    </>
  );
};

export default LeaveApprovals;
