import React from "react";
import { Users, CalendarCheck, MapPin, X } from "lucide-react";

export const SimpleDistrictInfo = ({ selectedDistrict, schemeWiseData, onClearFilter }) => {
  // Get data to display
  const getDisplayData = () => {
    if (selectedDistrict) {
      // Show selected district data - try multiple field name variations
      return {
        name: selectedDistrict.district_name,
        total_employees: selectedDistrict.total_employees || selectedDistrict.post_count || selectedDistrict.total || 0,
        present_today: selectedDistrict.present_today || selectedDistrict.application_count || selectedDistrict.present || 0,
        attendance_percentage: selectedDistrict.attendance_percentage || 0,
        schemes: selectedDistrict.schemes || {}
      };
    } else {
      // Show overall state data - calculate from schemes
      if (!schemeWiseData?.schemes) {
        return null;
      }
      
      // Calculate totals from schemes data
      const totals = schemeWiseData.schemes.reduce((acc, scheme) => {
        if (scheme.scheme_type && scheme.scheme_type !== 'OTHER') {
          acc.total += scheme.total || 0;
          acc.present += scheme.present || 0;
        }
        return acc;
      }, { total: 0, present: 0 });
      
      const percentage = totals.total > 0 ? Math.round((totals.present / totals.total) * 100) : 0;
      
      return {
        name: "Maharashtra State",
        total_employees: totals.total,
        present_today: totals.present,
        attendance_percentage: percentage,
        schemes: {}
      };
    }
  };

  const data = getDisplayData();
  
  if (!data) {
    return (
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-4">
        <div className="text-center text-slate-400 text-sm">
          No attendance data available
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-4">
      <div className="flex items-center justify-between mb-3">
        <h3 className="font-semibold text-slate-700 text-sm flex items-center gap-2">
          <MapPin className="h-4 w-4 text-blue-500" />
          {data.name} - Attendance Summary
        </h3>
      </div>
      
      <div className="grid grid-cols-3 gap-3 mb-3">
        <div className="text-center">
          <div className="text-2xl font-bold text-slate-900">
            {data.total_employees.toLocaleString()}
          </div>
          <div className="text-xs text-slate-500">Total Employees</div>
        </div>
        
        <div className="text-center">
          <div className="text-2xl font-bold text-green-600">
            {data.present_today.toLocaleString()}
          </div>
          <div className="text-xs text-slate-500">Present Today</div>
        </div>
        
        <div className="text-center">
          <div className="text-2xl font-bold text-blue-600">
            {data.attendance_percentage}%
          </div>
          <div className="text-xs text-slate-500">Attendance Rate</div>
        </div>
      </div>

      {/* Scheme breakdown if available */}
      {Object.keys(data.schemes).length > 0 && (
        <div className="border-t border-slate-100 pt-3">
          <div className="text-xs text-slate-500 mb-3">Scheme Breakdown:</div>
          <div className="space-y-2">
            {Object.entries(data.schemes)
              .filter(([schemeType]) => schemeType !== 'OTHER')
              .map(([schemeType, schemeData]) => {
              const percentage = schemeData.total > 0 
                ? Math.round((schemeData.present / schemeData.total) * 100) 
                : 0;
              
              const colorClass = schemeType === 'OSC' ? 'text-orange-500' : 'text-red-500';
              const bgClass = schemeType === 'OSC' ? 'bg-orange-50' : 'bg-red-50';
              
              return (
                <div key={schemeType} className={`flex items-center justify-between p-2 rounded-lg ${bgClass} border border-opacity-20 ${schemeType === 'OSC' ? 'border-orange-200' : 'border-red-200'}`}>
                  <div className="flex items-center gap-2">
                    <div className={`w-2 h-2 rounded-full ${schemeType === 'OSC' ? 'bg-orange-400' : 'bg-red-400'}`}></div>
                    <span className={`font-semibold text-sm ${colorClass}`}>{schemeType}</span>
                  </div>
                  <div className="flex items-center gap-3">
                    <div className="text-right">
                      <div className="font-bold text-base text-slate-900">
                        {schemeData.present}/{schemeData.total}
                      </div>
                      <div className="text-xs text-slate-500">
                        {percentage}%
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};
