import React, { useState, useEffect, useCallback } from "react";
import {
  Users,
  CalendarCheck,
  CalendarOff,
  FileText,
  Star,
  MapPin,
  TrendingUp,
  Clock,
  AlertCircle,
  ClipboardList,
  RefreshCw,
  Filter,
  Download,
  X,
  ChevronDown,
  Building,
  Grid3x3
} from "lucide-react";
import { getSchemeWiseAttendance, downloadSchemeWiseAttendancePDF } from "../../../services/workforce.service";
import { getDistricts, getSchemesWithTypes, getSchemeTypes } from "../../../services/master.service";
import DropdownSearch from "../../../components/common/DropdownSearch";
import EnhancedMaharashtraMap from "../../../components/dashboard/EnhancedMaharashtraMap";
import { SimpleDistrictInfo } from "../../../components/dashboard/SimpleDistrictInfo";
import { DistrictAttendanceTable } from "../../../components/dashboard/DistrictAttendanceTable";
import toast from 'react-hot-toast';

const EnhancedAttendanceDashboard = () => {
  const [schemeWiseData, setSchemeWiseData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [schemeLoading, setSchemeLoading] = useState(false);
  const [error, setError] = useState(null);
  const [filters, setFilters] = useState({
    district_id: '',
    scheme_type: '',
    date: new Date().toISOString().split('T')[0]
  });
  const [districts, setDistricts] = useState([]);
  const [schemes, setSchemes] = useState([]);
  const [filteredSchemes, setFilteredSchemes] = useState([]);
  const [schemeTypes, setSchemeTypes] = useState([]);
  const [pdfLoading, setPdfLoading] = useState(false);
  const [selectedDistrict, setSelectedDistrict] = useState(null);
  const [mapSummaryData, setMapSummaryData] = useState([]);
  const [fullDistrictData, setFullDistrictData] = useState([]); // Store full district list for map
  const [schemeLocations, setSchemeLocations] = useState([]);

  
  // Transform attendance data for map visualization
  const transformDataForMap = (attendanceData) => {
    if (!attendanceData?.districts) return [];
    
    return attendanceData.districts.map(district => ({
      district_name: district.district_name,
      district_id: district.district_id,
      application_count: district.present_today || 0, // Use present_today as application_count for map
      post_count: district.total_employees || 0, // Use total_employees as post_count for map
      attendance_percentage: district.attendance_percentage || 0,
      schemes: district.schemes || {}
    }));
  };

  // Fetch scheme locations with lat/long data
  const fetchSchemeLocations = async () => {
    try {
      // Use schemeWiseData to get scheme locations with attendance data
      if (!schemeWiseData?.schemes) return;
      
      const locations = schemeWiseData.schemes
        .filter(scheme => scheme.scheme_type && scheme.scheme_type !== 'OTHER' && scheme.latitude && scheme.longitude)
        .map(scheme => ({
          scheme_id: scheme.scheme_id,
          scheme_name: scheme.scheme_name,
          scheme_type: scheme.scheme_type,
          district_name: scheme.district_name,
          latitude: parseFloat(scheme.latitude),
          longitude: parseFloat(scheme.longitude),
          total_employees: scheme.total || 0,
          present_today: scheme.present || 0,
          attendance_percentage: scheme.percentage || 0
        }));
      
      setSchemeLocations(locations);
    } catch (err) {
      console.error('Failed to fetch scheme locations:', err);
    }
  };

  // Fetch scheme-wise attendance data
  const fetchSchemeWiseData = async () => {
    try {
      setSchemeLoading(true);
      const activeFilters = Object.fromEntries(
        Object.entries(filters).filter(([_, value]) => value !== '')
      );
      
      const result = await getSchemeWiseAttendance(activeFilters);
      const data = result?.data || result;
      
      setSchemeWiseData(data);
      
      // If no district filter, store full district data for map
      if (!activeFilters.district_id) {
        const mapData = transformDataForMap(data);
        setFullDistrictData(mapData);
        setMapSummaryData(mapData);
      } else {
        // When filtered, use full district data for map but filtered data for other components
        setMapSummaryData(fullDistrictData);
      }
      
      // Fetch scheme locations
      await fetchSchemeLocations();
    } catch (err) {
      console.error('Failed to fetch scheme-wise data:', err);
      toast.error('Failed to fetch scheme-wise attendance data');
    } finally {
      setSchemeLoading(false);
    }
  };

  // Fetch districts for filtering - following attendance records pattern
  const fetchDistricts = async () => {
    try {
      const res = await getDistricts({ is_active: true });
      setDistricts(
        (res?.data || res || []).map((d) => ({
          id: d.district_id,
          name: d.district_name,
        })),
      );
    } catch (err) {
      console.error(err);
    }
  };

  // Fetch schemes for filtering - following attendance records pattern
  const fetchSchemes = async (districtId) => {
    try {
      const params = { is_active: true };
      if (districtId) params.district_id = districtId;
      const res = await getSchemesWithTypes(params);
      const schemesData = (res?.data || res?.schemes || res || []).map((s) => ({
        id: s.scheme_id,
        name: s.scheme_name,
        scheme_type: s.scheme_type,
        scheme_type_id: s.scheme_type_id, // Keep for compatibility
      }));
      setSchemes(schemesData);
      setFilteredSchemes(schemesData);
    } catch (err) {
      console.error("Error fetching schemes:", err);
    }
  };

  // Handle district change - following attendance records pattern
  const handleDistrictChange = (value) => {
    setFilters(prev => ({ ...prev, district_id: value, scheme_id: '', scheme_type: '' }));
    fetchSchemes(value);
  };

  // Handle clickable progress bars
  const handleDistrictClick = (district) => {
    setFilters(prev => ({
      ...prev,
      district_id: prev.district_id === district.district_id ? '' : district.district_id
    }));
  };

  const handleSchemeClick = (schemeType) => {
    setFilters(prev => ({
      ...prev,
      scheme_type: prev.scheme_type === schemeType ? '' : schemeType
    }));
  };

  // Handle district selection from map
  const handleMapDistrictSelect = (districtData) => {
    if (districtData) {
      // Find the full district data from schemeWiseData to get correct field names
      const fullDistrictData = schemeWiseData?.districts?.find(d => 
        d.district_id?.toString() === districtData.district_id?.toString() ||
        d.district_name === districtData.district_name
      );
      
      // Use the full district data if available, otherwise use the map data
      const districtToSelect = fullDistrictData || {
        ...districtData,
        total_employees: districtData.post_count || 0,
        present_today: districtData.application_count || 0
      };
      
      setSelectedDistrict(districtToSelect);
      
      const newFilterValue = districtData.district_id?.toString() || '';
      
      // Update filters and fetch data in sequence
      setFilters({
        district_id: newFilterValue,
        scheme_type: filters.scheme_type,
        date: filters.date
      });
      
      fetchSchemeWiseData();
    } else {
      setSelectedDistrict(null);
      setFilters({
        district_id: '',
        scheme_type: filters.scheme_type,
        date: filters.date
      });
      fetchSchemeWiseData();
    }
  };

  // PDF Generation - Works for both filtered and non-filtered data
  const handleGeneratePDF = async () => {
    try {
      setPdfLoading(true);

      const params = {
        date: filters.date,
      };

      // Add filters only if they're selected
      if (filters.district_id) {
        params.district_id = filters.district_id;
      }
      if (filters.scheme_type) {
        params.scheme_type = filters.scheme_type;
      }
      if (filters.scheme_id) {
        params.scheme_id = filters.scheme_id;
      }

      // Call service function to download PDF
      await downloadSchemeWiseAttendancePDF(params);
    } catch (err) {
      console.error("Error generating PDF:", err);
      alert("Failed to generate PDF. Please try again.");
    } finally {
      setPdfLoading(false);
    }
  };

  useEffect(() => {
    fetchSchemeWiseData();
    fetchDistricts();
    getSchemeTypes({ is_active: true })
      .then((res) => setSchemeTypes(res?.schemeTypes || res || []))
      .catch(console.error);
  }, []);

  useEffect(() => {
    fetchSchemeWiseData();
  }, [filters]);

  
  
  // Get color based on percentage
  const getAttendanceColor = (percentage) => {
    if (percentage >= 80) return '#10b981';
    if (percentage >= 60) return '#f59e0b';
    return '#ef4444';
  };

  // Get scheme color
  const getSchemeColor = (schemeType) => {
    const colors = {
      'OSC': '#3b82f6',
      'HUB': '#10b981',
      'OTHER': '#6b7280'
    };
    return colors[schemeType] || '#6b7280';
  };

  // Handle filter changes
  const handleFilterChange = (key, value) => {
    setFilters(prev => ({
      ...prev,
      [key]: value
    }));
    
    // If district filter changes, update selectedDistrict and fetch new data
    if (key === 'district_id') {
      if (value) {
        // Find the district data and set it as selected
        const district = schemeWiseData?.districts?.find(d => d.district_id?.toString() === value);
        if (district) {
          setSelectedDistrict(district);
        }
      } else {
        // Clear district selection
        setSelectedDistrict(null);
      }
      // Fetch data with new filter immediately
      fetchSchemeWiseData();
    }
  };

  // Clear all filters
  const clearFilters = () => {
    setFilters({
      district_id: '',
      scheme_type: '',
      date: new Date().toISOString().split('T')[0]
    });
    setSelectedDistrict(null);
  };

  // Download PDF
  const handleDownloadPDF = async () => {
    try {
      const activeFilters = Object.fromEntries(
        Object.entries(filters).filter(([_, value]) => value !== '')
      );
      await downloadSchemeWiseAttendancePDF(activeFilters);
      toast.success('PDF downloaded successfully');
    } catch (err) {
      toast.error('Failed to download PDF');
    }
  };

  if (loading && !schemeWiseData) {
    return (
      <div className="flex items-center justify-center h-64">
        <RefreshCw className="h-8 w-8 animate-spin text-blue-500" />
        <span className="ml-2 text-gray-600">Loading dashboard...</span>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-64">
        <AlertCircle className="h-12 w-12 text-red-500 mb-4" />
        <p className="text-red-600 font-medium">{error}</p>
        <button
          onClick={fetchSchemeWiseData}
          className="mt-4 px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors"
        >
          Retry
        </button>
      </div>
    );
  }

  
  return (
    <div className="space-y-4">
      {/* Compact Header with Filters */}
      <div className="bg-white rounded-lg border border-slate-200 p-3">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
          <h1 className="text-base sm:text-lg font-bold text-slate-800">Attendance Dashboard</h1>
          <div className="flex flex-wrap items-center gap-2">
            {/* Date Filter */}
            <input
              type="date"
              value={filters.date}
              onChange={(e) => handleFilterChange('date', e.target.value)}
              className="px-2 py-1 text-xs sm:text-sm border border-slate-200 rounded focus:outline-none focus:ring-2 focus:ring-blue-500 min-w-[100px]"
            />
            
            {/* District Filter */}
            <DropdownSearch
              value={filters.district_id}
              onChange={(e) => handleFilterChange('district_id', e.target.value)}
              options={districts}
              placeholder="District"
              className="text-xs sm:text-sm min-w-[120px]"
            />
            
            {/* Refresh */}
            <button
              onClick={() => {
                // Clear all filters and selections
                setFilters({
                  district_id: '',
                  scheme_type: '',
                  scheme_id: '',
                  date: new Date().toISOString().split('T')[0]
                });
                setSelectedDistrict(null);
                setError(null);
                setSchemeWiseData(null);
                setMapSummaryData([]);
                setSchemeLocations([]);
                // Fetch fresh data
                fetchSchemeWiseData();
              }}
              className="flex items-center gap-1 px-2 py-1 text-xs sm:text-sm bg-blue-500 text-white rounded hover:bg-blue-600 transition-colors disabled:opacity-50"
              disabled={schemeLoading}
            >
              <RefreshCw className={`h-3 w-3 ${schemeLoading ? 'animate-spin' : ''}`} />
              <span className="hidden sm:inline">Reset</span>
            </button>
            
            {/* Download PDF */}
            <button
              onClick={handleGeneratePDF}
              disabled={pdfLoading}
              className="flex items-center gap-1 px-2 py-1 text-xs sm:text-sm bg-green-600 text-white rounded hover:bg-green-700 disabled:opacity-50 transition-colors"
            >
              <FileText className="w-3 h-3" />
              <span className="hidden sm:inline">{pdfLoading ? "..." : "PDF"}</span>
            </button>
          </div>
        </div>
      </div>

      
      
      
      {/* Scheme-wise Attendance Grid */}
      {schemeWiseData && (
        <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
          <div className="px-5 py-4 border-b border-slate-50">
            <h3 className="font-semibold text-slate-700 flex items-center gap-2 text-sm">
              <Grid3x3 className="h-4 w-4 text-blue-500" />
              Scheme-wise Attendance Breakdown
              {schemeLoading && <RefreshCw className="h-3 w-3 animate-spin" />}
            </h3>
          </div>
          
          <div className="p-5">
            {/* Compact Layout - Map and Stats Side by Side */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-3 mb-3">
              {/* Interactive Maharashtra Map */}
              <div className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden">
                <div className="px-3 py-2 border-b border-slate-100">
                  <h3 className="font-semibold text-slate-700 flex items-center gap-2 text-xs">
                    <MapPin className="h-3 w-3 text-blue-500" />
                    District Attendance Map
                  </h3>
                </div>
                <div className="p-2">
                  <EnhancedMaharashtraMap 
                    summaryData={mapSummaryData}
                    schemeLocations={schemeLocations}
                    onDistrictSelect={handleMapDistrictSelect}
                    selectedDistrictName={selectedDistrict?.district_name}
                    width={320}
                    height={280}
                  />
                </div>
              </div>

              {/* Compact District Info */}
              <SimpleDistrictInfo 
                selectedDistrict={selectedDistrict}
                schemeWiseData={schemeWiseData}
                onClearFilter={() => setSelectedDistrict(null)}
              />
            </div>

            
            {/* District Attendance Table */}
            <DistrictAttendanceTable 
              districtsData={schemeWiseData?.districts || []}
              schemeWiseData={schemeWiseData}
              onDistrictSelect={handleMapDistrictSelect}
            />

                      </div>
        </div>
      )}

      </div>
  );
};

export default EnhancedAttendanceDashboard;
