import { useSearchParams, Link } from "react-router-dom";
import {
  Users,
  CalendarCheck,
  CalendarOff,
  FileText,
  Star,
  LayoutDashboard,
  IndianRupee,
  Upload,
  CheckCircle,
} from "lucide-react";
import EmployeeList from "./employees/EmployeeList";
import ApplicantOnboarding from "./employees/ApplicantOnboarding";
import HRMDashboard from "./dashboard/HRMDashboard";
import EnhancedAttendanceDashboard from "./dashboard/EnhancedHRMDashboard";
import AttendanceRecords from "./attendance/AttendanceRecords";
import AttendanceSummary from "./attendance/AttendanceSummary";
import BulkAttendanceUpload from "./attendance/BulkAttendanceUpload";
import BulkAttendancePending from "./attendance/BulkAttendancePending";
import LeaveApprovals from "./leave/LeaveApprovals";
import LeaveSummary from "./leave/LeaveSummary";
import WeeklyOffApproval from "./weekly-off/WeeklyOffApproval";
import ReviewReports from "./reports/ReviewReports";
import ReportSummary from "./reports/ReportSummary";
import EvaluateStaff from "./performance/EvaluateStaff";
import EvaluationSummary from "./performance/EvaluationSummary";
import SalaryCalculation from "./salary/SalaryCalculation";
import EmployeeView from "./employees/EmployeeView";
import EmployeeEdit from "./employees/EmployeeEdit";
import EmployeeRecords from "./employees/EmployeeRecords";
import CalendarPage from "./CalendarPage";
import { usePermission } from "../../hooks/usePermission";

const TABS = [
  {
    key: "dashboard",
    label: "Dashboard",
    icon: LayoutDashboard,
    color: "#6366f1",
    subTabs: [
      {
        key: "workforce-dashboard",
        label: "Workforce Dashboard",
        component: HRMDashboard,
      },
      {
        key: "enhanced-attendance-dashboard",
        label: "Attendance Dashboard",
        component: EnhancedAttendanceDashboard,
      },
    ],
  },
  {
    key: "employees",
    label: "Employees",
    icon: Users,
    color: "#3b82f6",
    subTabs: [
      { key: "employee-list", label: "Onboard Employee", component: EmployeeList },
      {
        key: "applicant-onboarding",
        label: "Onboard from Applications",
        component: ApplicantOnboarding,
      },
      {
        key: "employee-records",
        label: "Employee Records",
        component: EmployeeRecords,
      },
      {
        key: "employee-view",
        label: "Employee View",
        component: EmployeeView,
        hidden: true,
      },
      {
        key: "employee-edit",
        label: "Employee Edit",
        component: EmployeeEdit,
        hidden: true,
      },
    ],
  },

  {
    key: "attendance",
    label: "Attendance",
    icon: CalendarCheck,
    color: "#10b981",
    subTabs: [
      {
        key: "attendance-records",
        label: "Attendance Records",
        component: AttendanceRecords,
      },
      {
        key: "attendance-summary",
        label: "Attendance Summary",
        component: AttendanceSummary,
      },
      {
        key: "bulk-upload",
        label: "Bulk Upload",
        component: BulkAttendanceUpload,
      },
      {
        key: "bulk-pending",
        label: "Pending Approvals",
        component: BulkAttendancePending,
      },
    ],
  },
  {
    key: "leave",
    label: "Leave",
    icon: CalendarOff,
    color: "#f59e0b",
    subTabs: [
      {
        key: "leave-approvals",
        label: "Leave Approvals",
        component: LeaveApprovals,
      },
      { key: "leave-summary", label: "Leave Summary", component: LeaveSummary },
      {
        key: "weekly-off-approval",
        label: "Weekly Off Approval",
        component: WeeklyOffApproval,
        permission: "hrm.weekly_off.manage",
      },
    ],
  },
  // {
  //   key: "reports",
  //   label: "Reports",
  //   icon: FileText,
  //   color: "#8b5cf6",
  //   subTabs: [
  //     {
  //       key: "review-reports",
  //       label: "Review Reports",
  //       component: ReviewReports,
  //     },
  //     {
  //       key: "reports-overview",
  //       label: "Report Summary",
  //       component: ReportSummary,
  //     },
  //   ],
  // },
  // {
  //   key: "evaluation",
  //   label: "Performance",
  //   icon: Star,
  //   color: "#ec4899",
  //   subTabs: [
  //     {
  //       key: "evaluate-staff",
  //       label: "Review Staff",
  //       component: EvaluateStaff,
  //     },
  //     {
  //       key: "evaluation-summary",
  //       label: "Performance Summary",
  //       component: EvaluationSummary,
  //     },
  //   ],
  // },

  {
    key: "salary",
    label: "Salary",
    icon: IndianRupee,
    color: "#f97316",
    subTabs: [
      {
        key: "salary-calculation",
        label: "Salary Calculation",
        component: SalaryCalculation,
      },
    ],
  },
  {
    key: "calendar",
    label: "Calendar",
    icon: CalendarCheck,
    color: "#8b5cf6",
    subTabs: [
      {
        key: "hrm-calendar",
        label: "HRM Calendar",
        component: CalendarPage,
      },
    ],
  },
];

const PERMISSION_MAP = {
  dashboard: "hrm.dashboard.view",
  employees: "hrm.employees.view",
  attendance: "hrm.attendance.view",
  leave: "hrm.leave.view",
  reports: "hrm.reports.view",
  evaluation: "hrm.performance.view",
  salary: "hrm.payroll.view",
  calendar: "hrm.calendar.manage",
};

const HRMPage = () => {
  const { hasPermission } = usePermission();
  const [searchParams, setSearchParams] = useSearchParams();

  // Read tab/subtab from URL — persist on refresh
  const activeTab = searchParams.get("tab") || "dashboard";
  const activeSubTab = searchParams.get("subtab") || "workforce-dashboard";
  const visibleTabs = TABS.filter((tab) => {
    const perm = PERMISSION_MAP[tab.key];
    // Special handling for Leave tab - show if user has leave OR weekly off permissions
    if (tab.key === 'leave') {
      return hasPermission(perm) || hasPermission('hrm.weekly_off.view') || hasPermission('hrm.weekly_off.manage');
    }
    return hasPermission(perm);
  });
  const currentTab =
    visibleTabs.find((t) => t.key === activeTab) || visibleTabs[0] || {};
  const currentSubTab =
    currentTab?.subTabs?.find((s) => s.key === activeSubTab) ||
    currentTab?.subTabs?.find((s) => !s.hidden) ||
    currentTab?.subTabs?.[0];
  const ActiveComponent = currentSubTab?.component;

  const handleTabChange = (tabKey) => {
    const tab = TABS.find((t) => t.key === tabKey);
    setSearchParams({ tab: tabKey, subtab: tab?.subTabs[0]?.key || "" });
  };

  const handleSubTabChange = (subKey) => {
    setSearchParams({ tab: activeTab, subtab: subKey });
  };

  return (
    <div className="-m-4 md:-m-6 lg:-m-8 -mt-4 md:-mt-6 lg:-mt-8 min-h-screen bg-slate-100 font-sans">
      {/* ── Sticky Tab Bar ── */}
      <div className="sticky top-0 z-15">
        {/* Main Tabs */}
        <div className="bg-slate-900 px-4 shadow-lg">
          <div className="flex overflow-x-auto scrollbar-hide">
            {visibleTabs.map((tab) => {
              const isActive = activeTab === tab.key;
              return (
                <button
                  key={tab.key}
                  onClick={() => handleTabChange(tab.key)}
                  className="relative flex items-center gap-3 px-6 py-4 text-base font-semibold whitespace-nowrap transition-all duration-200"
                >
                  {isActive && (
                    <span
                      className="absolute inset-x-2 inset-y-1.5 rounded-xl"
                      style={{ background: tab.color + "25" }}
                    />
                  )}
                  {isActive && (
                    <span
                      className="absolute bottom-0 left-2 right-2 h-0.5 rounded-full"
                      style={{ background: tab.color }}
                    />
                  )}
                  <span className="relative z-10">
                    <tab.icon
                      className="h-5 w-5"
                      style={{ color: isActive ? tab.color : "#94a3b8" }}
                    />
                  </span>
                  <span
                    className="relative z-10"
                    style={{ color: isActive ? tab.color : "#cbd5e1" }}
                  >
                    {tab.label}
                  </span>
                </button>
              );
            })}
          </div>
        </div>

        {/* Sub Tabs */}
        {currentTab?.subTabs?.length > 1 && (
          <div className="bg-white border-b border-slate-200">
            <div className="flex gap-2 overflow-x-auto scrollbar-hide py-2 px-6">
              {currentTab.subTabs
                .filter((sub) => {
                  if (sub.hidden) return false;

                  const SUBTAB_PERMISSION_MAP = {
                    "employee-list": "hrm.employees.view",
                    "applicant-onboarding": "hrm.onboarding.view",
                    "attendance-records": "hrm.attendance.view",
                    "bulk-upload": "hrm.attendance.bulk_upload",
                    "bulk-pending": "hrm.attendance.bulk_approve",
                    "leave-approvals": "hrm.leave.view",
                    "leave-summary": "hrm.leave.view",
                  };
                  const perm = SUBTAB_PERMISSION_MAP[sub.key];

                  return !perm || hasPermission(perm);
                })
                .map((sub) => {
                  const isActive = activeSubTab === sub.key;
                  return (
                    <button
                      key={sub.key}
                      onClick={() => handleSubTabChange(sub.key)}
                      className="px-3 py-1.5 rounded-md text-sm font-medium whitespace-nowrap transition-all duration-200"
                      style={
                        isActive
                          ? { background: currentTab.color, color: "#fff" }
                          : { color: "#64748b" }
                      }
                      onMouseEnter={(e) => {
                        if (!isActive) {
                          e.currentTarget.style.background =
                            currentTab.color + "12";
                          e.currentTarget.style.color = currentTab.color;
                        }
                      }}
                      onMouseLeave={(e) => {
                        if (!isActive) {
                          e.currentTarget.style.background = "transparent";
                          e.currentTarget.style.color = "#64748b";
                        }
                      }}
                    >
                      {sub.label}
                    </button>
                  );
                })}
            </div>
          </div>
        )}
      </div>

      {/* ── Content ── */}
      <div className="p-6 md:p-8 lg:p-10">
        {ActiveComponent ? <ActiveComponent /> : null}
      </div>
    </div>
  );
};

export default HRMPage;
