import React, { useState, useEffect, useCallback } from "react";
import { DataTable } from "../../../components/ui/DataTable";
import toast from "react-hot-toast";
import { 
  getEmployeeWeeklyOffClaims, 
  submitWeeklyOffClaim 
} from "../../../services/workforce.service";
import { Calendar, Clock, CheckCircle, AlertCircle, CalendarDays } from "lucide-react";

const EmployeeWeeklyOffClaim = () => {
  const [claims, setClaims] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(null);
  const [selectedDate, setSelectedDate] = useState("");
  const [selectedClaim, setSelectedClaim] = useState(null);
  const [showModal, setShowModal] = useState(false);

  const fetchClaims = useCallback(async () => {
    try {
      setLoading(true);
      const result = await getEmployeeWeeklyOffClaims();
      setClaims(result || []);
    } catch (error) {
      toast.error("Failed to load weekly off claims");
      console.error(error);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchClaims();
  }, [fetchClaims]);

  const handleClaimClick = (claim) => {
    // Only allow claiming if not already approved
    if (claim.claim_status === 'APPROVED') {
      toast.info("This weekly off has already been approved");
      return;
    }

    setSelectedClaim(claim);
    // Default to a date within the entitlement window
    const today = new Date();
    const weekStart = new Date(claim.entitlement_week_start);
    const weekEnd = new Date(claim.entitlement_week_end);
    
    // If today is within the window, use today, otherwise use week start
    let defaultDate = today;
    if (today < weekStart) defaultDate = weekStart;
    if (today > weekEnd) defaultDate = weekEnd;
    
    setSelectedDate(defaultDate.toISOString().split('T')[0]);
    setShowModal(true);
  };

  const handleSubmit = async () => {
    if (!selectedDate) {
      toast.error("Please select a date");
      return;
    }

    // Validate date is within entitlement window
    const selected = new Date(selectedDate);
    const weekStart = new Date(selectedClaim.entitlement_week_start);
    const weekEnd = new Date(selectedClaim.entitlement_week_end);
    
    if (selected < weekStart || selected > weekEnd) {
      toast.error(`Date must be between ${selectedClaim.entitlement_week_start} and ${selectedClaim.entitlement_week_end}`);
      return;
    }

    try {
      setSubmitting(selectedClaim.claim_id);
      await submitWeeklyOffClaim(selectedClaim.claim_id, selectedDate);
      toast.success("Weekly off claim submitted successfully");
      setShowModal(false);
      setSelectedClaim(null);
      setSelectedDate("");
      fetchClaims();
    } catch (error) {
      toast.error(error.message || "Failed to submit claim");
      console.error(error);
    } finally {
      setSubmitting(null);
    }
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case 'PENDING':
        return (
          <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-amber-50 text-amber-700 text-xs font-medium">
            <Clock className="w-3 h-3" />
            Pending Approval
          </span>
        );
      case 'APPROVED':
        return (
          <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-emerald-50 text-emerald-700 text-xs font-medium">
            <CheckCircle className="w-3 h-3" />
            Approved
          </span>
        );
      default:
        return (
          <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-slate-50 text-slate-600 text-xs font-medium">
            {status}
          </span>
        );
    }
  };

  const columns = [
    {
      key: "entitlement_week",
      header: "Entitlement Week",
      render: (_, row) => (
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-indigo-50 flex items-center justify-center">
            <CalendarDays className="w-4 h-4 text-indigo-600" />
          </div>
          <div>
            <p className="text-sm font-medium text-slate-900">{row.entitlement_week_start} to {row.entitlement_week_end}</p>
            <p className="text-xs text-slate-500">Month: {row.entitlement_month}</p>
          </div>
        </div>
      ),
    },
    {
      key: "claimed_off_date",
      header: "Claimed Off Date",
      render: (_, row) => (
        <div className="text-sm">
          {row.claimed_off_date ? (
            <div className="flex items-center gap-1.5 text-slate-700">
              <Calendar className="w-3.5 h-3.5 text-indigo-500" />
              <span className="font-medium">
                {new Date(row.claimed_off_date).toLocaleDateString('en-GB', { 
                  day: 'numeric', 
                  month: 'long', 
                  year: 'numeric' 
                })}
              </span>
            </div>
          ) : (
            <span className="text-slate-400 italic">Not claimed yet</span>
          )}
        </div>
      ),
    },
    {
      key: "status",
      header: "Status",
      render: (_, row) => getStatusBadge(row.claim_status),
    },
    {
      key: "requested_at",
      header: "Requested",
      render: (_, row) => (
        <div className="text-sm text-slate-500">
          {row.requested_at ? new Date(row.requested_at).toLocaleString('en-GB', { 
            day: 'numeric',
            month: 'short',
            hour: '2-digit',
            minute: '2-digit'
          }) : '-'}
        </div>
      ),
    },
    {
      key: "actions",
      header: "Actions",
      className: "text-center",
      render: (_, row) => {
        const isApproved = row.claim_status === 'APPROVED';
        const canClaim = !isApproved;
        
        return (
          <button
            onClick={() => handleClaimClick(row)}
            disabled={!canClaim || submitting === row.claim_id}
            className={`inline-flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg transition-colors ${
              isApproved 
                ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                : row.claimed_off_date
                  ? 'bg-amber-50 text-amber-700 hover:bg-amber-100'
                  : 'bg-indigo-600 text-white hover:bg-indigo-700'
            } disabled:opacity-50 disabled:cursor-not-allowed`}
          >
            {submitting === row.claim_id ? (
              <>
                <span className="w-3 h-3 border-2 border-current border-t-transparent rounded-full animate-spin" />
                Submitting...
              </>
            ) : isApproved ? (
              <>
                <CheckCircle className="w-3.5 h-3.5" />
                Approved
              </>
            ) : row.claimed_off_date ? (
              <>
                <AlertCircle className="w-3.5 h-3.5" />
                Update Claim
              </>
            ) : (
              <>
                <Calendar className="w-3.5 h-3.5" />
                Claim Weekly Off
              </>
            )}
          </button>
        );
      },
    },
  ];

  // Get pending and available claims
  const pendingClaims = claims.filter(c => c.claim_status === 'PENDING');
  const approvedClaims = claims.filter(c => c.claim_status === 'APPROVED');

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-semibold text-slate-900">Weekly Off Claims</h1>
          <p className="text-sm text-slate-500 mt-1">
            You get 1 weekly off per week. Claim any day within your entitlement window. 
            Unclaimed weekly offs expire at month-end.
          </p>
        </div>
        <div className="flex items-center gap-4">
          {pendingClaims.length > 0 && (
            <div className="flex items-center gap-2 text-sm text-amber-600 bg-amber-50 px-3 py-1.5 rounded-lg">
              <AlertCircle className="w-4 h-4" />
              <span>{pendingClaims.length} pending approval</span>
            </div>
          )}
          <div className="text-sm text-slate-500">
            Approved this month: <span className="font-medium text-emerald-600">{approvedClaims.length}</span>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 shadow-sm">
        <DataTable
          columns={columns}
          data={claims}
          loading={loading}
          emptyMessage="No weekly off claims available. New entitlements are generated every Sunday."
        />
      </div>

      {/* Claim Modal */}
      {showModal && selectedClaim && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-md mx-4">
            <div className="p-6 border-b border-slate-100">
              <h2 className="text-lg font-semibold text-slate-900">
                {selectedClaim.claimed_off_date ? 'Update Weekly Off Claim' : 'Claim Weekly Off'}
              </h2>
              <p className="text-sm text-slate-500 mt-1">
                Select any date within your entitlement week
              </p>
            </div>
            <div className="p-6 space-y-4">
              <div className="bg-slate-50 rounded-lg p-4 space-y-2">
                <div className="flex justify-between text-sm">
                  <span className="text-slate-500">Entitlement Week:</span>
                  <span className="font-medium text-slate-700">{selectedClaim.entitlement_week_start} to {selectedClaim.entitlement_week_end}</span>
                </div>
                {selectedClaim.claimed_off_date && (
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-500">Currently Claimed:</span>
                    <span className="font-medium text-amber-600">{new Date(selectedClaim.claimed_off_date).toLocaleDateString('en-GB')}</span>
                  </div>
                )}
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">
                  Select Weekly Off Date <span className="text-red-500">*</span>
                </label>
                <input
                  type="date"
                  value={selectedDate}
                  onChange={(e) => setSelectedDate(e.target.value)}
                  min={selectedClaim.entitlement_week_start}
                  max={selectedClaim.entitlement_week_end}
                  className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500"
                />
                <p className="text-xs text-slate-500 mt-1">
                  Must be between {selectedClaim.entitlement_week_start} and {selectedClaim.entitlement_week_end}
                </p>
              </div>

              <div className="bg-amber-50 border border-amber-100 rounded-lg p-3 text-sm text-amber-700">
                <p className="flex items-start gap-2">
                  <AlertCircle className="w-4 h-4 mt-0.5 flex-shrink-0" />
                  <span>
                    Your claim will be sent for admin approval. If no action is taken within 24 hours, it will be auto-approved.
                  </span>
                </p>
              </div>
            </div>
            <div className="p-6 border-t border-slate-100 flex justify-end gap-3">
              <button
                onClick={() => setShowModal(false)}
                className="px-4 py-2 text-sm font-medium text-slate-600 hover:text-slate-800 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleSubmit}
                disabled={!selectedDate || submitting}
                className="px-4 py-2 bg-indigo-600 text-white text-sm font-medium rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center gap-2"
              >
                {submitting ? (
                  <>
                    <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    Submitting...
                  </>
                ) : (
                  <>
                    <Calendar className="w-4 h-4" />
                    {selectedClaim.claimed_off_date ? 'Update Claim' : 'Submit Claim'}
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default EmployeeWeeklyOffClaim;
