import React, { useState, useMemo, useEffect, useCallback, useRef } from "react";
import { CheckCircle2, XCircle } from "lucide-react";
import { DataTable } from "../../../components/ui/DataTable";
import DropdownSearch from "../../../components/common/DropdownSearch";
import { Button } from "../../../components/common/Button";
import toast from "react-hot-toast";
import { getDistricts, getSchemesWithTypes, getSchemeTypes } from "../../../services/master.service";
import { calculate11MonthEndDate } from "../../../utils/date";
import DatePicker from "../../../components/common/Datepicker";
import {
  getPendingApplications,
  confirmOnboardApplicant,
  rejectOnboardApplicant,
} from "../../../services/workforce.service";
import { PermissionGuard } from "../../../components/auth/PermissionGuard";
import { usePermission } from "../../../hooks/usePermission";

const ApplicantOnboarding = () => {
  const { hasPermission } = usePermission();
  const [applicants, setApplicants] = useState([]);
  const [loading, setLoading] = useState(true);

  // Pagination state
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  const [selectedDistrict, setSelectedDistrict] = useState("");
  const [selectedScheme, setSelectedScheme] = useState("");
  const [search, setSearch] = useState("");
  const prevSearchRef = useRef("");

  const [districtOptions, setDistrictOptions] = useState([]);
  const [schemeOptions, setSchemeOptions] = useState([]);
  const [schemeTypeOptions, setSchemeTypeOptions] = useState([]);
  const [selectedSchemeType, setSelectedSchemeType] = useState("");

  const [actionModal, setActionModal] = useState({
    open: false,
    type: "",
    row: null,
    reason: "",
  });

  useEffect(() => {
    const loadMasters = async () => {
      try {
        const [districts, schemes, schemeTypes] = await Promise.all([
          getDistricts({ is_active: true }),
          getSchemesWithTypes({ is_active: true }),
          getSchemeTypes({ is_active: true }),
        ]);
        setDistrictOptions(
          (districts || []).map((d) => ({
            id: d.district_id,
            name: d.district_name,
          })),
        );
        setSchemeOptions(
          (schemes || []).map((s) => ({
            id: s.scheme_id,
            name: s.scheme_name,
            district_id: s.district_id,
            scheme_type_id: s.scheme_type_id,
          })),
        );
        setSchemeTypeOptions(
          (schemeTypes || []).map((st) => ({
            id: st.scheme_type_id,
            name: st.scheme_name,
          })),
        );
      } catch (err) {
        console.error(err);
      }
    };
    loadMasters();
  }, []);

  const filteredSchemeOptions = useMemo(
    () =>
      schemeOptions.filter((s) => {
        const districtMatch = selectedDistrict
          ? String(s.district_id) === String(selectedDistrict)
          : true;
        const typeMatch = selectedSchemeType
          ? String(s.scheme_type_id) === String(selectedSchemeType)
          : true;
        return districtMatch && typeMatch;
      }),
    [selectedDistrict, selectedSchemeType, schemeOptions],
  );

  const fetchApplicants = async () => {
    try {
      setLoading(true);

      const res = await getPendingApplications({
        page,
        limit,
        district_id: selectedDistrict || undefined,
        scheme_id: selectedScheme || undefined,
        scheme_type_id: selectedSchemeType || undefined,
        search: search || undefined,
      });

      setApplicants(res?.data?.data || []);
      setTotalPages(res?.data?.pagination?.totalPages || 1);
      setTotalItems(res?.data?.pagination?.total || 0);
    } catch (err) {
      toast.error(err.message || "Failed to load applicants");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchApplicants();
  }, [page, limit, selectedDistrict, selectedScheme, selectedSchemeType, search]);

  const handleSearch = useCallback((value) => {
    // Only reset page to 1 if search value actually changed
    if (value !== prevSearchRef.current) {
      prevSearchRef.current = value;
      setSearch(value);
      setPage(1);
    }
  }, []);

  const getStatusBadge = (status) => {
    if (status === "pending")
      return (
        <span className="px-2.5 py-0.5 rounded-full text-xs font-medium bg-amber-50 text-amber-700">
          Pending
        </span>
      );
    if (status === "onboarded")
      return (
        <span className="px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-50 text-green-700">
          Onboarded
        </span>
      );
    if (status === "rejected")
      return (
        <span className="px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-50 text-red-700">
          Rejected
        </span>
      );
    return null;
  };

  const updateStatus = async (row, type) => {
    try {
      if (type === "onboarded") {
        if (!actionModal.start_date || !actionModal.end_date) {
          toast.error("Contract dates required");
          return;
        }

        await confirmOnboardApplicant({
          applicant_id: row.applicant_id,
          employee_data: {
            contract_start_date: actionModal.start_date,
            contract_end_date: actionModal.end_date,
          },
        });
      } else {
        await rejectOnboardApplicant({
          applicant_id: row.applicant_id,
          reason: "Rejected by admin",
        });
      }

      fetchApplicants();
    } catch (err) {
      toast.error(err.message || "Action failed");
    }
  };

  const columns = useMemo(
    () => [
      {
        key: "full_name",
        header: "Candidate",
        render: (_, row) => (
          <div>
            <div className="font-medium text-slate-900">
              {row.applicant?.personal?.full_name || "-"}
            </div>
            <div className="text-xs text-slate-400">{row.application_no}</div>
          </div>
        ),
      },
      {
        key: "district",
        header: "District / Scheme",
        render: (_, row) => (
          <div>
            <div className="text-sm">{row.district?.district_name || "-"}</div>
            <div className="text-xs text-slate-400">
              {row.scheme?.scheme_name || "-"}
            </div>
          </div>
        ),
      },
      {
        key: "post",
        header: "Post",
        render: (_, row) => (
          <span className="px-2.5 py-0.5 rounded-full text-xs bg-blue-50 text-blue-700">
            {row.post?.post_name || "-"}
          </span>
        ),
      },
      {
        key: "email",
        header: "Email",
        render: (_, row) => row.applicant?.email || "-",
      },

      {
        key: "actions",
        header: "Actions",
        className: "text-center",
        render: (_, row) => {
          const isDone =
            row.status === "onboarded" || row.status === "rejected";
          return (
            <div className="flex justify-center gap-2">
              {hasPermission("hrm.onboarding.confirm") && (
                <Button
                  variant="ghost"
                  size="sm"
                  disabled={isDone}
                  onClick={() =>
                    setActionModal({ open: true, type: "onboarded", row })
                  }
                >
                  <CheckCircle2 className="h-4 w-4 text-green-600" />
                </Button>
              )}
              {hasPermission("hrm.onboarding.confirm") && (
                <Button
                  variant="ghost"
                  size="sm"
                  disabled={isDone}
                  onClick={() =>
                    setActionModal({ open: true, type: "rejected", row })
                  }
                >
                  <XCircle className="h-4 w-4 text-red-600" />
                </Button>
              )}
            </div>
          );
        },
      },
    ],
    [],
  );

  return (
    <PermissionGuard permissions="hrm.onboarding.view">
      <div className="space-y-4">
        <div className="flex items-center gap-3 flex-wrap">
          {/* District Filter */}
          <div className="w-44">
            <DropdownSearch
              value={selectedDistrict}
              onChange={(e) => {
                setSelectedDistrict(e.target.value);
                setSelectedScheme("");
              }}
              options={districtOptions}
              placeholder="All Districts"
            />
          </div>

          {/* Scheme Type Filter */}
          <div className="w-44">
            <DropdownSearch
              value={selectedSchemeType}
              onChange={(e) => {
                setSelectedSchemeType(e.target.value);
                setSelectedScheme("");
              }}
              options={schemeTypeOptions}
              placeholder="All Scheme Types"
            />
          </div>

          {/* Scheme Filter */}
          <div className="w-44">
            <DropdownSearch
              value={selectedScheme}
              onChange={(e) => {
                setSelectedScheme(e.target.value);
              }}
              options={filteredSchemeOptions}
              placeholder="All Schemes"
            />
          </div>
        </div>

        <DataTable
          columns={columns}
          data={applicants}
          isLoading={loading}
          enableSelection={false}
          showRowNumbers={true}
          onSearch={handleSearch}
          pagination={{
            currentPage: page,
            totalPages,
            totalItems,
            onPageChange: (newPage) => setPage(newPage),
            pageSize: limit,
            onPageSizeChange: (newLimit) => {
              setLimit(newLimit);
              setPage(1);
            },
            pageSizeOptions: [10, 25, 50, 100],
          }}
          rowKey="applicant_id"
          headerClassName="bg-slate-900 text-white"
        />

        {actionModal.open && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-md p-6">
              <h2 className="text-lg font-semibold mb-2">
                {actionModal.type === "onboarded"
                  ? "Confirm Onboarding"
                  : "Reject Applicant"}
              </h2>

              <p className="text-sm text-gray-600 mb-4">
                Are you sure you want to{" "}
                <b>{actionModal.type === "onboarded" ? "confirm" : "reject"}</b>{" "}
                this applicant?
              </p>

              {actionModal.type === "rejected" && (
                <textarea
                  className="w-full border rounded-lg p-2 mb-3 text-sm"
                  placeholder="Enter rejection reason..."
                  onChange={(e) =>
                    setActionModal((prev) => ({
                      ...prev,
                      reason: e.target.value,
                    }))
                  }
                />
              )}

              {actionModal.type === "onboarded" && (
                <>
                  {/* Start Date */}
                  <DatePicker
                    label="Contract Start Date"
                    value={actionModal.start_date}
                    onChange={(value) => {
                      setActionModal((prev) => ({
                        ...prev,
                        start_date: value,
                        end_date: calculate11MonthEndDate(value), // 🔥 AUTO
                      }));
                    }}
                    required
                  />

                  {/* End Date */}
                  <DatePicker
                    label="Contract End Date"
                    value={actionModal.end_date}
                    min={actionModal.start_date}
                    disabled
                    required
                  />
                </>
              )}

              <div className="flex justify-end gap-3 mt-3">
                <Button
                  variant="outline"
                  onClick={() =>
                    setActionModal({
                      open: false,
                      type: "",
                      row: null,
                      reason: "",
                      start_date: "",
                      end_date: "",
                    })
                  }
                >
                  Cancel
                </Button>
                <Button
                  onClick={async () => {
                    // 🔒 Permission check (IMPORTANT)
                    if (!hasPermission("hrm.onboarding.confirm")) {
                      toast.error("Unauthorized");
                      return;
                    }

                    try {
                      if (actionModal.type === "onboarded") {
                        if (!actionModal.start_date || !actionModal.end_date) {
                          toast.error("Contract dates required");
                          return;
                        }

                        await updateStatus(actionModal.row, "onboarded");
                        toast.success("Applicant onboarded successfully");
                      } else {
                        await rejectOnboardApplicant({
                          applicant_id: actionModal.row.applicant_id,
                          reason: actionModal.reason || "Rejected by admin",
                        });

                        toast.success("Applicant rejected successfully");
                        fetchApplicants();
                      }
                    } catch (err) {
                      toast.error(err.message || "Action failed");
                    } finally {
                      setActionModal({
                        open: false,
                        type: "",
                        row: null,
                        reason: "",
                        start_date: "",
                        end_date: "",
                      });
                    }
                  }}
                >
                  Confirm
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>
    </PermissionGuard>
  );
};

export default ApplicantOnboarding;
