import React, { useState, useEffect } from "react";
import { X, UserPlus, Loader2 } from "lucide-react";
import { Input } from "../../../components/common/Input";
import DropdownSearch from "../../../components/common/DropdownSearch";
import { Button } from "../../../components/common/Button";
import toast from "react-hot-toast";
import { createExistingEmployee } from "../../../services/workforce.service";
import {
  getDistricts,
  getSchemesWithTypes,
  getPosts,
  getSchemeTypes,
} from "../../../services/master.service";

const calculate11MonthEndDate = (startDate) => {
  if (!startDate) return "";
  const end = new Date(startDate);
  end.setMonth(end.getMonth() + 11);
  end.setDate(end.getDate() - 1);
  return end.toISOString().split("T")[0];
};

const INITIAL_FORM = {
  district_id: "",
  scheme_id: "",
  post_id: "",
  full_name: "",
  dob: "",
  gender: "",
  email: "",
  contract_start_date: "",
  contract_end_date: "",
  employee_pay: "",
};

const OnboardModal = ({ isOpen, onClose, onSuccess }) => {
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState(INITIAL_FORM);
  const [errors, setErrors] = useState({});

  const [districtOptions, setDistrictOptions] = useState([]);
  const [schemeOptions, setSchemeOptions] = useState([]);
  const [schemeTypes, setSchemeTypes] = useState([]);
  const [postOptions, setPostOptions] = useState([]);

  const filterBy = (list, key, value) =>
    value ? list.filter((i) => String(i[key]) === String(value)) : list;

  // Group schemes by type like we did for OSC/Hub
  const schemesByType = schemeTypes.reduce((acc, type) => {
    acc[type.scheme_type_id] = {
      ...type,
      schemes: schemeOptions.filter(scheme => scheme.scheme_type_id === type.scheme_type_id)
    };
    return acc;
  }, {});

  // Filter schemes by district
  const filteredSchemesByType = Object.keys(schemesByType).reduce((acc, typeId) => {
    const type = schemesByType[typeId];
    acc[typeId] = {
      ...type,
      schemes: formData.district_id 
        ? type.schemes.filter(scheme => String(scheme.district_id) === String(formData.district_id))
        : type.schemes
    };
    return acc;
  }, {});

  const filteredPosts = postOptions.filter(
    (p) =>
      (!formData.district_id || p.district_id == formData.district_id) &&
      (!formData.scheme_id || p.scheme_id == formData.scheme_id),
  );

  const handleChange = (field, value) => {
    setFormData((prev) => {
      const updated = { ...prev, [field]: value || "" };

      if (field === "district_id")
        return { ...updated, scheme_id: "", post_id: "" };

      if (field === "scheme_id") {
        return { ...updated, post_id: "" };
      }
      if (field === "contract_start_date")
        return {
          ...updated,
          contract_end_date: calculate11MonthEndDate(value),
        };

      return updated;
    });

    setErrors((prev) => ({ ...prev, [field]: "" }));
  };

  const validate = () => {
    const newErrors = {};

    if (!formData.district_id) newErrors.district_id = "District is required";
    if (!formData.post_id) newErrors.post_id = "Post is required";

    if (!formData.full_name.trim()) {
      newErrors.full_name = "Full name is required";
    } else if (!/^[A-Za-z\s]+$/.test(formData.full_name)) {
      newErrors.full_name = "Only alphabets allowed";
    }
    if (!formData.email.trim()) newErrors.email = "Email is required";
    else if (!/\S+@\S+\.\S+/.test(formData.email))
      newErrors.email = "Invalid email";

    if (!formData.contract_start_date)
      newErrors.contract_start_date = "Required";
    if (!formData.contract_end_date) newErrors.contract_end_date = "Required";
    if (!formData.dob) newErrors.dob = "Date of birth is required";
    if (!formData.gender) newErrors.gender = "Gender is required";
    if (formData.employee_pay && Number(formData.employee_pay) < 0) {
      newErrors.employee_pay = "Pay cannot be negative";
    }

    setErrors(newErrors);
    return !Object.keys(newErrors).length;
  };

  const handleSubmit = async () => {
    if (!validate()) return;

    setLoading(true);
    try {
      await createExistingEmployee({
        ...formData,
        full_name: formData.full_name.trim(),
        email: formData.email.trim(),
      });

      toast.success("Employee onboarded successfully!");
      onSuccess?.();
      handleClose();
    } catch (err) {
      toast.error(err?.message || "Failed to onboard employee");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const loadMasters = async () => {
      try {
        const [d, s, st, p] = await Promise.all([
          getDistricts({ is_active: true }),
          getSchemesWithTypes({ is_active: true }),
          getSchemeTypes({ is_active: true }),
          getPosts({ is_active: true }),
        ]);

        setDistrictOptions(d?.districts || d || []);
        setSchemeOptions(s?.schemes || s || []);
        setSchemeTypes(st?.schemeTypes || st || []);
        setPostOptions(p?.posts || p || []);
      } catch {
        toast.error("Failed to load master data");
      }
    };

    loadMasters();
  }, []);

  const handleClose = () => {
    setFormData(INITIAL_FORM);
    setErrors({});
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] flex flex-col">
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-blue-50 rounded-xl">
              <UserPlus className="h-5 w-5 text-blue-600" />
            </div>
            <h2 className="text-lg font-semibold text-slate-800">
              Onboard Employee
            </h2>
          </div>
          <button
            onClick={handleClose}
            className="p-2 rounded-xl text-slate-400 hover:text-slate-600 hover:bg-slate-100 transition-colors"
          >
            <X className="h-5 w-5" />
          </button>
        </div>

        {/* Body */}
        <div className="overflow-y-auto flex-1 px-6 py-5 space-y-6">
          {/* Posting Details */}
          <div>
            <h3 className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-3">
              Posting Details
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">
                  District <span className="text-red-500">*</span>
                </label>
                <DropdownSearch
                  value={formData.district_id}
                  onChange={(e) => handleChange("district_id", e.target.value)}
                  options={districtOptions.map((d) => ({
                    id: d.district_id,
                    name: d.district_name,
                  }))}
                  placeholder="Select District"
                />
                {errors.district_id && (
                  <p className="text-xs text-red-500 mt-1">
                    {errors.district_id}
                  </p>
                )}
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">
                  Scheme
                </label>
                <DropdownSearch
                  value={formData.scheme_id}
                  onChange={(e) => handleChange("scheme_id", e.target.value)}
                  options={Object.values(filteredSchemesByType).flatMap(type => 
                    type.schemes.map(scheme => ({
                      id: scheme.scheme_id,
                      name: `${scheme.scheme_name} (${type.scheme_name})`,
                      group: type.scheme_name
                    }))
                  )}
                  placeholder={
                    formData.district_id
                      ? "Select Scheme"
                      : "Select District first"
                  }
                  disabled={!formData.district_id}
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">
                  Post <span className="text-red-500">*</span>
                </label>
                <DropdownSearch
                  value={formData.post_id}
                  onChange={(e) => handleChange("post_id", e.target.value)}
                  options={filteredPosts.map((p) => ({
                    id: p.post_id,
                    name: p.post_name,
                  }))}
                  placeholder={
                    !formData.district_id
                      ? "Select District first"
                      : "Select Post"
                  }
                  disabled={!formData.district_id}
                />
                {errors.post_id && (
                  <p className="text-xs text-red-500 mt-1">{errors.post_id}</p>
                )}
              </div>
            </div>
          </div>

          {/* Contract Period */}
          <div>
            <h3 className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-3">
              Contract Period
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <Input
                  label="Contract Start Date"
                  type="date"
                  value={formData.contract_start_date}
                  onChange={(e) =>
                    handleChange("contract_start_date", e.target.value)
                  }
                  required
                />
                {errors.contract_start_date && (
                  <p className="text-xs text-red-500 mt-1">
                    {errors.contract_start_date}
                  </p>
                )}
              </div>
              <div>
                <Input
                  label="Contract End Date"
                  type="date"
                  value={formData.contract_end_date}
                  onChange={(e) =>
                    handleChange("contract_end_date", e.target.value)
                  }
                  disabled={!formData.contract_start_date}
                  required
                />
                {errors.contract_end_date && (
                  <p className="text-xs text-red-500 mt-1">
                    {errors.contract_end_date}
                  </p>
                )}
              </div>
            </div>
          </div>

          {/* Employee Details */}
          <div>
            <h3 className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-3">
              Employee Details
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="md:col-span-2">
                <Input
                  label="Full Name"
                  value={formData.full_name}
                  onChange={(e) =>
                    handleChange(
                      "full_name",
                      e.target.value.replace(/[^A-Za-z\s]/g, ""),
                    )
                  }
                  placeholder="e.g. Priya Sharma"
                  required
                />
                {errors.full_name && (
                  <p className="text-xs text-red-500 mt-1">
                    {errors.full_name}
                  </p>
                )}
              </div>

              <div className="md:col-span-2">
                <Input
                  label="Date of Birth"
                  type="date"
                  max={new Date().toISOString().split("T")[0]}
                  value={formData.dob}
                  onChange={(e) => handleChange("dob", e.target.value)}
                  required
                />
                {errors.dob && (
                  <p className="text-xs text-red-500 mt-1">{errors.dob}</p>
                )}
              </div>

              <div className="md:col-span-2">
                <label className="block text-sm font-medium mb-2">
                  Gender <span className="text-red-500">*</span>
                </label>
                <div className="flex gap-4">
                  {["Male", "Female", "Other"].map((g) => (
                    <label
                      key={g}
                      className={`flex items-center gap-2 px-3 py-2 border rounded-lg cursor-pointer 
                        ${formData.gender === g ? "bg-blue-100 border-blue-500" : "border-gray-300"}`}
                    >
                      <input
                        type="radio"
                        name="gender"
                        value={g}
                        checked={formData.gender === g}
                        onChange={(e) => handleChange("gender", e.target.value)}
                        className="hidden"
                      />
                      <span className="text-sm">{g}</span>
                    </label>
                  ))}
                </div>
                {errors.gender && (
                  <p className="text-xs text-red-500 mt-1">{errors.gender}</p>
                )}
              </div>

              <div className="md:col-span">
                <Input
                  label="Email"
                  type="email"
                  value={formData.email}
                  onChange={(e) => handleChange("email", e.target.value)}
                  placeholder="employee@example.com"
                  required
                />
                {errors.email && (
                  <p className="text-xs text-red-500 mt-1">{errors.email}</p>
                )}
              </div>

              <div className="md:col-span">
                <Input
                  label="Pay"
                  type="number"
                  min="0"
                  value={formData.employee_pay}
                  onChange={(e) => handleChange("employee_pay", e.target.value)}
                />
                {errors.employee_pay && (
                  <p className="text-xs text-red-500 mt-1">
                    {errors.employee_pay}
                  </p>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="px-6 py-4 border-t border-slate-100 flex items-center justify-end gap-3">
          <Button variant="outline" onClick={handleClose} disabled={loading}>
            Cancel
          </Button>
          <Button onClick={handleSubmit} disabled={loading}>
            {loading ? (
              <span className="flex items-center gap-2">
                <Loader2 className="h-4 w-4 animate-spin" />
                Onboarding...
              </span>
            ) : (
              "Onboard Employee"
            )}
          </Button>
        </div>
      </div>
    </div>
  );
};
export default OnboardModal;
