import React, {
  useState,
  useMemo,
  useEffect,
  useCallback,
  useRef,
} from "react";
import { Eye, UserPlus, RefreshCw, Upload, Download, Mail } from "lucide-react";
import { useSearchParams } from "react-router-dom";
import { DataTable } from "../../../components/ui/DataTable";
import { Button } from "../../../components/common/Button";
import DropdownSearch from "../../../components/common/DropdownSearch";
import { PermissionGuard } from "../../../components/auth/PermissionGuard";
import OnboardModal from "./OnboardModal";
import {
  getEmployees,
  importEmployeesFromExcel,
  downloadExcelTemplate,
  sendOnboardingEmail,
} from "../../../services/workforce.service";
import {
  getSchemesWithTypes,
  getSchemeTypes,
  getDistricts,
} from "../../../services/master.service";
import toast from "react-hot-toast";

const EXPORT_COLUMNS = [
  { key: "employee_code", header: "Emp Code" },
  { key: "full_name", header: "Name" },
  { key: "scheme_name", header: "Scheme" },
  { key: "district_name", header: "District" },
  { key: "post_name", header: "Post" },
  { key: "contract_start", header: "Contract Start" },
  { key: "contract_end", header: "Contract End" },
];

const EmployeeList = () => {
  const fileInputRef = useRef(null);

  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isOnboardOpen, setIsOnboardOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  const [selectedScheme, setSelectedScheme] = useState("");
  const [selectedDistrict, setSelectedDistrict] = useState("");
  const [selectedSchemeType, setSelectedSchemeType] = useState("");
  const [selectedRows, setSelectedRows] = useState([]);
  const [locationType, setLocationType] = useState("all"); // "all", "hub", "osc"

  const [schemeOptions, setSchemeOptions] = useState([]);
  const [schemeTypes, setSchemeTypes] = useState([]);
  const [districtOptions, setDistrictOptions] = useState([]);
  const [, setSearchParams] = useSearchParams();
  const [emailLoading, setEmailLoading] = useState(false);
  const prevSearchRef = useRef("");

  const handleSearch = useCallback((value) => {
    // Only reset page to 1 if search value actually changed
    if (value !== prevSearchRef.current) {
      prevSearchRef.current = value;
      setSearchQuery(value);
      setPage(1);
    }
  }, []);
  useEffect(() => {
    const loadMasters = async () => {
      try {
        const [schemes, schemeTypes, districts] = await Promise.all([
          getSchemesWithTypes({ is_active: true }),
          getSchemeTypes({ is_active: true }),
          getDistricts({ is_active: true }),
        ]);
        setSchemeOptions(
          (schemes || []).map((s) => ({ 
            id: s.scheme_id, 
            name: s.scheme_name,
            scheme_type_id: s.scheme_type_id,
            district_id: s.district_id
          })),
        );
        setSchemeTypes(schemeTypes || []);
        setDistrictOptions(
          (districts || []).map((d) => ({
            id: d.district_id,
            name: d.district_name,
          })),
        );
      } catch {
        toast.error("Failed to load master data");
      }
    };
    loadMasters();
  }, []);

  // Filter options based on selections
  const filteredDistrictOptions = useMemo(() => {
    let options = districtOptions;
    // District filtering doesn't depend on scheme selection
    return options;
  }, [districtOptions]);

  // Group schemes by type like we did for OSC/Hub
  const schemesByType = schemeTypes.reduce((acc, type) => {
    acc[type.scheme_type_id] = {
      ...type,
      schemes: schemeOptions.filter(scheme => scheme.scheme_type_id === type.scheme_type_id)
    };
    return acc;
  }, {});

  // Filter schemes by district and scheme type
  const filteredSchemesByType = useMemo(() => {
    return Object.keys(schemesByType).reduce((acc, typeId) => {
      const type = schemesByType[typeId];
      
      // First filter by scheme type if selected
      if (selectedSchemeType && String(typeId) !== String(selectedSchemeType)) {
        return acc;
      }
      
      // Then filter by district if selected
      acc[typeId] = {
        ...type,
        schemes: selectedDistrict 
          ? type.schemes.filter(scheme => String(scheme.district_id) === String(selectedDistrict))
          : type.schemes
      };
      return acc;
    }, {});
  }, [selectedDistrict, selectedSchemeType, schemeOptions, schemeTypes]);

  const fetchEmployees = useCallback(async () => {
    setLoading(true);
    try {
      const response = await getEmployees({
        page,
        limit,
        search: searchQuery || undefined,
        district_id: selectedDistrict ? Number(selectedDistrict) : undefined,
        scheme_id: selectedScheme ? Number(selectedScheme) : undefined,
        scheme_type_id: selectedSchemeType ? Number(selectedSchemeType) : undefined,
      });

      setEmployees(response.data?.data || []);
      setTotalPages(response.data?.pagination?.totalPages || 1);
      setTotalItems(response.data?.pagination?.total || 0);
    } catch (err) {
      toast.error(
        err?.response?.data?.message ||
          err.message ||
          "Failed to load employees",
      );
    } finally {
      setLoading(false);
    }
  }, [page, limit, searchQuery, selectedDistrict, selectedScheme, selectedSchemeType]);

  useEffect(() => {
    fetchEmployees();
  }, [fetchEmployees]);
  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    try {
      setLoading(true);
      await importEmployeesFromExcel(file);
      toast.success("Employees imported successfully");
      fetchEmployees();
    } catch (err) {
      toast.error(err.message || "Upload failed");
    } finally {
      setLoading(false);
      e.target.value = null;
    }
  };

  const handleSampleDownload = async () => {
    try {
      setLoading(true);
      const blob = await downloadExcelTemplate();
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = "employee-onboarding-template.xlsx";
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      toast.success("Template downloaded");
    } catch (err) {
      toast.error(err.message || "Download failed");
    } finally {
      setLoading(false);
    }
  };

  const handleBulkEmail = async () => {
    try {
      const ids = selectedRows
        .map((row) => row?.applicant?.applicant_id)
        .filter((id) => !!id);

      if (!ids.length) {
        toast.error("No valid applicants selected");
        return;
      }

      setEmailLoading(true);

      await sendOnboardingEmail(ids);

      toast.success("Emails sent successfully!");
    } catch (err) {
      toast.error(
        err?.response?.data?.message || err?.message || "Failed to send emails",
      );
    } finally {
      setEmailLoading(false);
    }
  };

  const getStatusBadge = (employmentStatus, endDate) => {
    // First check employment_status from database
    if (employmentStatus === 'INACTIVE') {
      return (
        <span className="px-2 py-0.5 bg-gray-50 text-gray-700 text-xs rounded-full">
          Inactive
        </span>
      );
    }
    
    if (employmentStatus === 'ACTIVE') {
      return (
        <span className="px-2 py-0.5 bg-green-50 text-green-700 text-xs rounded-full">
          Active
        </span>
      );
    }
    
    // Fallback to contract date calculation if employment_status is not set
    if (!endDate) return null;
    const today = new Date();
    const end = new Date(endDate);
    const diffDays = Math.ceil((end - today) / (1000 * 60 * 60 * 24));
    if (end < today)
      return (
        <span className="px-2 py-0.5 bg-red-50 text-red-700 text-xs rounded-full">
          Expired
        </span>
      );
    if (diffDays <= 30)
      return (
        <span className="px-2 py-0.5 bg-amber-50 text-amber-700 text-xs rounded-full">
          ⚠ {diffDays}d
        </span>
      );
    return (
      <span className="px-2 py-0.5 bg-green-50 text-green-700 text-xs rounded-full">
        Active
      </span>
    );
  };

  const columns = useMemo(
    () => [
      { key: "employee_code", header: "Emp Code" },

      {
        key: "full_name",
        header: "Name",
        render: (_, r) => r.applicant?.personal?.full_name || "-",
      },

      {
        key: "scheme",
        header: "Scheme",
        render: (_, r) => r.scheme?.scheme_name || "-",
      },
      {
        key: "district",
        header: "District",
        render: (_, r) => r.district?.district_name || "-",
      },
      {
        key: "post",
        header: "Post",
        render: (_, r) => r.post?.post_name || "-",
      },

      {
        key: "contract_start",
        header: "Start",
        render: (_, r) =>
          new Date(r.contract_start_date).toLocaleDateString("en-IN"),
      },

      {
        key: "contract_end",
        header: "End",
        render: (_, r) =>
          new Date(r.contract_end_date).toLocaleDateString("en-IN"),
      },

      {
        key: "email_sent",
        header: "Email Sent",
        render: (_, r) => r.onboarding_email_sent_at || "-",
      },

      {
        key: "actions",
        header: "Actions",
        render: (_, row) => (
          <button
            type="button"
            className="p-2 text-blue-600 hover:bg-blue-50 rounded-full transition"
            onClick={() =>
              setSearchParams({
                tab: "employees",
                subtab: "employee-view",
                id: row.employee_id,
                fromTab: "employee-list",
              })
            }
          >
            <Eye className="h-5 w-5" />
          </button>
        ),
      },
    ],
    [],
  );

  return (
    <div className="space-y-4">
      {/* Filter Section */}
      <div className="bg-white p-4 rounded-xl shadow-sm">
        <div className="flex flex-col gap-4">
          {/* Primary Filters Row */}
          <div className="flex flex-wrap gap-3 items-center">
            {/* District Filter */}
            <DropdownSearch
              value={selectedDistrict}
              onChange={(e) => {
                setSelectedDistrict(e.target.value);
                setSelectedScheme(""); // Reset scheme when district changes
                setSelectedSchemeType(""); // Reset scheme type when district changes
              }}
              options={districtOptions}
              placeholder="All Districts"
            />

            {/* Scheme Type Filter */}
            <DropdownSearch
              value={selectedSchemeType}
              onChange={(e) => {
                setSelectedSchemeType(e.target.value);
                setSelectedScheme(""); // Reset scheme when scheme type changes
              }}
              options={schemeTypes.map(type => ({
                id: type.scheme_type_id,
                name: type.scheme_name
              }))}
              placeholder="All Scheme Types"
            />

            {/* Scheme Filter */}
            <DropdownSearch
              value={selectedScheme}
              onChange={(e) => setSelectedScheme(e.target.value)}
              options={Object.values(filteredSchemesByType).flatMap(type => 
                type.schemes.map(scheme => ({
                  id: scheme.id,
                  name: `${scheme.name} (${type.scheme_name})`,
                  group: type.scheme_name
                }))
              )}
              placeholder="All Schemes"
            />

            {/* Action Buttons */}
            <div className="flex gap-2 ml-auto">
              <button
                type="button"
                onClick={fetchEmployees}
                className="flex items-center gap-2 px-3 py-2 rounded-lg hover:bg-slate-100 text-slate-600 transition-colors text-sm font-medium"
                title="Refresh"
              >
                <RefreshCw className="h-4 w-4" />
                Refresh
              </button>

              <PermissionGuard permissions="hrm.onboarding.import">
                <Button
                  variant="outline"
                  onClick={() => fileInputRef.current?.click()}
                  className="flex items-center gap-2 border-blue-200 text-blue-700 hover:bg-blue-50"
                >
                  <Upload className="h-4 w-4" />
                  Upload Excel
                </Button>
              </PermissionGuard>

              <Button
                variant="outline"
                onClick={handleSampleDownload}
                className="flex items-center gap-2 border-amber-200 text-amber-700 hover:bg-amber-50"
              >
                <Download className="h-4 w-4" />
                Sample Excel
              </Button>
            </div>
          </div>

          {/* Secondary Actions Row */}
          <div className="flex flex-wrap gap-3 items-center pt-2 border-t border-slate-100">
            <PermissionGuard permissions="hrm.onboarding.email">
              <Button
                type="button"
                variant="outline"
                disabled={selectedRows.length === 0 || emailLoading}
                onClick={handleBulkEmail}
                className="flex items-center gap-2 border-blue-200 text-blue-700 hover:bg-blue-50"
              >
                {emailLoading ? (
                  <>
                    <RefreshCw className="h-4 w-4 animate-spin" />
                    Sending...
                  </>
                ) : (
                  <>
                    <Mail className="h-4 w-4" />
                    Send Email
                  </>
                )}
              </Button>
            </PermissionGuard>

            <PermissionGuard permissions="hrm.onboarding.create">
              <Button
                type="button"
                onClick={() => setIsOnboardOpen(true)}
                className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white"
              >
                <UserPlus className="h-4 w-4" />
                Onboard Employee
              </Button>
            </PermissionGuard>
          </div>
        </div>
      </div>

      <input
        type="file"
        accept=".xlsx,.xls"
        ref={fileInputRef}
        onChange={handleFileUpload}
        style={{ display: "none" }}
      />

      <DataTable
      showRowNumbers={true}
        columns={columns}
        data={employees}
        isLoading={loading}
        enableSelection={true}
        rowKey="employee_id"
        onSelectionChange={setSelectedRows}
        onSearch={handleSearch}
        pagination={{
          currentPage: page,
          totalPages,
          totalItems,
          onPageChange: (newPage) => {
            setPage(newPage);
          },
          pageSize: limit,
          onPageSizeChange: (newLimit) => {
            setLimit(newLimit);
            setPage(1);
          },
          pageSizeOptions: [10, 25, 50, 100],
        }}
      />

      <OnboardModal
        isOpen={isOnboardOpen}
        onClose={() => setIsOnboardOpen(false)}
        onSuccess={fetchEmployees}
      />
    </div>
  );
};

export default EmployeeList;
