import React, { useState, useMemo, useEffect, useCallback, useRef } from "react";
import { DataTable } from "../../../components/ui/DataTable";
import DropdownSearch from "../../../components/common/DropdownSearch";
import { getAttendanceRecords, downloadAttendancePDF } from "../../../services/workforce.service";
import { getDistricts, getSchemesWithTypes, getSchemeTypes } from "../../../services/master.service";
import { PermissionGuard } from "../../../components/auth/PermissionGuard";
import { FileText, Download } from "lucide-react";


const getStatusBadge = (status) => {
  const config = {
    PRESENT: "bg-emerald-50 text-emerald-700 bg-emerald-500",
    ABSENT: "bg-red-50 text-red-700 bg-red-500",
    ON_LEAVE: "bg-purple-50 text-purple-700 bg-purple-400",
    WEEKLY_OFF: "bg-blue-50 text-blue-700 bg-blue-500",
  };

  const [bg, text, dot] = config[status]?.split(" ") || [
    "bg-slate-100",
    "text-slate-500",
    "bg-slate-400",
  ];

  return (
    <span
      className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold ${bg} ${text}`}
    >
      <span className={`w-1.5 h-1.5 rounded-full ${dot}`} />
      {status}
    </span>
  );
};

const AttendanceRecords = () => {
  const now = new Date();
  const [selectedDistrict, setSelectedDistrict] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const prevSearchRef = useRef("");
  const [records, setRecords] = useState([]);
  const [loading, setLoading] = useState(false);
  const [districts, setDistricts] = useState([]);
  const [schemes, setSchemes] = useState([]);
  const [filteredSchemes, setFilteredSchemes] = useState([]);
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);
  const [selectedMonth, setSelectedMonth] = useState(now.getMonth() + 1);
  const [selectedYear, setSelectedYear] = useState(now.getFullYear());
  const [schemeTypes, setSchemeTypes] = useState([]);
  const [selectedSchemeType, setSelectedSchemeType] = useState("");
  const [schemeId, setSchemeId] = useState("");
  const [pdfLoading, setPdfLoading] = useState(false);
  const [dateRangeMode, setDateRangeMode] = useState(false);
  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");
  const [filterType, setFilterType] = useState("all");
  

  const fetchDistricts = async () => {
    try {
      const res = await getDistricts({ is_active: true });

      setDistricts(
        (res || []).map((d) => ({
          id: d.district_id,
          name: d.district_name,
        })),
      );
    } catch (err) {
      console.error(err);
    }
  };

  const fetchSchemes = async (districtId) => {
    try {
      const params = { is_active: true };
      if (districtId) params.district_id = districtId;
      const res = await getSchemesWithTypes(params);
      const schemesData = (res?.schemes || res || []).map((s) => ({
        id: s.scheme_id,
        name: s.scheme_name,
        scheme_type_id: s.scheme_type_id,
      }));
      setSchemes(schemesData);
      setFilteredSchemes(schemesData);
    } catch (err) {
      console.error("Error fetching schemes:", err);
    }
  };

  const handleDistrictChange = (value) => {
    setSelectedDistrict(value);
    setSelectedSchemeType("");
    setSchemeId("");
    fetchSchemes(value);
  };

  // API now handles filtering, so no client-side filtering needed
  const filtered = records;

  const fetchRecords = useCallback(async () => {
    try {
      setLoading(true);

      const params = {
        page,
        limit,
        search: searchQuery || undefined,
      };

      // Add date filter - either month/year or date range
      if (dateRangeMode && fromDate && toDate) {
        params.from_date = fromDate;
        params.to_date = toDate;
      } else if (selectedMonth && selectedYear) {
        params.month = selectedMonth;
        params.year = selectedYear;
      }

      // Add filter parameters based on selection
      if (selectedDistrict) {
        params.district_id = selectedDistrict;
        if (schemeId) params.scheme_id = schemeId;
        else if (selectedSchemeType) params.scheme_type_id = selectedSchemeType;
      }

      const res = await getAttendanceRecords(params);

      setRecords(res?.data?.data || []);
      setTotalPages(res?.data?.pagination?.totalPages || 1);
      setTotalItems(res?.data?.pagination?.total || 0);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [dateRangeMode, fromDate, toDate, selectedMonth, selectedYear, page, limit, searchQuery, selectedDistrict, selectedSchemeType, schemeId]);

  useEffect(() => {
    fetchRecords();
  }, [fetchRecords]);

  useEffect(() => {
    fetchDistricts();
    getSchemeTypes({ is_active: true })
      .then((res) => setSchemeTypes(res?.schemeTypes || res || []))
      .catch(console.error);
  }, []);

  const handleSearch = useCallback((value) => {
    // Only reset page to 1 if search value actually changed
    if (value !== prevSearchRef.current) {
      prevSearchRef.current = value;
      setSearchQuery(value);
      setPage(1);
    }
  }, []);

  const handleGeneratePDF = async () => {
    // Validate district selection
    if (!selectedDistrict) {
      alert("Please select a district to generate PDF");
      return;
    }

    try {
      setPdfLoading(true);

      const params = {
        district_id: selectedDistrict,
        search: searchQuery || undefined,
      };

      // Add date filter - either month/year or date range
      if (dateRangeMode && fromDate && toDate) {
        params.from_date = fromDate;
        params.to_date = toDate;
      } else if (selectedMonth && selectedYear) {
        params.month = selectedMonth;
        params.year = selectedYear;
      }

      // Add filter_type and scheme filters matching the records list filters
      params.filter_type = filterType || "all";
      if (selectedDistrict) {
        if (schemeId) params.scheme_id = schemeId;
        else if (selectedSchemeType) params.scheme_type_id = selectedSchemeType;
      }

      
      // Call service function to download PDF
      await downloadAttendancePDF(params);
    } catch (err) {
      console.error("Error generating PDF:", err);
      alert("Failed to generate PDF. Please try again.");
    } finally {
      setPdfLoading(false);
    }
  };

  const columns = useMemo(
    () => [
      {
        key: "attendance_date",
        header: "Date",
        sortable: true,
      },
      {
        key: "employee_code",
        header: "Emp Code",
        render: (_, row) => (
          <span className="font-mono text-xs text-slate-700">{row.employee_code || "-"}</span>
        ),
      },
      {
        key: "employee_name",
        header: "Name",
        render: (_, row) => (
          <span className="font-medium text-slate-900">{row.employee_name || "-"}</span>
        ),
      },
      {
        key: "check_in_time",
        header: "Check-In",
        render: (_, row) => (
          <span className="text-xs font-mono text-slate-600">{row.check_in_time || "--"}</span>
        ),
      },
      {
        key: "check_out_time",
        header: "Check-Out",
        render: (_, row) => (
          <span className="text-xs font-mono text-slate-600">{row.check_out_time || "--"}</span>
        ),
      },
      {
        key: "district_name",
        header: "District",
        render: (_, row) => (
          <span className="text-xs text-slate-700">{row.district_name || "-"}</span>
        ),
      },
      {
        key: "scheme_name",
        header: "Scheme",
        render: (_, row) => (
          <span className="text-xs text-slate-700">{row.scheme_name || "-"}</span>
        ),
      },
      {
        key: "scheme_type",
        header: "Type",
        render: (_, row) => (
          <span className="text-xs text-slate-600">{row.scheme_type || "-"}</span>
        ),
      },
      {
        key: "total_work_hours",
        header: "Total Hours",
        render: (_, row) => {
          if (!row.total_work_hours || row.total_work_hours === 0) {
            return <span className="text-xs text-slate-400">--</span>;
          }
          
          // Convert decimal hours to HH:MM format
          const hours = Math.floor(row.total_work_hours);
          const minutes = Math.round((row.total_work_hours - hours) * 60);
          
          return (
            <span className="text-xs font-mono text-slate-700">
              {hours}h {minutes.toString().padStart(2, '0')}m
            </span>
          );
        },
      },
  {
    key: "status_badge",
    header: "Status",
    render: (_, row) => getStatusBadge(row.status),
  },
  {
    key: "location",
    header: "Location",
    render: (_, row) => (
      <span className="text-xs font-mono text-slate-400">
        {row.location || "--"}
      </span>
    ),
  },
    ],
    [],
  );

  return (
  <PermissionGuard permissions="hrm.attendance.view">
    <div className="space-y-4"></div>
    <div className="space-y-4">
      <div className="flex items-center justify-between gap-3 flex-wrap">
        <div className="flex items-center gap-3 flex-wrap">
          <div className="w-32">
            <select
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
              disabled={dateRangeMode}
              className={`w-full border border-slate-200 rounded-lg px-3 py-2 text-sm ${
                dateRangeMode 
                  ? 'text-slate-400 bg-slate-50 cursor-not-allowed' 
                  : 'text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-400/30 focus:border-indigo-400'
              }`}
            >
              {Array.from({ length: 12 }, (_, i) => (
                <option key={i + 1} value={i + 1}>
                  {new Date(2026, i).toLocaleString('default', { month: 'long' })}
                </option>
              ))}
            </select>
          </div>
          <div className="w-24">
            <select
              value={selectedYear}
              onChange={(e) => setSelectedYear(parseInt(e.target.value))}
              disabled={dateRangeMode}
              className={`w-full border border-slate-200 rounded-lg px-3 py-2 text-sm ${
                dateRangeMode 
                  ? 'text-slate-400 bg-slate-50 cursor-not-allowed' 
                  : 'text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-400/30 focus:border-indigo-400'
              }`}
            >
              {Array.from({ length: now.getFullYear() - 2020 + 3 }, (_, i) => 2020 + i).map((year) => (
                <option key={year} value={year}>
                  {year}
                </option>
              ))}
            </select>
          </div>
          
          {/* Date Range Toggle */}
          <div className="flex items-center gap-2">
            <label className="flex items-center gap-1 cursor-pointer">
              <input
                type="radio"
                name="dateMode"
                checked={!dateRangeMode}
                onChange={() => setDateRangeMode(false)}
                className="w-4 h-4 text-blue-600"
              />
              <span className="text-sm text-slate-700">Month</span>
            </label>
            <label className="flex items-center gap-1 cursor-pointer">
              <input
                type="radio"
                name="dateMode"
                checked={dateRangeMode}
                onChange={() => setDateRangeMode(true)}
                className="w-4 h-4 text-blue-600"
              />
              <span className="text-sm text-slate-700">Date Range</span>
            </label>
          </div>
          
          {/* Date Range Inputs */}
          {dateRangeMode && (
            <>
              <div className="w-36">
                <input
                  type="date"
                  value={fromDate}
                  onChange={(e) => setFromDate(e.target.value)}
                  className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-400/30 focus:border-indigo-400"
                />
              </div>
              <div className="w-36">
                <input
                  type="date"
                  value={toDate}
                  onChange={(e) => setToDate(e.target.value)}
                  min={fromDate}
                  className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-400/30 focus:border-indigo-400"
                />
              </div>
            </>
          )}
          
          <div className="w-48">
            <DropdownSearch
              value={selectedDistrict}
              onChange={(e) => handleDistrictChange(e.target.value)}
              options={districts}
              placeholder="Select District"
            />
          </div>

          {selectedDistrict && (
            <>
              <div className="w-48">
                <DropdownSearch
                  value={selectedSchemeType}
                  onChange={(e) => {
                    setSelectedSchemeType(e.target.value);
                    setSchemeId("");
                  }}
                  options={schemeTypes.map((t) => ({ id: t.scheme_type_id, name: t.scheme_name }))}
                  placeholder="Scheme Type"
                />
              </div>

              <div className="w-48">
                <DropdownSearch
                  value={schemeId}
                  onChange={(e) => setSchemeId(e.target.value)}
                  options={schemes.filter((s) =>
                    selectedSchemeType
                      ? String(s.scheme_type_id) === String(selectedSchemeType)
                      : true
                  )}
                  placeholder="Select Scheme"
                />
              </div>
            </>
          )}
        </div>

        {/* PDF Download Button */}
        {selectedDistrict && (
          <button
            onClick={handleGeneratePDF}
            disabled={pdfLoading}
            className="inline-flex items-center gap-2 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <FileText className="w-4 h-4" />
            {pdfLoading ? "Generating..." : "Download All Records"}
          </button>
        )}
      </div>

      <DataTable
      enableSelection={false}
        columns={columns}
        data={filtered}
        onSearch={handleSearch}
        pagination={{
          currentPage: page,
          totalPages: totalPages,
          totalItems: totalItems,
          onPageChange: setPage,
          pageSize: limit,
          onPageSizeChange: (newLimit) => {
            setLimit(newLimit);
            setPage(1);
          },
          pageSizeOptions: [10, 25, 50],
        }}
        isLoading={loading}
        rowKey="attendance_id"
        headerClassName="bg-slate-900 text-white"
        showRowNumbers={true}
      />
    </div>
  </PermissionGuard>
  );
};

export default AttendanceRecords;
