import React, { useState, useEffect } from "react";
import { CheckCircle, XCircle, Clock, Eye, FileText, ArrowLeft } from "lucide-react";
import { Link, useNavigate } from "react-router-dom";
import { DataTable } from "../../../components/ui/DataTable";
import { PermissionGuard } from "../../../components/auth/PermissionGuard";
import {
  getPendingBulks,
  approveBulkAttendance,
} from "../../../services/workforce.service";
import DropdownSearch from "../../../components/common/DropdownSearch";

const BulkAttendancePending = () => {
  const navigate = useNavigate();
  const [bulks, setBulks] = useState([]);
  const [loading, setLoading] = useState(false);
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);
  const [selectedBulk, setSelectedBulk] = useState(null);
  const [actionLoading, setActionLoading] = useState(false);
  const [actionRemarks, setActionRemarks] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");

  useEffect(() => {
    fetchBulks();
  }, [page, limit, statusFilter]);

  const fetchBulks = async () => {
    try {
      setLoading(true);
      const params = { page, limit };
     if (statusFilter && statusFilter !== "all") {
  params.status = statusFilter;
}
      const res = await getPendingBulks(params);

      setBulks(res.data.bulks || []);
      setTotalPages(res.data.pagination?.totalPages || 1);
      setTotalItems(res.data.pagination?.total || 0);
    } catch (err) {
      console.error("Error fetching bulks:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (bulkId) => {
    if (
      !window.confirm("Are you sure you want to approve this bulk attendance?")
    ) {
      return;
    }

    try {
      setActionLoading(true);
      await approveBulkAttendance(bulkId, {
        action: "APPROVE",
        remarks: actionRemarks,
      });

      alert("Bulk attendance approved successfully!");
      setActionRemarks("");
      setSelectedBulk(null);
      fetchBulks();
    } catch (err) {
      console.error("Error approving bulk:", err);
      alert(err.response?.data?.message || "Failed to approve bulk attendance");
    } finally {
      setActionLoading(false);
    }
  };

  const handleReject = async (bulkId) => {
    if (!actionRemarks.trim()) {
      alert("Please provide remarks for rejection");
      return;
    }

    if (
      !window.confirm("Are you sure you want to reject this bulk attendance?")
    ) {
      return;
    }

    try {
      setActionLoading(true);
      await approveBulkAttendance(bulkId, {
        action: "REJECT",
        remarks: actionRemarks,
      });

      alert("Bulk attendance rejected successfully!");
      setActionRemarks("");
      setSelectedBulk(null);
      fetchBulks();
    } catch (err) {
      console.error("Error rejecting bulk:", err);
      alert(err.response?.data?.message || "Failed to reject bulk attendance");
    } finally {
      setActionLoading(false);
    }
  };

  const getStatusBadge = (status) => {
    const config = {
      PENDING: {
        bg: "bg-amber-50",
        text: "text-amber-700",
        dot: "bg-amber-500",
      },
      APPROVED: {
        bg: "bg-green-50",
        text: "text-green-700",
        dot: "bg-green-500",
      },
      REJECTED: { bg: "bg-red-50", text: "text-red-700", dot: "bg-red-500" },
      PARTIALLY_APPROVED: {
        bg: "bg-blue-50",
        text: "text-blue-700",
        dot: "bg-blue-500",
      },
    };

    const { bg, text, dot } = config[status] || config.PENDING;

    return (
      <span
        className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold ${bg} ${text}`}
      >
        <span className={`w-1.5 h-1.5 rounded-full ${dot}`} />
        {status}
      </span>
    );
  };

  const columns = [
    {
      key: "bulk_no",
      header: "Bulk No",
      render: (_, row) => (
        <span className="font-mono font-semibold text-slate-900">
          {row.bulk_no}
        </span>
      ),
    },
    {
      key: "month_year",
      header: "Month/Year",
      render: (_, row) => (
        <span className="text-sm text-slate-700">
          {row.month}/{row.year}
        </span>
      ),
    },
    {
      key: "uploader",
      header: "Uploaded By",
      render: (_, row) => (
        <div>
          <p className="text-sm font-medium text-slate-900">
            {row.uploader?.full_name || "-"}
          </p>
          <p className="text-xs text-slate-500">
            {row.uploader?.username || "-"}
          </p>
        </div>
      ),
    },
    {
      key: "upload_date",
      header: "Upload Date",
      render: (_, row) => (
        <span className="text-sm text-slate-700">
          {new Date(row.upload_date).toLocaleDateString()}
        </span>
      ),
    },
    {
      key: "records",
      header: "Records",
      render: (_, row) => (
        <div className="text-sm">
          <div className="flex items-center gap-2">
            <span className="font-semibold text-slate-900">
              {row.total_records}
            </span>
            <span className="text-slate-500">total</span>
          </div>
        </div>
      ),
    },
    {
      key: "status",
      header: "Status",
      render: (_, row) => getStatusBadge(row.status),
    },
    {
      key: "remarks",
      header: "Remarks",
      render: (_, row) => (
        <span className="text-xs text-slate-500">{row.remarks || "-"}</span>
      ),
    },
    {
      key: "actions",
      header: "Actions",
      render: (_, row) => (
        <div className="flex items-center gap-2">
          <button
            onClick={() => setSelectedBulk(row)}
            className="p-1.5 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
            title="View Details"
          >
            <Eye className="w-4 h-4" />
          </button>
          {row.status === "PENDING" && (
            <>
              <button
                onClick={() => handleApprove(row.bulk_id)}
                disabled={actionLoading}
                className="p-1.5 text-green-600 hover:bg-green-50 rounded-lg transition-colors disabled:opacity-50"
                title="Approve"
              >
                <CheckCircle className="w-4 h-4" />
              </button>
              <button
                onClick={() => {
                  setSelectedBulk(row);
                  setActionRemarks("");
                }}
                disabled={actionLoading}
                className="p-1.5 text-red-600 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-50"
                title="Reject"
              >
                <XCircle className="w-4 h-4" />
              </button>
            </>
          )}
        </div>
      ),
    },
  ];

  const statusOptions = [
    { id: "", name: "All Status" },
    { id: "PENDING", name: "Pending" },
    { id: "APPROVED", name: "Approved" },
    { id: "REJECTED", name: "Rejected" },
    { id: "PARTIALLY_APPROVED", name: "Partially Approved" },
  ];

  return (
    <PermissionGuard permissions="hrm.attendance.bulk_approve">
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold text-slate-900">
              Bulk Attendance Management
            </h1>
            <p className="text-sm text-slate-600 mt-1">
              Review and manage bulk attendance uploads
            </p>
          </div>
          <div className="w-48">
           
              <DropdownSearch
                value={statusFilter}
                onChange={(e) => {
                  setStatusFilter(e.target.value || "all");
                  setPage(1);
                }}
                options={statusOptions}
                placeholder="All Status"
              />
          
          </div>
        </div>

        <DataTable
        enableSelection={false}
          columns={columns}
          data={bulks}
          onSearch={() => {}}
          pagination={{
            currentPage: page,
            totalPages: totalPages,
            totalItems: totalItems,
            onPageChange: setPage,
            pageSize: limit,
            onPageSizeChange: (newLimit) => {
              setLimit(newLimit);
              setPage(1);
            },
            pageSizeOptions: [10, 25, 50],
          }}
          isLoading={loading}
          rowKey="bulk_id"
          headerClassName="bg-slate-900 text-white"
          showRowNumbers={true}
        />

        {/* Details Modal */}
        {selectedBulk && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-lg shadow-xl max-w-4xl w-full max-h-[90vh] overflow-y-auto">
              <div className="p-6 border-b border-slate-200">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <FileText className="w-6 h-6 text-blue-600" />
                    <div>
                      <h2 className="text-xl font-bold text-slate-900">
                        Bulk Details: {selectedBulk.bulk_no}
                      </h2>
                      <p className="text-sm text-slate-600">
                        {selectedBulk.month}/{selectedBulk.year}
                      </p>
                    </div>
                  </div>
                  <button
                    onClick={() => setSelectedBulk(null)}
                    className="text-slate-400 hover:text-slate-600"
                  >
                    ✕
                  </button>
                </div>
              </div>

              <div className="p-6 space-y-6">
                {/* Bulk Info */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  <div>
                    <p className="text-sm text-slate-600">Uploaded By</p>
                    <p className="font-semibold text-slate-900">
                      {selectedBulk.uploader?.full_name}
                    </p>
                  </div>
                  <div>
                    <p className="text-sm text-slate-600">Upload Date</p>
                    <p className="font-semibold text-slate-900">
                      {new Date(selectedBulk.upload_date).toLocaleDateString()}
                    </p>
                  </div>
                  <div>
                    <p className="text-sm text-slate-600">Total Records</p>
                    <p className="font-semibold text-slate-900">
                      {selectedBulk.total_records}
                    </p>
                  </div>
                  <div>
                    <p className="text-sm text-slate-600">Status</p>
                    {getStatusBadge(selectedBulk.status)}
                  </div>
                </div>

                {/* Sample Records */}
                {selectedBulk.sample_records &&
                  selectedBulk.sample_records.length > 0 && (
                    <div>
                      <h3 className="text-lg font-semibold text-slate-900 mb-3">
                        Sample Records (Latest 5)
                      </h3>
                      <div className="space-y-2">
                        {selectedBulk.sample_records.map((record) => (
                          <div
                            key={record.attendance_id}
                            className="p-3 bg-slate-50 rounded-lg border border-slate-200"
                          >
                            <div className="flex items-center justify-between">
                              <div className="flex items-center gap-4">
                                <span className="font-mono text-sm font-semibold text-slate-900">
                                  {record.employee?.employee_code}
                                </span>
                                <span className="text-sm text-slate-600">
                                  {record.employee?.applicant?.email}
                                </span>
                                <span className="text-sm text-slate-600">
                                  {new Date(
                                    record.attendance_date,
                                  ).toLocaleDateString()}
                                </span>
                              </div>
                              <div className="flex items-center gap-3">
                                {getStatusBadge(record.status)}
                                <span
                                  className={`text-xs px-2 py-1 rounded ${
                                    record.approval_status === "PENDING"
                                      ? "bg-amber-100 text-amber-700"
                                      : record.approval_status === "APPROVED"
                                        ? "bg-green-100 text-green-700"
                                        : "bg-red-100 text-red-700"
                                  }`}
                                >
                                  {record.approval_status}
                                </span>
                              </div>
                            </div>
                            {record.remarks && (
                              <p className="text-xs text-slate-500 mt-2">
                                {record.remarks}
                              </p>
                            )}
                          </div>
                        ))}
                      </div>
                    </div>
                  )}

                {/* Action Section */}
                {selectedBulk.status === "PENDING" && (
                  <div className="border-t border-slate-200 pt-6">
                    <h3 className="text-lg font-semibold text-slate-900 mb-3">
                      Take Action
                    </h3>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-sm font-medium text-slate-700 mb-2">
                          Remarks (Required)
                        </label>
                        <textarea
                          value={actionRemarks}
                          onChange={(e) => setActionRemarks(e.target.value)}
                          rows={3}
                          className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                          placeholder="Enter remarks..."
                        />
                      </div>
                      <div className="flex gap-3">
                        <button
                          onClick={() => handleApprove(selectedBulk.bulk_id)}
                          disabled={actionLoading}
                          className="flex-1 inline-flex items-center justify-center gap-2 px-4 py-2.5 bg-green-600 text-white rounded-lg hover:bg-green-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors font-medium"
                        >
                          <CheckCircle className="w-4 h-4" />
                          {actionLoading ? "Processing..." : "Approve All"}
                        </button>
                        <button
                          onClick={() => handleReject(selectedBulk.bulk_id)}
                          disabled={actionLoading || !actionRemarks.trim()}
                          className="flex-1 inline-flex items-center justify-center gap-2 px-4 py-2.5 bg-red-600 text-white rounded-lg hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors font-medium"
                        >
                          <XCircle className="w-4 h-4" />
                          {actionLoading ? "Processing..." : "Reject All"}
                        </button>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </PermissionGuard>
  );
};

export default BulkAttendancePending;
