import React, { useState, useMemo, useEffect } from "react";
import {
  IndianRupee,
  Users,
  ChevronDown,
  FileDown,
  FileText,
  Loader2,
  CheckCircle2,
  X,
  BadgeCheck,
  MapPin,
  Briefcase,
  Calendar,
} from "lucide-react";
import { DataTable } from "../../../components/ui/DataTable";
import DropdownSearch from "../../../components/common/DropdownSearch";
import toast from "react-hot-toast";
import { getPayslips, getEmployeePayslip, downloadEmployeePayslipPDF } from "../../../services/workforce.service";
import { getDistricts } from "../../../services/master.service";

const MONTHS = [
  { id: "1", name: "January" },
  { id: "2", name: "February" },
  { id: "3", name: "March" },
  { id: "4", name: "April" },
  { id: "5", name: "May" },
  { id: "6", name: "June" },
  { id: "7", name: "July" },
  { id: "8", name: "August" },
  { id: "9", name: "September" },
  { id: "10", name: "October" },
  { id: "11", name: "November" },
  { id: "12", name: "December" },
];
// Generate years dynamically from 2024 to current year + 2
const generateYears = () => {
  const currentYear = new Date().getFullYear();
  const years = [];
  for (let year = 2024; year <= currentYear + 2; year++) {
    years.push(year.toString());
  }
  return years;
};

const YEARS = generateYears();


const CircleProgress = ({ value, max, color, size = 56, stroke = 5 }) => {
  const r = (size - stroke) / 2,
    circ = 2 * Math.PI * r,
    dash = circ * Math.min(value / (max || 1), 1);
  return (
    <svg width={size} height={size} className="-rotate-90">
      <circle
        cx={size / 2}
        cy={size / 2}
        r={r}
        fill="none"
        stroke="#f1f5f9"
        strokeWidth={stroke}
      />
      <circle
        cx={size / 2}
        cy={size / 2}
        r={r}
        fill="none"
        stroke={color}
        strokeWidth={stroke}
        strokeDasharray={`${dash} ${circ}`}
        strokeLinecap="round"
        style={{ transition: "stroke-dasharray 0.6s ease" }}
      />
    </svg>
  );
};

// ── Salary Slip Modal ─────────────────────────────────────────────────────────
const SlipModal = ({ emp, month, year, onClose }) => {
  const [payslipData, setPayslipData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchPayslipDetails = async () => {
      try {
        setLoading(true);
        const data = await getEmployeePayslip(emp.id, month, year);
        setPayslipData(data);
      } catch (error) {
        toast.error("Failed to load payslip details");
        console.error(error);
      } finally {
        setLoading(false);
      }
    };

    fetchPayslipDetails();
  }, [emp.id, month, year]);

  const s = payslipData?.salary || {};
  const employee = payslipData?.employee || emp;
  const attendance = payslipData?.attendance || {};

  const initials = (employee.full_name || emp.name || 'E')
    .split(" ")
    .map((w) => w[0])
    .join("")
    .slice(0, 2)
    .toUpperCase();


  if (loading) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
        <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={onClose} />
        <div className="relative w-full max-w-lg bg-white rounded-2xl shadow-2xl p-8 flex items-center justify-center">
          <div className="text-center">
            <Loader2 className="h-8 w-8 animate-spin text-slate-600 mx-auto mb-4" />
            <p className="text-sm text-slate-600">Loading payslip details...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div
        className="absolute inset-0 bg-black/40 backdrop-blur-sm"
        onClick={onClose}
      />
      <div className="relative w-full max-w-lg bg-white rounded-2xl shadow-2xl overflow-hidden">
        <div className="px-6 py-4 bg-slate-900 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="h-9 w-9 rounded-xl bg-white/10 flex items-center justify-center text-sm font-bold text-white">
              {initials}
            </div>
            <div>
              <div className="flex items-center gap-1.5">
                <p className="text-sm font-bold text-white">{employee.full_name || emp.name}</p>
                <BadgeCheck className="h-3.5 w-3.5 text-blue-400" />
              </div>
              <p className="text-xs text-slate-400 font-mono">
                {employee.employee_code || emp.code} · {month} {year}
              </p>
            </div>
          </div>
          <button
            onClick={onClose}
            className="text-slate-400 hover:text-white transition-colors"
          >
            <X className="h-4 w-4" />
          </button>
        </div>
        <div className="bg-slate-50 border-b border-slate-100 px-6 py-3 flex flex-wrap items-center gap-4 text-xs text-slate-500">
          <span className="flex items-center gap-1.5">
            <MapPin className="h-3.5 w-3.5 text-slate-400" />
            {employee.district_name || emp.district}
          </span>
          <span className="flex items-center gap-1.5">
            <Briefcase className="h-3.5 w-3.5 text-slate-400" />
            {employee.post_name || emp.post}
          </span>
          <span className="flex items-center gap-1.5">
            <Calendar className="h-3.5 w-3.5 text-slate-400" />
            Absent: {attendance.absent_days || 0} day{attendance.absent_days !== 1 ? "s" : ""}
          </span>
        </div>
        <div className="p-6 space-y-4">
          <div className="grid grid-cols-2 gap-3">
            <div className="bg-green-50 border border-green-100 rounded-xl p-4 space-y-2">
              <p className="text-[10px] font-bold uppercase tracking-widest text-green-600 mb-2">
                Earnings
              </p>
              <div className="flex justify-between text-xs">
                <span className="text-slate-600">Monthly Pay</span>
                <span className="font-semibold text-slate-800">
                  ₹{(s.monthly_pay || 0).toLocaleString("en-IN")}
                </span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-slate-600">Working Days</span>
                <span className="font-semibold text-slate-800">
                  {attendance.working_days || 0} days
                </span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-slate-600">Paid Days</span>
                <span className="font-semibold text-slate-800">
                  {attendance.paid_days || 0} days
                </span>
              </div>
              <div className="border-t border-green-200 pt-2 flex justify-between text-xs font-bold text-green-700">
                <span>Calculated Salary</span>
                <span>₹{(s.calculated_salary || 0).toLocaleString("en-IN")}</span>
              </div>
            </div>
            <div className="bg-red-50 border border-red-100 rounded-xl p-4 space-y-2">
              <p className="text-[10px] font-bold uppercase tracking-widest text-red-500 mb-2">
                Deductions
              </p>
              <div className="flex justify-between text-xs">
                <span className="text-slate-600">Absent Deduction</span>
                <span className="font-semibold text-slate-800">
                  ₹{(s.attendance_deduction || 0).toLocaleString("en-IN")}
                </span>
              </div>

              {/* Additional Deductions with Breakdown */}
              {s.deduction_breakdown && s.deduction_breakdown.length > 0 && (
                <>
                  <div className="border-t border-red-100 pt-2 mt-2">
                    {s.deduction_breakdown.map((deduction, index) => (
                      <div key={index} className="space-y-1">
                        <div className="flex justify-between text-xs">
                          <span className="text-slate-600">{deduction.name}</span>
                          <span className="font-semibold text-slate-800">
                            ₹{deduction.amount.toLocaleString("en-IN")}
                          </span>
                        </div>
                        <div className="text-[10px] text-slate-500 italic ml-4">
                          {deduction.reason}
                        </div>
                      </div>
                    ))}
                  </div>
                </>
              )}
              <div className="border-t border-red-200 pt-2 flex justify-between text-xs font-bold text-red-600">
                <span>Total Deduction</span>
                <span>₹{(s.total_deduction || 0).toLocaleString("en-IN")}</span>
              </div>
            </div>
          </div>
          <div className="bg-slate-900 rounded-xl px-5 py-4 flex items-center justify-between">
            <div>
              <p className="text-xs text-slate-400 uppercase tracking-widest font-semibold">
                Net Payable
              </p>
              <p className="text-2xl font-black text-white mt-0.5">
                ₹{(s.net_salary || 0).toLocaleString("en-IN")}
              </p>
            </div>
            <IndianRupee className="h-8 w-8 text-white/20" />
          </div>
        </div>
        <div className="flex justify-end gap-3 px-6 py-4 border-t border-slate-100 bg-slate-50">
          <button
            onClick={onClose}
            className="px-4 py-2 rounded-xl text-sm font-semibold text-slate-600 border border-slate-200 hover:bg-slate-100 transition-all"
          >
            Close
          </button>
        </div>
      </div>
    </div>
  );
};

// ── Main ──────────────────────────────────────────────────────────────────────
const SalaryCalculation = () => {
  const [selectedMonth, setSelectedMonth] = useState("5");
  const [selectedYear, setSelectedYear] = useState("2026");
  const [selectedDistrict, setSelectedDistrict] = useState("");
  const [slipEmp, setSlipEmp] = useState(null);
  const [loading, setLoading] = useState(false);
  const [districtOptions, setDistrictOptions] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [summary, setSummary] = useState(null);
  const [pagination, setPagination] = useState({
    currentPage: 1,
    totalPages: 1,
    totalRecords: 0,
    recordsOnPage: 0
  });
  const [searchTerm, setSearchTerm] = useState("");
  const [pageSize, setPageSize] = useState(10);

  const calculated = useMemo(
    () =>
      employees.filter(
        (e) => !selectedDistrict || e.district === selectedDistrict,
      ),
    [employees, selectedDistrict],
  );

  const monthName = MONTHS.find((m) => m.id === selectedMonth)?.name || "";

  const totalNet = calculated.reduce((a, b) => a + (Number(b.net) || 0), 0);
  const totalDeduct = calculated.reduce((a, b) => a + (Number(b.total_deduct) || 0), 0);

  const fetchPayslips = async (page = 1, search = "") => {
    try {
      setLoading(true);

      const params = {
        month: selectedMonth,
        year: selectedYear,
        page,
        limit: pageSize,
        ...(selectedDistrict && { district_id: selectedDistrict }),
        ...(search && { search })
      };

      const response = await getPayslips(params);
      const data = response.data || response; // Handle nested structure

      const employeesData = data.employees || [];
      const paginationData = data.pagination || {};


      const mapped = employeesData.map((item, index) => ({
        id: item.employee_id || `emp-${index}`,
        code: String(item.employee_code || ''),
        name: String(item.full_name || ''),
        district: String(item.district_name || ''),
        post: String(item.post_name || ''),

        basic: Number(item.basic_salary) || 0,
        total_deduct: Number(item.total_deduction) || 0,
        net: Number(item.net_pay) || 0,
      }));

      setEmployees(mapped);
      setSummary(data.summary);
      setPagination({
        currentPage: paginationData.current_page || 1,
        totalPages: paginationData.total_pages || 1,
        totalRecords: paginationData.total_records || 0,
        recordsOnPage: paginationData.records_on_page || 0
      });
    } catch (error) {
      console.error(error);
      toast.error("API failed");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const loadDistricts = async () => {
      try {
        const res = await getDistricts({ is_active: true });

        const formatted = (res || []).map((d) => ({
          id: d.district_id,
          name: d.district_name,
        }));

        setDistrictOptions(formatted);
      } catch {
        toast.error("District load failed");
      }
    };

    loadDistricts();
  }, []);

  useEffect(() => {
    fetchPayslips(1, searchTerm);
  }, [selectedMonth, selectedYear, selectedDistrict, pageSize]); // Remove searchTerm to prevent loop

  const handleSearch = (search) => {
    if (search !== searchTerm) {
      setSearchTerm(search);
      fetchPayslips(1, search);
    }
  };

  const handlePageChange = (page) => {
    fetchPayslips(page, searchTerm);
  };

  const handlePdfDownload = async (employeeId) => {
    try {
      await downloadEmployeePayslipPDF(employeeId, selectedMonth, selectedYear);
      toast.success("PDF payslip downloaded successfully");
    } catch (error) {
      toast.error("Failed to download PDF");
      console.error("PDF download error:", error);
    }
  };

  const handlePageSizeChange = (size) => {
    setPageSize(size);
    fetchPayslips(1, searchTerm);
  };

  const columns = useMemo(
    () => [
      {
        key: "name",
        header: "Employee",
        sortable: true,
        render: (_, row) => (
          <div className="flex items-center gap-2.5">
            <div>
              <p className="font-semibold text-slate-800 text-xs">{row.name}</p>
              <p className="text-[10px] text-slate-400 font-mono">{row.code}</p>
            </div>
          </div>
        ),
      },
      {
        key: "district",
        header: "District",
        sortable: true,
        render: (_, row) => (
          <span className="text-xs text-slate-600">{row.district}</span>
        ),
      },
      {
        key: "post",
        header: "Post",
        sortable: true,
        render: (_, row) => (
          <span className="text-xs text-slate-600">{row.post}</span>
        ),
      },
      {
        key: "basic",
        header: "Basic",
        render: (_, row) => (
          <span className="text-xs font-medium text-slate-700 float-right">
            ₹{row.basic.toLocaleString("en-IN")}
          </span>
        ),
      },
      {
        key: "total_deduct",
        header: "Deductions",
        render: (_, row) => (
          <span className="text-xs font-semibold text-red-600 float-right">
            {row.total_deduct > 0
              ? `−₹${row.total_deduct.toLocaleString("en-IN")}`
              : "—"}
          </span>
        ),
      },
      {
        key: "net",
        header: "Net Pay",
        render: (_, row) => (
          <span className="text-sm font-black text-slate-900 float-right">
            ₹{row.net.toLocaleString("en-IN")}
          </span>
        ),
      },
      {
        key: "slip",
        header: "Slip",
        className: "text-center",
        render: (_, row) => (
          <div className="flex items-center justify-center gap-1 mx-auto">
            <button
              onClick={() => setSlipEmp(row)}
              title="View Slip"
              className="flex items-center justify-center w-8 h-8 rounded-lg bg-slate-50 hover:bg-slate-100 border border-slate-200 transition-all"
            >
              <FileText className="h-3.5 w-3.5 text-slate-600" />
            </button>
            <button
              onClick={() => handlePdfDownload(row.id)}
              title="Download PDF"
              className="flex items-center justify-center w-8 h-8 rounded-lg bg-blue-50 hover:bg-blue-100 border border-blue-200 transition-all"
            >
              <FileDown className="h-3.5 w-3.5 text-blue-600" />
            </button>
          </div>
        ),
      },
    ],
    [],
  );

  return (
    <div className="space-y-5">
      {/* Controls Row */}
      <div className="flex items-center justify-between gap-3 flex-wrap">
        {/* Left */}
        <div className="flex items-center gap-3 flex-wrap">
          <div className="relative">
            <select
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="appearance-none bg-white border border-slate-200 rounded-xl px-4 py-2.5 pr-8 text-sm font-medium text-slate-700 outline-none focus:border-slate-400 cursor-pointer"
            >
              {MONTHS.map((m) => (
                <option key={m.id} value={m.id}>
                  {m.name}
                </option>
              ))}
            </select>
            <ChevronDown className="h-3.5 w-3.5 text-slate-400 absolute right-2.5 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
          <div className="relative">
            <select
              value={selectedYear}
              onChange={(e) => setSelectedYear(e.target.value)}
              className="appearance-none bg-white border border-slate-200 rounded-xl px-4 py-2.5 pr-8 text-sm font-medium text-slate-700 outline-none focus:border-slate-400 cursor-pointer"
            >
              {YEARS.map((y) => (
                <option key={y} value={y}>
                  {y}
                </option>
              ))}
            </select>
            <ChevronDown className="h-3.5 w-3.5 text-slate-400 absolute right-2.5 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
          <div className="w-48">
            <DropdownSearch
              value={selectedDistrict}
              onChange={(e) => setSelectedDistrict(e.target.value)}
              options={districtOptions}
              placeholder="All Districts"
            />
          </div>
        </div>
        {/* Right */}
        <div className="flex items-center gap-2">
          {/* Export functionality moved to backend */}
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          {
            label: "Total Employees",
            value: Number(summary?.total_employees) || calculated.length,
            max: Number(summary?.total_employees) || calculated.length,
            color: "#3b82f6",
            bg: "#eff6ff",
            icon: Users,
            fmt: false,
            sub: `${monthName} ${selectedYear}`,
          },
          {
            label: "Total Basic",
            value: Number(summary?.total_basic_salary) || calculated.reduce((a, b) => a + (Number(b.basic) || 0), 0),
            max: Number(summary?.total_basic_salary) || calculated.reduce((a, b) => a + (Number(b.basic) || 0), 0),
            color: "#10b981",
            bg: "#ecfdf5",
            icon: IndianRupee,
            fmt: true,
            sub: "Monthly salary",
          },
          {
            label: "Total Deductions",
            value: Number(summary?.total_deduction) || totalDeduct,
            max: Number(summary?.total_deduction) || totalDeduct,
            color: "#ef4444",
            bg: "#fef2f2",
            icon: IndianRupee,
            fmt: true,
            sub: "Absent deductions",
          },
          {
            label: "Net Payable",
            value: Number(summary?.total_net_pay) || totalNet,
            max: Number(summary?.total_net_pay) || totalNet,
            color: "#0f172a",
            bg: "#f8fafc",
            icon: IndianRupee,
            fmt: false,
            sub: `${monthName} ${selectedYear}`,
          },
        ].map((card, i) => (
          <div
            key={i}
            className="bg-white rounded-2xl p-4 shadow-sm border border-slate-100 flex items-center gap-4 hover:shadow-md transition-all"
          >
            <div className="relative flex-shrink-0">
              <CircleProgress
                value={card.value}
                max={card.max}
                color={card.color}
                size={56}
                stroke={5}
              />
              <div className="absolute inset-0 flex items-center justify-center">
                <div
                  className="w-8 h-8 rounded-full flex items-center justify-center"
                  style={{ background: card.bg }}
                >
                  <card.icon
                    className="h-4 w-4"
                    style={{ color: card.color }}
                  />
                </div>
              </div>
            </div>
            <div className="min-w-0">
              <p className="text-base font-black text-slate-800 leading-none truncate">
                {card.fmt
                  ? `₹${card.value.toLocaleString("en-IN")}`
                  : card.value}
              </p>
              <p className="text-xs font-semibold text-slate-600 mt-0.5">
                {card.label}
              </p>
              <p className="text-[10px] text-slate-400 mt-0.5">{card.sub}</p>
            </div>
          </div>
        ))}
      </div>

      <DataTable
        columns={columns}
        data={employees}
        onSearch={handleSearch}
        pagination={{
          currentPage: pagination.currentPage || 1,
          totalPages: pagination.totalPages || 1,
          totalItems: pagination.totalRecords || 0,
          onPageChange: handlePageChange,
          pageSize: pageSize || 10,
          onPageSizeChange: handlePageSizeChange,
          pageSizeOptions: [10, 25, 50],
        }}
        isLoading={loading}
        rowKey="id"
        headerClassName="bg-slate-900 text-white"
        showRowNumbers={true}
        enableSelection={false}
        searchPlaceholder="Search by employee code or name..."
      />

      {slipEmp && (
        <SlipModal
          emp={slipEmp}
          month={selectedMonth}
          year={selectedYear}
          onClose={() => setSlipEmp(null)}
        />
      )}
    </div>
  );
};

export default SalaryCalculation;
