const divisionHues = {
  'Amravati': 30,
  'Aurangabad': 200,
  'Konkan': 120,
  'Nagpur': 270,
  'Nashik': 45,
  'Pune': 0,
  'Ratnagiri': 180,
  'Sindhudurg': 300,
};

const canonicalDistrictName = (name) => {
  if (!name) return null;
  const normalized = name.toLowerCase().trim().replace(/\s+/g, ' ');
  return DISTRICT_NAME_MAPPING[normalized] || normalized;
};

const formatDistrictName = (name) => {
  if (!name) return '';
  return name.split(' ').map(word => 
    word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()
  ).join(' ');
};

const hexToRgb = (hex) => {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : null;
};

const rgbToHex = ({ r, g, b }) =>
  '#' +
  [r, g, b]
    .map((v) => {
      const h = v.toString(16);
      return h.length === 1 ? '0' + h : h;
    })
    .join('');

const mixHex = (fromHex, toHex, t) => {
  const a = hexToRgb(fromHex);
  const b = hexToRgb(toHex);
  const mix = (ax, bx) => Math.round(ax + (bx - ax) * t);
  return rgbToHex({ r: mix(a.r, b.r), g: mix(a.g, b.g), b: mix(a.b, b.b) });
};

const hslToHex = (h, s, l) => {
  const a = s * Math.min(l, 100 - l) / 10000;
  const f = (n) => {
    const k = (n + h / 30) % 12;
    const color = l - a * Math.max(Math.min(k - 3, 9 - k, 1), -1) * 100;
    return Math.round(color * 2.55)
      .toString(16)
      .padStart(2, '0');
  };
  return `#${f(0)}${f(8)}${f(4)}`;
};

const EnhancedMaharashtraMap = ({ 
  summaryData = [], 
  schemeLocations = [], 
  onDistrictSelect, 
  selectedDistrictName,
  width = 400,
  height = 350 
}) => {
  const [geographies, setGeographies] = useState([]);
  const [stateBoundary, setStateBoundary] = useState(null);
  const [tooltip, setTooltip] = useState({ show: false, x: 0, y: 0, content: null });
  const [hoveredDistrict, setHoveredDistrict] = useState(null);

  useEffect(() => {
    fetch('/admin/maps/maharashtra.topo.json')
      .then(res => res.json())
      .then(topo => {
        const geo = feature(topo, topo.objects.districts);
        setGeographies(geo.features);
        
        const merged = merge(topo, topo.objects.districts.geometries);
        setStateBoundary(merged);
      })
      .catch(err => console.error('Failed to load map topology:', err));
  }, []);

  const summaryLookup = useMemo(() => {
    const aggregated = {};
    summaryData.forEach((district) => {
      const key = canonicalDistrictName(district.district_name);
      if (!key) return;
      if (!aggregated[key]) {
        aggregated[key] = {
          district_name: formatDistrictName(key),
          application_count: 0,
          post_count: 0,
          attendance_percentage: 0,
        };
      }
      aggregated[key].application_count += district.application_count ?? 0;
      aggregated[key].post_count += district.post_count ?? 0;
      aggregated[key].attendance_percentage = district.attendance_percentage ?? 0;
    });
    return aggregated;
  }, [summaryData]);

  const getDistrictNameForMatching = (mapDistrictName) => {
    return canonicalDistrictName(mapDistrictName);
  };

  const { path, viewBox } = useMemo(() => {
    if (geographies.length === 0) return { path: null, viewBox: `0 0 ${width} ${height}` };
    const size = [width, height];
    const projection = geoMercator().fitSize(size, { type: 'FeatureCollection', features: geographies });
    const p = geoPath().projection(projection);
    return { path: p, viewBox: `0 0 ${size[0]} ${size[1]}` };
  }, [geographies, width, height]);

  const palette = useMemo(() => {
    const districtColors = {};
    const divisionDistricts = {};
    geographies.forEach((geo) => {
      const districtKey = getDistrictNameForMatching(geo.properties.district);
      const division = DIVISION_MAPPING[districtKey] || 'Unknown';
      if (!divisionDistricts[division]) divisionDistricts[division] = [];
      if (!divisionDistricts[division].includes(districtKey)) {
        divisionDistricts[division].push(districtKey);
      }
    });

    Object.keys(divisionDistricts).forEach((division) => {
      const districts = divisionDistricts[division].sort();
      const n = districts.length;
      const baseHue = divisionHues[division] || 0;
      const hueSpread = 30;
      districts.forEach((dist, i) => {
        const offset = n > 1 ? (i / (n - 1) - 0.5) * hueSpread : 0;
        const hue = (baseHue + offset + 360) % 360;
        districtColors[dist] = hslToHex(hue, 70, 85);
      });
    });

    return districtColors;
  }, [geographies]);

  const getColor = (districtKey, attendanceData) => {
    if (!attendanceData) return '#e5e7eb'; // Default gray for no data
    
    const percentage = attendanceData.attendance_percentage || 0;
    
    // Base colors for attendance ranges
    if (percentage >= 75) return '#10b981'; // Green for 75%+
    if (percentage >= 50) return '#3b82f6'; // Blue for 50-74%
    if (percentage > 0) return '#f59e0b';   // Amber for 1-49%
    return '#ef4444'; // Red for 0%
  };

  const handleMouseMove = (e, districtKey) => {
    const attendanceData = summaryLookup[districtKey];
    const districtSchemes = schemeLocations.filter(scheme => 
      canonicalDistrictName(scheme.district_name) === districtKey
    );
    
    let content = {
      name: attendanceData?.district_name || districtKey,
      attendance: `${attendanceData?.application_count || 0}/${attendanceData?.post_count || 0} (${attendanceData?.attendance_percentage || 0}%)`,
      schemes: []
    };
    
    // Add OSC/HUB details for this district
    districtSchemes.forEach(scheme => {
      content.schemes.push({
        name: scheme.scheme_name,
        type: scheme.scheme_type,
        attendance: `${scheme.present_today || 0}/${scheme.total_employees || 0} (${scheme.attendance_percentage || 0}%)`
      });
    });
    
    setHoveredDistrict(districtKey);
    setTooltip({
      show: true,
      x: e.clientX,
      y: e.clientY,
      content
    });
  };

  const handleMouseLeave = () => {
    setHoveredDistrict(null);
    setTooltip(prev => ({ ...prev, show: false }));
  };

  const projection = useMemo(() => {
    if (geographies.length === 0) return null;
    return geoMercator().fitSize([width, height], { type: 'FeatureCollection', features: geographies });
  }, [geographies, width, height]);

  const getSchemeMarkerPosition = (latitude, longitude) => {
    if (!projection) return { x: 0, y: 0 };
    const [x, y] = projection([longitude, latitude]);
    return { x, y };
  };

  return (
    <div className="relative">
      <svg
        width={width}
        height={height}
        viewBox={viewBox}
        className="w-full h-full"
        style={{ maxWidth: '100%', height: 'auto' }}
      >
        <defs>
          <filter id="glow">
            <feGaussianBlur stdDeviation="3" result="coloredBlur"/>
            <feMerge>
              <feMergeNode in="coloredBlur"/>
              <feMergeNode in="SourceGraphic"/>
            </feMerge>
          </filter>
        </defs>
        {/* State Boundary */}
        {stateBoundary && path(stateBoundary) && (
          <path
            d={path(stateBoundary)}
            fill="none"
            stroke="#374151"
            strokeWidth={2}
            strokeLinejoin="round"
            strokeLinecap="round"
          />
        )}

        {/* Districts */}
        {geographies.map((geo) => {
          const districtKey = getDistrictNameForMatching(geo.properties.district);
          const attendanceData = summaryLookup[districtKey];
          const isSelected = selectedDistrictName && 
            canonicalDistrictName(selectedDistrictName) === districtKey;
          const isHovered = hoveredDistrict === districtKey;
          
          
          return (
            <path
              key={geo.properties.district}
              d={path(geo)}
              className="transition-all duration-300 cursor-pointer outline-none"
              style={{
                fill: getColor(districtKey, attendanceData),
                stroke: '#1e293b',
                strokeWidth: isHovered || isSelected ? '2.5' : '1.2',
                strokeLinejoin: 'round',
                filter: isSelected ? 'url(#glow)' : 'none',
                opacity: 1
              }}
              onClick={() => {
                // Try multiple ways to find the district data
                let districtData = summaryData.find(d => 
                  canonicalDistrictName(d.district_name) === districtKey
                );
                
                // If not found, try direct comparison
                if (!districtData) {
                  districtData = summaryData.find(d => 
                    d.district_name?.toLowerCase().trim() === geo.properties.district?.toLowerCase().trim()
                  );
                }
                
                // If still not found, try fuzzy matching
                if (!districtData) {
                  districtData = summaryData.find(d => 
                    d.district_name?.toLowerCase().includes(geo.properties.district?.toLowerCase()) ||
                    geo.properties.district?.toLowerCase().includes(d.district_name?.toLowerCase())
                  );
                }
                
                if (districtData) {
                  onDistrictSelect(districtData);
                }
              }}
              onMouseMove={(e) => handleMouseMove(e, districtKey)}
              onMouseLeave={handleMouseLeave}
            />
          );
        })}

        {/* Scheme Location Markers */}
        {schemeLocations.map((scheme, index) => {
          if (!scheme.latitude || !scheme.longitude) return null;
          
          const position = getSchemeMarkerPosition(scheme.latitude, scheme.longitude);
          const attendancePercentage = scheme.attendance_percentage || 0;
          const color = attendancePercentage >= 75 ? '#10b981' : 
                       attendancePercentage >= 50 ? '#3b82f6' : 
                       attendancePercentage > 0 ? '#f59e0b' : '#ef4444';
          
          return (
            <g key={`scheme-${index}`} transform={`translate(${position.x}, ${position.y})`}>
              {/* Small marker circle */}
              <circle
                r="3"
                fill={color}
                stroke="white"
                strokeWidth="1"
                className="cursor-pointer hover:r-4 transition-all duration-200"
              />
            </g>
          );
        })}
      </svg>

      {/* Tooltip */}
      {tooltip.show && tooltip.content && (
        <div
          className="fixed z-50 pointer-events-none"
          style={{
            left: `${tooltip.x}px`,
            top: `${tooltip.y - 10}px`,
            transform: 'translate(-50%, -100%)'
          }}
        >
          <div className="bg-slate-900 text-white px-4 py-3 rounded-lg shadow-2xl border border-slate-700 backdrop-blur-sm">
            <div className="font-semibold text-sm mb-2 text-slate-100">{tooltip.content.name}</div>
            <div className="space-y-1 text-xs">
              <div className="flex items-center justify-between gap-6">
                <span className="text-slate-300">Attendance:</span>
                <span className="font-mono font-medium text-blue-300">{tooltip.content.attendance}</span>
              </div>
              
              {tooltip.content.schemes.length > 0 && (
                <div className="pt-2 mt-2 border-t border-slate-700">
                  <div className="text-slate-400 text-xs mb-1">OSC/HUB Centers:</div>
                  {tooltip.content.schemes.map((scheme, idx) => (
                    <div key={idx} className="text-slate-300 text-xs mb-1">
                      <div className="flex items-center justify-between gap-4">
                        <span>{scheme.name} ({scheme.type})</span>
                        <span className="font-mono text-emerald-300">{scheme.attendance}</span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Legend */}
      <div className="absolute bottom-2 right-2 bg-white/95 backdrop-blur-sm p-2 rounded-lg shadow-lg border border-slate-200 text-xs">
        <div className="font-semibold mb-1 text-xs">Attendance Rate</div>
        <div className="space-y-0.5">
          <div className="flex items-center gap-1">
            <div className="w-2 h-2 bg-green-500 rounded-full"></div>
            <span className="text-[10px]">75%+ (Excellent)</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
            <span className="text-[10px]">50-74% (Good)</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-2 h-2 bg-amber-500 rounded-full"></div>
            <span className="text-[10px]">1-49% (Low)</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-2 h-2 bg-red-500 rounded-full"></div>
            <span className="text-[10px]">0% (Absent)</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default EnhancedMaharashtraMap;
