import React from "react";
import { Routes, Route, Navigate } from "react-router-dom";
import EmployeeList from "../pages/workforce/employees/EmployeeList";
import HRMPage from "../pages/workforce/HRMPage";
import CalendarPage from "../pages/workforce/CalendarPage";
import BulkAttendanceUpload from "../pages/workforce/attendance/BulkAttendanceUpload";
import BulkAttendancePending from "../pages/workforce/attendance/BulkAttendancePending";
import HRMSettings from "../pages/workforce/settings/HRMSettings";
import EmployeeWeeklyOffClaim from "../pages/workforce/weekly-off/EmployeeWeeklyOffClaim";
import WeeklyOffApproval from "../pages/workforce/weekly-off/WeeklyOffApproval";

const WorkforceRoutes = () => {
  return (
    <Routes>
      <Route path="/" element={<Navigate to="hrm" replace />} />
      <Route path="hrm" element={<HRMPage />} />
      <Route path="calendar" element={<CalendarPage />} />
      <Route path="employees" element={<EmployeeList />} />
      <Route path="attendance/bulk-upload" element={<BulkAttendanceUpload />} />
      <Route path="attendance/bulk-pending" element={<BulkAttendancePending />} />
      <Route path="weekly-off/claims" element={<EmployeeWeeklyOffClaim />} />
      <Route path="weekly-off/approval" element={<WeeklyOffApproval />} />
      <Route path="settings" element={<HRMSettings />} />
    </Routes>
  );
};

export default WorkforceRoutes;