import React, { useState, useEffect, useCallback, useRef, useMemo } from "react";
import { DataTable } from "../../../components/ui/DataTable";
import { Button } from "../../../components/common/Button";
import { Modal } from "../../../components/common/Modal";
import toast from "react-hot-toast";
import {
  getPendingWeeklyOffClaims,
  approveWeeklyOffClaim,
} from "../../../services/workforce.service";
import {
  CheckCircle2,
  X,
  CalendarDays,
  User,
  Clock,
  MapPin,
} from "lucide-react";

// Reuse the same modal pattern from LeaveApprovals
const ApprovalModal = ({ claim, onClose, onConfirm }) => {
  const [remark, setRemark] = useState("");
  const [loading, setLoading] = useState(false);
  const employee = claim.employee || {};

  const handleConfirm = async () => {
    if (!remark.trim()) {
      toast.error("Please enter a remark");
      return;
    }

    setLoading(true);
    await onConfirm(claim.claim_id, remark.trim());
    setLoading(false);
  };

  return (
    <Modal
      isOpen={true}
      onClose={onClose}
      title="Approve Weekly Off"
      size="md"
      footer={
        <>
          <Button variant="outline" onClick={onClose}>
            Cancel
          </Button>
          <Button
            onClick={handleConfirm}
            isLoading={loading}
            leftIcon={<CheckCircle2 className="h-4 w-4" />}
          >
            Approve
          </Button>
        </>
      }
    >
      <div className="space-y-4">
        {/* Employee Info Card */}
        <div className="bg-slate-50 rounded-xl border border-slate-200 p-4 space-y-3">
          <div className="flex items-center gap-3">
            <div className="h-10 w-10 rounded-xl bg-green-600 flex items-center justify-center text-sm font-bold text-white">
              {employee.employee_name
                ?.split(" ")
                .map((w) => w[0])
                .join("")
                .slice(0, 2) || "WO"}
            </div>
            <div>
              <p className="text-sm font-bold text-slate-800">
                {employee.employee_name || "—"}
              </p>
              <p className="text-xs text-slate-400 font-mono">
                {employee.employee_code || "—"}
              </p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-2.5 pt-1">
            <div className="flex items-center gap-2 text-xs text-slate-600">
              <MapPin className="h-3.5 w-3.5 text-slate-400" />
              {employee.district_name || "—"}
            </div>
            <div className="flex items-center gap-2 text-xs text-slate-600">
              <User className="h-3.5 w-3.5 text-slate-400" />
              {employee.scheme_name || "—"}
            </div>
            <div className="flex items-center gap-2 text-xs text-slate-600 col-span-2">
              <CalendarDays className="h-3.5 w-3.5 text-slate-400" />
              Week: {claim.entitlement_week_start} → {claim.entitlement_week_end}
            </div>
            <div className="flex items-center gap-2 text-xs text-slate-600">
              <Clock className="h-3.5 w-3.5 text-slate-400" />
              Claimed: {claim.claimed_off_date
                ? new Date(claim.claimed_off_date).toLocaleDateString("en-GB", {
                    day: "numeric",
                    month: "short",
                    year: "numeric",
                  })
                : "—"}
            </div>
          </div>
        </div>

        {/* Info Alert */}
        <div className="bg-blue-50 rounded-lg border border-blue-200 p-3">
          <p className="text-xs text-blue-700">
            Approving this claim will mark {claim.claimed_off_date} as a weekly off record for this employee.
          </p>
        </div>

        {/* Remarks */}
        <div className="space-y-2">
          <p className="text-xs font-semibold uppercase tracking-widest text-slate-400">
            Remark <span className="text-red-400">*</span>
          </p>
          <textarea
            rows={3}
            value={remark}
            onChange={(e) => setRemark(e.target.value)}
            placeholder="Enter approval remarks..."
            className="w-full rounded-xl border border-slate-200 bg-slate-50 px-4 py-3 text-sm outline-none focus:border-slate-400 focus:bg-white"
          />
        </div>
      </div>
    </Modal>
  );
};

const WeeklyOffApproval = () => {
  const [pendingClaims, setPendingClaims] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modalClaim, setModalClaim] = useState(null);
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  // Debouncing refs
  const searchTimeoutRef = useRef(null);
  const lastSearchQueryRef = useRef("");

  const fetchPendingClaims = useCallback(async (filters = {}) => {
    try {
      setLoading(true);
      const result = await getPendingWeeklyOffClaims({ 
        ...filters, 
        limit: limit,
        page: page
      });
      setPendingClaims(result?.data?.data || []);
      setTotalPages(result?.data?.pagination?.totalPages || 1);
      setTotalItems(result?.data?.pagination?.total || 0);
    } catch (error) {
      toast.error("Failed to load pending weekly off claims");
      console.error(error);
    } finally {
      setLoading(false);
    }
  }, [limit, page]);

  // Debounced search function
  const debouncedSearch = useCallback((searchQuery) => {
    if (searchTimeoutRef.current) {
      clearTimeout(searchTimeoutRef.current);
    }
    if (searchQuery === lastSearchQueryRef.current) {
      return;
    }
    searchTimeoutRef.current = setTimeout(() => {
      lastSearchQueryRef.current = searchQuery;
      setPage(1); // Reset to first page when searching
      fetchPendingClaims({ search: searchQuery });
    }, 500);
  }, [fetchPendingClaims]);

  useEffect(() => {
    fetchPendingClaims();
    const interval = setInterval(fetchPendingClaims, 300000);
    return () => {
      clearInterval(interval);
      if (searchTimeoutRef.current) {
        clearTimeout(searchTimeoutRef.current);
      }
    };
  }, [fetchPendingClaims]);

  const handleConfirm = async (claimId, remark) => {
    try {
      await approveWeeklyOffClaim(claimId, remark);
      toast.success("Weekly off claim approved successfully");
      setModalClaim(null);
      fetchPendingClaims();
    } catch (error) {
      toast.error(error.message || "Failed to approve claim");
    }
  };

  const handlePageSizeChange = (newLimit) => {
    setLimit(newLimit);
    setPage(1); // Reset to first page when changing page size
  };

  const handlePageChange = (newPage) => {
    setPage(newPage);
  };

  const columns = useMemo(
    () => [
      {
        key: "employee",
        header: "Employee",
        render: (_, row) => {
          const emp = row.employee || {};
          return (
            <div className="flex items-center gap-3">
              <div className="h-8 w-8 rounded-lg bg-slate-100 flex items-center justify-center text-xs font-bold text-slate-600">
                {emp.employee_name?.split(" ").map(w => w[0]).join("").slice(0, 2) || "—"}
              </div>
              <div>
                <p className="text-sm font-medium text-slate-900">{emp.employee_name || "—"}</p>
                <p className="text-xs text-slate-400 font-mono">{emp.employee_code || "—"}</p>
              </div>
            </div>
          );
        },
      },
      {
        key: "district_scheme",
        header: "District / Scheme",
        render: (_, row) => {
          const emp = row.employee || {};
          return (
            <div className="text-xs">
              <div className="text-slate-700">{emp.district_name || "—"}</div>
              <div className="text-slate-400">{emp.scheme_name || "—"}</div>
            </div>
          );
        },
      },
      {
        key: "entitlement_week",
        header: "Entitlement Week",
        render: (_, row) => (
          <span className="text-xs text-slate-600">
            {row.entitlement_week_start} → {row.entitlement_week_end}
          </span>
        ),
      },
      {
        key: "claimed_off_date",
        header: "Claimed Date",
        render: (_, row) =>
          row.claimed_off_date ? (
            <span className="text-xs font-medium text-slate-700">
              {new Date(row.claimed_off_date).toLocaleDateString("en-GB", {
                day: "numeric",
                month: "short",
                year: "numeric",
              })}
            </span>
          ) : (
            <span className="text-xs text-slate-400 italic">Not selected</span>
          ),
      },
      {
        key: "requested_at",
        header: "Requested",
        render: (_, row) =>
          row.requested_at ? (
            <span className="text-xs text-slate-500">
              {new Date(row.requested_at).toLocaleString("en-GB", {
                day: "numeric",
                month: "short",
                hour: "2-digit",
                minute: "2-digit",
              })}
            </span>
          ) : (
            <span className="text-xs text-slate-400">—</span>
          ),
      },
      {
        key: "actions",
        header: "Actions",
        render: (_, row) => (
          <button
            onClick={() => setModalClaim(row)}
            className="p-1.5 rounded-lg hover:bg-green-50 text-green-600 transition-colors"
            title="Approve"
          >
            <CheckCircle2 className="h-5 w-5" />
          </button>
        ),
      },
    ],
    []
  );

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-semibold text-slate-900">Weekly Off Claims Approval</h1>
          <p className="text-sm text-slate-500 mt-1">
            Review and approve employee weekly off claims. Claims are auto-approved after 24 hours.
          </p>
        </div>
        <div className="flex items-center gap-2 text-sm text-slate-500">
          <span className="w-2 h-2 rounded-full bg-amber-400 animate-pulse" />
          <span>{pendingClaims.length} pending</span>
        </div>
      </div>

      <DataTable
        columns={columns}
        data={pendingClaims}
        isLoading={loading}
        enableSelection={false}
        showRowNumbers={true}
        rowKey="claim_id"
        onSearch={debouncedSearch}
        pagination={{
          currentPage: page,
          totalPages: totalPages,
          totalItems: totalItems,
          onPageChange: handlePageChange,
          pageSize: limit,
          onPageSizeChange: handlePageSizeChange,
          pageSizeOptions: [10, 25, 50],
        }}
        headerClassName="bg-slate-900 text-white"
      />

      {modalClaim && (
        <ApprovalModal
          claim={modalClaim}
          onClose={() => setModalClaim(null)}
          onConfirm={handleConfirm}
        />
      )}
    </div>
  );
};

export default WeeklyOffApproval;
