import { useSearchParams } from "react-router-dom";
import { useEffect, useState } from "react";
import { getEmployeeById } from "../../../services/workforce.service";
import { Pencil, User } from "lucide-react";
import toast from "react-hot-toast";
import { PUBLIC_FILE_BASE_URL } from "../../../config/appConfig";

const EmployeeView = () => {
  const [searchParams, setSearchParams] = useSearchParams();
  const id = searchParams.get("id");
  const fromTab = searchParams.get("fromTab") || "employee-list";

  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  const handleBack = () => {
    setSearchParams({ tab: "employees", subtab: fromTab });
  };

  useEffect(() => {
    if (!id) return;
    const fetchData = async () => {
      try {
        const res = await getEmployeeById(id);
        setData(res.data);
      } catch (err) {
        toast.error("Failed to load employee data");
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [id]);

  // Extract data from API response structure (nested from employeeService)
  const personalInfo = data?.personal_info || {};
  const employmentInfo = data?.employment_info || {};
  const reportingInfo = data?.reporting_info || {};
  const leaveBalance = data?.leave_balance || [];
  const attendanceSummary = data?.attendance_summary || {};

  const contractDays = employmentInfo?.contract_start_date && employmentInfo?.contract_end_date
    ? Math.round(
        (new Date(employmentInfo.contract_end_date) - new Date(employmentInfo.contract_start_date)) /
          (1000 * 60 * 60 * 24)
      )
    : null;

  const joinedDay = data?.created_at
    ? new Date(data.created_at).getDate()
    : null;

  const joinedMonthYear = data?.created_at
    ? new Date(data.created_at).toLocaleDateString("en-IN", {
        month: "short",
        year: "numeric",
      })
    : null;

  const initials = data?.employee_code
    ? data.employee_code.slice(-2).toUpperCase()
    : "??";

  if (loading) return <p className="p-4 text-slate-500">Loading...</p>;
  if (!data) return <p className="p-4 text-slate-500">No data found</p>;

  return (
    <div style={{ maxWidth: "100%", padding: "24px" }}>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "240px 1fr",
          minHeight: "480px",
          border: "0.5px solid #e2e8f0",
          borderRadius: "14px",
          overflow: "hidden",
          background: "#fff",
        }}
        className="employee-view-card"
      >
        {/* ── Sidebar ── */}
        <div
          style={{
            background: "#0C447C",
            padding: "28px 20px",
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
          }}
        >
          {/* Avatar with Profile Photo */}
          {personalInfo.photo_path ? (
            <img
              src={`${PUBLIC_FILE_BASE_URL}${personalInfo.photo_path.startsWith('/') ? '' : '/'}${personalInfo.photo_path}`}
              alt="Profile"
              style={{
                width: 64,
                height: 64,
                borderRadius: "50%",
                objectFit: "cover",
                marginBottom: 14,
                border: "2px solid #E6F1FB",
              }}
              onError={(e) => {
                // Fallback to initials if image fails to load
                e.target.style.display = 'none';
                e.target.nextSibling.style.display = 'flex';
              }}
            />
          ) : null}
          <div
            style={{
              width: 64,
              height: 64,
              borderRadius: "50%",
              background: "#E6F1FB",
              display: personalInfo.photo_path ? "none" : "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 20,
              fontWeight: 500,
              color: "#0C447C",
              marginBottom: 14,
            }}
          >
            {initials}
          </div>

          <p style={{ fontSize: 14, fontWeight: 500, color: "#E6F1FB", textAlign: "center", marginBottom: 20 }}>
            {data.employee_code}
          </p>

          <SidebarDivider />

          {/* Contract days stat */}
          {contractDays !== null && (
            <SidebarStat value={contractDays} label="days in contract" />
          )}

          <SidebarDivider />

          {/* Joined date stat */}
          {joinedDay && (
            <SidebarStat
              value={joinedDay}
              label={`${joinedMonthYear?.toLowerCase()} · joined`}
            />
          )}
        </div>

        {/* ── Main ── */}
        <div style={{ padding: "28px 28px", display: "flex", flexDirection: "column", gap: 24, overflowY: "auto", position: "relative" }}>
          
          {/* Action Buttons - Top Right */}
          <div style={{
            position: "absolute",
            top: "20px",
            right: "20px",
            display: "flex",
            gap: "8px",
            zIndex: 10
          }}>
            <button
              onClick={handleBack}
              style={{
                display: "inline-flex",
                alignItems: "center",
                gap: 6,
                fontSize: 12,
                padding: "6px 12px",
                borderRadius: 6,
                border: "0.5px solid #cbd5e1",
                background: "transparent",
                color: "#64748b",
                cursor: "pointer",
              }}
              onMouseEnter={(e) => (e.currentTarget.style.background = "#f1f5f9")}
              onMouseLeave={(e) => (e.currentTarget.style.background = "transparent")}
            >
              ← Back
            </button>
            <button
              onClick={() => setSearchParams({ tab: "employees", subtab: "employee-edit", id })}
              style={{
                display: "inline-flex",
                alignItems: "center",
                gap: 6,
                fontSize: 12,
                padding: "6px 12px",
                borderRadius: 6,
                border: "none",
                background: "#3b82f6",
                color: "#fff",
                cursor: "pointer",
              }}
              onMouseEnter={(e) => (e.currentTarget.style.background = "#2563eb")}
              onMouseLeave={(e) => (e.currentTarget.style.background = "#3b82f6")}
            >
              <Pencil style={{ width: 14, height: 14 }} /> Edit
            </button>
          </div>

          {/* Personal Information */}
          <section>
            <SectionTitle>Personal Information</SectionTitle>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 10 }}>
              <Field label="Full Name" value={personalInfo.full_name} />
              <Field label="Email" value={personalInfo.email} />
              <Field label="Mobile" value={personalInfo.mobile_no} />
              <Field label="Date of Birth" value={formatDate(personalInfo.dob)} />
              <Field label="Gender" value={personalInfo.gender} />
              <Field label="Aadhar No" value={personalInfo.aadhar_no} mono />
            </div>
          </section>

          {/* Posting details */}
          <section>
            <SectionTitle>Posting Details</SectionTitle>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(2, minmax(0,1fr))", gap: 10 }}>
              <Field label="District" value={employmentInfo.district_name} />
              <Field label="OSC" value={employmentInfo.component_name} />
              <Field label="Hub" value={employmentInfo.hub_name} />
              <Field label="Post" value={employmentInfo.post_name} />
              <Field label="Monthly Pay" value={employmentInfo.employee_pay ? `₹${Number(employmentInfo.employee_pay).toLocaleString('en-IN')}` : null} />
              <Field label="Reporting Officer" value={reportingInfo.reporting_officer_name || "Not Assigned"} />
            </div>
          </section>

          {/* Contract period */}
          <section>
            <SectionTitle>Contract Period</SectionTitle>
            <div style={{ display: "flex", alignItems: "center", gap: 0 }}>
              <TimelineNode label="Start" value={formatDate(employmentInfo.contract_start_date)} />
              <div style={{ display: "flex", alignItems: "center", flex: 1, padding: "0 4px" }}>
                <div style={{ flex: 1, height: 1, background: "#cbd5e1" }} />
                <div style={{
                  width: 0, height: 0,
                  borderTop: "4px solid transparent",
                  borderBottom: "4px solid transparent",
                  borderLeft: "6px solid #cbd5e1",
                }} />
              </div>
              <TimelineNode label="End" value={formatDate(employmentInfo.contract_end_date)} />
            </div>
          </section>

          {/* Attendance Summary (Current Month) */}
          {attendanceSummary && (
            <section>
              <SectionTitle>Attendance Summary (Current Month)</SectionTitle>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(5, minmax(0,1fr))", gap: 10 }}>
                <StatCard label="Present" value={attendanceSummary.present_days || 0} color="#059669" />
                <StatCard label="Absent" value={attendanceSummary.absent_days || 0} color="#dc2626" />
                <StatCard label="Half Day" value={attendanceSummary.half_days || 0} color="#7c3aed" />
                <StatCard label="On Leave" value={attendanceSummary.leave_days || 0} color="#7c3aed" />
                <StatCard label="Holidays" value={attendanceSummary.holidays || 0} color="#ca8a04" />
              </div>
            </section>
          )}

          {/* Leave Balance */}
          {leaveBalance.length > 0 && (
            <section>
              <SectionTitle>Leave Balance</SectionTitle>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(4, minmax(0,1fr))", gap: 10 }}>
                {leaveBalance.map((leave, idx) => (
                  <div key={idx} style={{
                    padding: "12px 14px",
                    borderRadius: 8,
                    border: "0.5px solid #e2e8f0",
                    background: "#fafafa"
                  }}>
                    <p style={{ fontSize: 11, color: "#64748b", marginBottom: 4 }}>{leave.leave_name}</p>
                    <p style={{ fontSize: 16, fontWeight: 600, color: "#1e293b" }}>
                      {leave.remaining || 0} <span style={{ fontSize: 11, color: "#94a3b8", fontWeight: 400 }}>/ {leave.total_allocated || 0}</span>
                    </p>
                    <p style={{ fontSize: 10, color: "#94a3b8", marginTop: 2 }}>Used: {leave.used || 0}</p>
                  </div>
                ))}
              </div>
            </section>
          )}

          {/* Employee details */}
          <section>
            <SectionTitle>System Details</SectionTitle>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(2, minmax(0,1fr))", gap: 10 }}>
              <Field label="Employee Code" value={data.employee_code} mono />
              <Field label="Joining Date" value={formatDate(employmentInfo.joining_date)} />
              <Field label="Onboarding Type" value={employmentInfo.onboarding_type} />
            </div>
          </section>

                  </div>
      </div>
    </div>
  );
};

// ── Small reusable pieces ──────────────────────────────────

const SectionTitle = ({ children }) => (
  <p style={{
    fontSize: 15,
    fontWeight: 700,
    letterSpacing: "0.07em",
    textTransform: "uppercase",
    color: "#94a3b8",
    marginBottom: 12,
  }}>
    {children}
  </p>
);

const Field = ({ label, value, mono }) => (
  <div style={{
    padding: "12px 14px",
    borderRadius: 8,
    border: "0.5px solid #e2e8f0",
    minWidth: 0, // Allow flex item to shrink below content size
  }}>
    <p style={{ fontSize: 11, color: "#94a3b8", marginBottom: 5 }}>{label}</p>
    <p style={{
      fontSize: mono ? 12 : 13,
      fontWeight: 500,
      color: "#1e293b",
      fontFamily: mono ? "monospace" : "inherit",
      wordBreak: "break-word",
      overflowWrap: "break-word",
      hyphens: "auto",
    }}>
      {value || "—"}
    </p>
  </div>
);

const TimelineNode = ({ label, value }) => (
  <div style={{
    padding: "12px 14px",
    borderRadius: 8,
    border: "0.5px solid #e2e8f0",
    minWidth: 130,
  }}>
    <p style={{ fontSize: 11, color: "#94a3b8", marginBottom: 4 }}>{label}</p>
    <p style={{ fontSize: 13, fontWeight: 500, color: "#1e293b" }}>{value || "—"}</p>
  </div>
);

const StatusPill = ({ label, color }) => (
  <div style={{
    display: "inline-flex",
    alignItems: "center",
    gap: 5,
    fontSize: 11,
    fontWeight: 500,
    padding: "4px 12px",
    borderRadius: 999,
    background: color.bg,
    color: color.text,
  }}>
    <span style={{
      width: 7, height: 7,
      borderRadius: "50%",
      background: color.dot,
      display: "inline-block",
    }} />
    {label}
  </div>
);

const SidebarDivider = () => (
  <div style={{ width: "100%", height: "0.5px", background: "#185FA5", margin: "20px 0" }} />
);

const SidebarStat = ({ value, label }) => (
  <div style={{ textAlign: "center" }}>
    <div style={{ fontSize: 22, fontWeight: 500, color: "#E6F1FB" }}>{value}</div>
    <div style={{ fontSize: 11, color: "#85B7EB", marginTop: 2 }}>{label}</div>
  </div>
);

const StatCard = ({ label, value, color }) => (
  <div style={{
    padding: "12px 14px",
    borderRadius: 8,
    border: "0.5px solid #e2e8f0",
    background: `${color}10`,
    textAlign: "center"
  }}>
    <p style={{ fontSize: 20, fontWeight: 600, color }}>{value}</p>
    <p style={{ fontSize: 11, color: "#64748b", marginTop: 4 }}>{label}</p>
  </div>
);

const formatDate = (date) => {
  if (!date) return "—";
  return new Date(date).toLocaleDateString("en-IN");
};

export default EmployeeView;