    if (!data?.report_status) return { submitted: 0, approved: 0, rejected: 0, pending: 0 };
    
    // Ensure it's an object with the expected properties
    return {
      submitted: data.report_status.submitted || 0,
      approved: data.report_status.approved || 0,
      rejected: data.report_status.rejected || 0,
      pending: data.report_status.pending || 0
    };
